{
  "name": "Mentoring Log System (Gen-Next)",
  "description": "A comprehensive system for managing mentoring logs, competency assessments, and budget tracking for the New Breed Graduate Project. Features mobile-first logging, automated payment calculation, and competency tracking via radar charts."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Role {
  ADMIN = 'ADMIN',
  MENTOR = 'MENTOR',
  STUDENT = 'STUDENT'
}

export enum LogStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED'
}

export enum AttendanceStatus {
  PRESENT = 'PRESENT',
  LATE = 'LATE',
  ABSENT = 'ABSENT'
}

export interface User {
  id: string;
  role: Role;
  fullName: string;
  email: string;
  avatarUrl?: string;
  // Specific to students
  batchId?: string;
}

export interface Batch {
  id: string;
  name: string;
  courseName: string;
  hourlyRate: number;
}

export interface CompetencyScore {
  studentId: string;
  attendance: AttendanceStatus;
  business: number; // 0-5
  creativity: number; // 0-5
  discipline: number; // 0-5
}

export interface MentoringLog {
  id: string;
  mentorId: string;
  batchId: string;
  date: string;
  startTime: string; // HH:mm
  endTime: string; // HH:mm
  durationMinutes: number;
  isPayable: boolean;
  status: LogStatus;
  summaryNote: string;
  artifactUrl: string;
  scores: CompetencyScore[]; // One entry per student in the session
  paymentAmount: number;
}

export interface SessionValidation {
  isValid: boolean;
  message: string;
  duration: number;
  isPayable: boolean;
}

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { MentoringLog, User, Batch, Role, LogStatus } from '../types';
import { MOCK_USERS, MOCK_BATCHES, INITIAL_LOGS } from '../constants';

interface DataContextType {
  currentUser: User;
  switchRole: (role: Role) => void;
  logs: MentoringLog[];
  users: User[];
  batches: Batch[];
  addLog: (log: MentoringLog) => void;
  updateLogStatus: (id: string, status: LogStatus) => void;
  getStudentsByBatch: (batchId: string) => User[];
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[1]); // Default to Mentor
  const [logs, setLogs] = useState<MentoringLog[]>(INITIAL_LOGS);
  const [users] = useState<User[]>(MOCK_USERS);
  const [batches] = useState<Batch[]>(MOCK_BATCHES);

  const switchRole = (role: Role) => {
    const user = users.find(u => u.role === role);
    if (user) setCurrentUser(user);
  };

  const addLog = (log: MentoringLog) => {
    setLogs(prev => [log, ...prev]);
  };

  const updateLogStatus = (id: string, status: LogStatus) => {
    setLogs(prev => prev.map(log => log.id === id ? { ...log, status } : log));
  };

  const getStudentsByBatch = (batchId: string) => {
    return users.filter(u => u.role === Role.STUDENT && u.batchId === batchId);
  };

  return (
    <DataContext.Provider value={{ 
      currentUser, 
      switchRole, 
      logs, 
      users, 
      batches, 
      addLog, 
      updateLogStatus,
      getStudentsByBatch 
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error('useData must be used within DataProvider');
  return context;
};

import React from 'react';
import { useData } from '../services/DataContext';
import { Role } from '../types';
import { LayoutDashboard, PenTool, GraduationCap, LogOut, Menu } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
