  const [isSidebarOpen, setIsSidebarOpen] = React.useState(false);

  const navItems = [
    { label: 'Switch to Admin', icon: <LayoutDashboard size={20} />, role: Role.ADMIN },
    { label: 'Switch to Mentor', icon: <PenTool size={20} />, role: Role.MENTOR },
    { label: 'Switch to Student', icon: <GraduationCap size={20} />, role: Role.STUDENT },
  ];

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-50">
      {/* Mobile Header */}
      <div className="md:hidden bg-white shadow-sm p-4 flex justify-between items-center sticky top-0 z-20">
        <h1 className="font-bold text-lg text-indigo-700">Mentoring Log</h1>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)}>
          <Menu className="text-gray-600" />
        </button>
      </div>

      {/* Sidebar / Drawer */}
      <aside className={`
        fixed md:sticky top-0 h-screen w-64 bg-white shadow-lg transform transition-transform duration-200 ease-in-out z-10
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0
      `}>
        <div className="p-6 border-b border-gray-100">
          <h2 className="text-2xl font-bold text-indigo-600">Gen-Next</h2>
          <p className="text-xs text-gray-500 mt-1">Mentoring System v2.0</p>
        </div>

        <div className="p-6">
          <div className="flex items-center space-x-3 mb-8">
            <img src={currentUser.avatarUrl} alt="Avatar" className="w-10 h-10 rounded-full border border-gray-200" />
            <div>
              <p className="text-sm font-semibold text-gray-800">{currentUser.fullName}</p>
              <p className="text-xs text-gray-500 capitalize">{currentUser.role.toLowerCase()}</p>
            </div>
          </div>

          <nav className="space-y-2">
            <div className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2">Role Switcher</div>
            {navItems.map((item) => (
              <button
                key={item.role}
                onClick={() => {
                  switchRole(item.role);
                  setIsSidebarOpen(false);
                }}
                className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${
                  currentUser.role === item.role 
                    ? 'bg-indigo-50 text-indigo-600' 
                    : 'text-gray-600 hover:bg-gray-50'
                }`}
              >
                {item.icon}
                <span className="text-sm font-medium">{item.label}</span>
              </button>
            ))}
          </nav>
        </div>

        <div className="absolute bottom-0 w-full p-6 border-t border-gray-100">
          <button className="flex items-center space-x-2 text-gray-500 hover:text-red-500 transition-colors">
            <LogOut size={18} />
            <span className="text-sm">Log Out</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-screen">
        <div className="max-w-5xl mx-auto">
          {children}
        </div>
      </main>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useData } from '../services/DataContext';
import { AttendanceStatus, CompetencyScore, LogStatus, MentoringLog, Role } from '../types';
import { Clock, Users, Save, AlertCircle, Link as LinkIcon, Upload } from 'lucide-react';

export const MentorLogForm: React.FC = () => {
  const { batches, currentUser, getStudentsByBatch, addLog } = useData();

  // Local State
  const [selectedBatchId, setSelectedBatchId] = useState(batches[0]?.id || '');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [summary, setSummary] = useState('');
  const [artifactUrl, setArtifactUrl] = useState('');
  const [scores, setScores] = useState<CompetencyScore[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  const students = getStudentsByBatch(selectedBatchId);

  // Initialize scores when students change
  useEffect(() => {
    if (students.length > 0) {
      const initialScores: CompetencyScore[] = students.map(s => ({
        studentId: s.id,
        attendance: AttendanceStatus.PRESENT,
        business: 3,
        creativity: 3,
        discipline: 3
      }));
      setScores(initialScores);
    }
  }, [selectedBatchId, students.length]); // Intentionally omitting full 'students' object dependency

  const calculateDuration = () => {
    if (!startTime || !endTime) return 0;
    const start = new Date(`2000-01-01T${startTime}`);
    const end = new Date(`2000-01-01T${endTime}`);
    const diffMs = end.getTime() - start.getTime();
    return Math.max(0, Math.floor(diffMs / 60000));
  };

  const duration = calculateDuration();
  const isEligible = duration >= 50;

  const handleScoreChange = (studentId: string, field: keyof CompetencyScore, value: any) => {
    setScores(prev => prev.map(s => s.studentId === studentId ? { ...s, [field]: value } : s));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!artifactUrl) {
      alert("Please provide an artifact link (Proof of work).");
      return;
    }

    setIsSubmitting(true);

    const newLog: MentoringLog = {
      id: `log-${Date.now()}`,
      mentorId: currentUser.id,
      batchId: selectedBatchId,
      date,
      startTime,
      endTime,
      durationMinutes: duration,
      isPayable: isEligible,
      status: LogStatus.PENDING,
      summaryNote: summary,
      artifactUrl,
      scores,
      paymentAmount: isEligible ? 1200 : 0
    };

    setTimeout(() => {
        addLog(newLog);
        setIsSubmitting(false);
        setSuccessMsg("Log submitted successfully!");
        // Reset form partially
        setSummary('');
        setArtifactUrl('');
        setTimeout(() => setSuccessMsg(''), 3000);
    }, 800);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="p-6 border-b border-gray-100 bg-indigo-50">
        <h2 className="text-xl font-bold text-indigo-900 flex items-center gap-2">
            <Clock className="w-5 h-5" /> New Session Log
        </h2>
        <p className="text-sm text-indigo-600 mt-1">Record your mentoring activity and assess students.</p>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-8">
        {/* Section 1: Session Details */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Batch / Course</label>
            <select 
              value={selectedBatchId}
              onChange={(e) => setSelectedBatchId(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
            >
              {batches.map(b => <option key={b.id} value={b.id}>{b.name} - {b.courseName}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Date</label>
            <input 
              type="date" 
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
                <label className="block text-xs font-medium text-gray-500 uppercase mb-1">Start Time</label>
                <input 
                    type="time" 
                    value={startTime}
                    onChange={(e) => setStartTime(e.target.value)}
                    className="w-full rounded-lg border-gray-300 p-2 border"
                    required
                />
             </div>
             <div>
                <label className="block text-xs font-medium text-gray-500 uppercase mb-1">End Time</label>
                <input 
                    type="time" 
                    value={endTime}
                    onChange={(e) => setEndTime(e.target.value)}
                    className="w-full rounded-lg border-gray-300 p-2 border"
                    required
                />
             </div>
          </div>

          <div className="flex items-center justify-center bg-gray-50 rounded-lg border border-gray-200 p-4">
             <div className="text-center">
                 <p className="text-xs text-gray-500 uppercase">Duration</p>
                 <p className={`text-2xl font-bold ${isEligible ? 'text-green-600' : 'text-red-500'}`}>
                     {duration} min
                 </p>
                 <p className="text-xs mt-1">
                     {isEligible ? 
                        <span className="bg-green-100 text-green-800 px-2 py-0.5 rounded-full">Eligible for Payment</span> : 
                        <span className="bg-red-100 text-red-800 px-2 py-0.5 rounded-full">Not Eligible (&lt;50m)</span>
                     }
                 </p>
             </div>
          </div>
        </section>

        {/* Section 2: Student Assessment */}
        <section>
            <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center gap-2">
                <Users className="w-5 h-5 text-indigo-500" /> Attendance & Competency
            </h3>
            <div className="space-y-6">
                {students.map((student) => {
                    const score = scores.find(s => s.studentId === student.id);
                    if (!score) return null;

                    return (
                        <div key={student.id} className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm hover:shadow-md transition-shadow">
                            <div className="flex flex-col sm:flex-row justify-between sm:items-center mb-4 gap-4">
                                <div className="flex items-center gap-3">
                                    <img src={student.avatarUrl} alt={student.fullName} className="w-10 h-10 rounded-full" />
                                    <span className="font-medium text-gray-900">{student.fullName}</span>
                                </div>
                                <div className="flex bg-gray-100 rounded-lg p-1">
                                    {[AttendanceStatus.PRESENT, AttendanceStatus.LATE, AttendanceStatus.ABSENT].map((status) => (
                                        <button
                                            type="button"
                                            key={status}
                                            onClick={() => handleScoreChange(student.id, 'attendance', status)}
                                            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                                                score.attendance === status 
                                                ? status === AttendanceStatus.PRESENT ? 'bg-green-500 text-white' 
                                                : status === AttendanceStatus.LATE ? 'bg-yellow-500 text-white' 
                                                : 'bg-red-500 text-white'
                                                : 'text-gray-500 hover:text-gray-900'
                                            }`}
                                        >
                                            {status}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Rubrics - Only show if present or late */}
                            {score.attendance !== AttendanceStatus.ABSENT && (
                                <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 pt-2 border-t border-gray-100">
                                    {[
                                        { label: 'Business Acumen', key: 'business' },
                                        { label: 'Creativity', key: 'creativity' },
                                        { label: 'Discipline', key: 'discipline' }
                                    ].map((metric) => (
                                        <div key={metric.key}>
                                            <div className="flex justify-between mb-1">
                                                <label className="text-xs font-medium text-gray-500 uppercase">{metric.label}</label>
                                                <span className="text-xs font-bold text-indigo-600">{(score as any)[metric.key]}/5</span>
                                            </div>
                                            <input 
                                                type="range" 
                                                min="0" max="5" step="1"
                                                value={(score as any)[metric.key]}
                                                onChange={(e) => handleScoreChange(student.id, metric.key as keyof CompetencyScore, parseInt(e.target.value))}
                                                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                                            />
                                            <div className="flex justify-between text-[10px] text-gray-400 mt-1">
                                                <span>Poor</span>
                                                <span>Excellent</span>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </section>

        {/* Section 3: Evidence & Summary */}
        <section className="bg-gray-50 p-6 rounded-lg border border-gray-200">
             <div className="mb-4">
                 <label className="block text-sm font-medium text-gray-700 mb-2">Session Summary</label>
                 <textarea 
                    value={summary}
                    onChange={(e) => setSummary(e.target.value)}
                    placeholder="Briefly describe what was covered..."
                    rows={3}
                    className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 p-2 border"
                 />
                 <button type="button" className="mt-2 text-xs text-indigo-600 font-medium hover:underline flex items-center gap-1">
                    Wait... Use Voice Input (Mock)
                 </button>
             </div>
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                    <LinkIcon className="w-4 h-4" /> Artifact / Evidence (Required)
                </label>
                <div className="flex gap-2">
                    <input 
                        type="url" 
                        value={artifactUrl}
                        onChange={(e) => setArtifactUrl(e.target.value)}
                        placeholder="https://github.com/..."
                        className="flex-1 rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 p-2 border"
                        required
                    />
                    <button type="button" className="bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded-lg text-sm hover:bg-gray-50 flex items-center gap-2">
                        <Upload className="w-4 h-4" /> Upload
                    </button>
                </div>
             </div>
        </section>

        {/* Footer */}
        <div className="flex items-center justify-between pt-4 border-t border-gray-100">
             <div className="text-sm text-gray-500">
                Est. Payment: <span className="font-bold text-gray-900">{isEligible ? '1,200 THB' : '0 THB'}</span>
             </div>
             <button 
                type="submit" 
                disabled={isSubmitting}
                className={`flex items-center gap-2 bg-indigo-600 text-white px-6 py-2.5 rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-all ${isSubmitting ? 'opacity-70 cursor-not-allowed' : ''}`}
             >
                <Save className="w-4 h-4" />
                {isSubmitting ? 'Submitting...' : 'Submit Log'}
             </button>
        </div>
        {successMsg && (
            <div className="bg-green-100 text-green-800 p-4 rounded-lg flex items-center gap-2 animate-bounce">
                <AlertCircle className="w-5 h-5" /> {successMsg}
            </div>
        )}
      </form>
    </div>
  );
};

import React from 'react';
import { useData } from '../services/DataContext';
import { RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, ResponsiveContainer, Tooltip } from 'recharts';
import { Trophy, TrendingUp, Calendar } from 'lucide-react';

export const StudentView: React.FC = () => {
  const { currentUser, logs } = useData();

  // Filter logs where this student was scored
  const myScores = logs.flatMap(log => 
    log.scores
        .filter(s => s.studentId === currentUser.id)
        .map(s => ({...s, date: log.date}))
  );

  // Calculate Average Competency
  const totalSessions = myScores.length;
  let avgBusiness = 0, avgCreativity = 0, avgDiscipline = 0;

  if (totalSessions > 0) {
      avgBusiness = myScores.reduce((a, b) => a + b.business, 0) / totalSessions;
      avgCreativity = myScores.reduce((a, b) => a + b.creativity, 0) / totalSessions;
      avgDiscipline = myScores.reduce((a, b) => a + b.discipline, 0) / totalSessions;
  }

  const radarData = [
    { subject: 'Business', A: avgBusiness, fullMark: 5 },
    { subject: 'Creativity', A: avgCreativity, fullMark: 5 },
    { subject: 'Discipline', A: avgDiscipline, fullMark: 5 },
  ];

  return (
    <div className="space-y-6">
      <div className="bg-indigo-600 rounded-2xl p-8 text-white shadow-lg">
          <h1 className="text-3xl font-bold">Hello, {currentUser.fullName.split(' ')[0]}!</h1>
          <p className="text-indigo-200 mt-2">Here is your competency growth report.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Radar Chart */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
              <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
                  <Trophy className="w-5 h-5 text-yellow-500" /> Competency Radar
              </h3>
              <div className="h-72 w-full flex justify-center items-center">
                {totalSessions > 0 ? (
                    <ResponsiveContainer width="100%" height="100%">
                        <RadarChart cx="50%" cy="50%" outerRadius="80%" data={radarData}>
                            <PolarGrid />
                            <PolarAngleAxis dataKey="subject" />
                            <PolarRadiusAxis angle={30} domain={[0, 5]} />
                            <Radar name="My Competency" dataKey="A" stroke="#4f46e5" fill="#4f46e5" fillOpacity={0.6} />
                            <Tooltip />
                        </RadarChart>
                    </ResponsiveContainer>
                ) : (
                    <p className="text-gray-400">No assessment data available yet.</p>
                )}
              </div>
          </div>

          {/* Stats & History */}
          <div className="space-y-6">
               <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                    <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
                        <TrendingUp className="w-5 h-5 text-green-500" /> Current Standing
                    </h3>
                    <div className="grid grid-cols-3 gap-4 text-center">
                        <div className="p-3 bg-indigo-50 rounded-lg">
                            <div className="text-2xl font-bold text-indigo-700">{avgBusiness.toFixed(1)}</div>
                            <div className="text-xs text-indigo-500 uppercase font-medium">Business</div>
                        </div>
                        <div className="p-3 bg-purple-50 rounded-lg">
                            <div className="text-2xl font-bold text-purple-700">{avgCreativity.toFixed(1)}</div>
                            <div className="text-xs text-purple-500 uppercase font-medium">Creativity</div>
                        </div>
                        <div className="p-3 bg-pink-50 rounded-lg">
                            <div className="text-2xl font-bold text-pink-700">{avgDiscipline.toFixed(1)}</div>
                            <div className="text-xs text-pink-500 uppercase font-medium">Discipline</div>
                        </div>
                    </div>
               </div>

               <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                    <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
                        <Calendar className="w-5 h-5 text-gray-500" /> Recent Sessions
                    </h3>
                    <div className="space-y-3">
                        {myScores.slice(0, 3).map((score, idx) => (
                            <div key={idx} className="flex justify-between items-center p-3 hover:bg-gray-50 rounded-lg transition-colors border-b border-gray-50 last:border-0">
                                <div>
                                    <p className="text-sm font-medium text-gray-900">{score.date}</p>
                                    <p className="text-xs text-gray-500">Attendance: <span className={score.attendance === 'PRESENT' ? 'text-green-600' : 'text-red-500'}>{score.attendance}</span></p>
                                </div>
                                <div className="text-sm font-bold text-gray-700">
                                    Avg: {((score.business + score.creativity + score.discipline)/3).toFixed(1)}
                                </div>
                            </div>
                        ))}
                        {myScores.length === 0 && <p className="text-gray-400 text-sm">No sessions recorded.</p>}
                    </div>
               </div>
          </div>
      </div>
    </div>
  );
};

import React from 'react';
import { DataProvider, useData } from './services/DataContext';
import { Layout } from './components/Layout';
import { MentorLogForm } from './components/MentorLogForm';
import { AdminDashboard } from './components/AdminDashboard';
import { StudentView } from './components/StudentView';
import { Role } from './types';

const AppContent: React.FC = () => {
  const { currentUser } = useData();

  return (
    <Layout>
      {currentUser.role === Role.MENTOR && <MentorLogForm />}
      {currentUser.role === Role.ADMIN && <AdminDashboard />}
      {currentUser.role === Role.STUDENT && <StudentView />}
    </Layout>
  );
};

