import React, { createContext, useContext, useState, ReactNode } from 'react';
import { MentoringLog, User, Batch, Module, Role, LogStatus } from '../types';
import { MOCK_USERS, MOCK_BATCHES, MOCK_MODULES, INITIAL_LOGS } from '../constants';

interface DataContextType {
  currentUser: User;
  switchRole: (role: Role) => void;
  logs: MentoringLog[];
  users: User[];
  batches: Batch[];
  modules: Module[];
  addLog: (log: MentoringLog) => void;
  updateLogStatus: (id: string, status: LogStatus) => void;
  getStudentsByBatch: (batchId: string) => User[];
  addUser: (user: User) => void;
  addBatch: (batch: Batch) => void;
  addModule: (module: Module) => void;
  getModulesByBatch: (batchId: string) => Module[];
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]); // Default to Admin
  const [logs, setLogs] = useState<MentoringLog[]>(INITIAL_LOGS);
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [batches, setBatches] = useState<Batch[]>(MOCK_BATCHES);
  const [modules, setModules] = useState<Module[]>(MOCK_MODULES);

  const switchRole = (role: Role) => {
    const user = users.find(u => u.role === role);
    if (user) setCurrentUser(user);
  };

  const addLog = (log: MentoringLog) => {
    setLogs(prev => [log, ...prev]);
  };

  const updateLogStatus = (id: string, status: LogStatus) => {
    setLogs(prev => prev.map(log => log.id === id ? { ...log, status } : log));
  };

  const getStudentsByBatch = (batchId: string) => {
    return users.filter(u => u.role === Role.STUDENT && u.batchId === batchId);
  };

  const addUser = (user: User) => {
    setUsers(prev => [...prev, user]);
  };

  const addBatch = (batch: Batch) => {
    setBatches(prev => [...prev, batch]);
  };

  const addModule = (module: Module) => {
    setModules(prev => [...prev, module]);
  };

  const getModulesByBatch = (batchId: string) => {
    return modules.filter(m => m.batchId === batchId);
  };

  return (
    <DataContext.Provider value={{ 
      currentUser, 
      switchRole, 
      logs, 
      users, 
      batches, 
      modules,
      addLog, 
      updateLogStatus,
      getStudentsByBatch,
      addUser,
      addBatch,
      addModule,
      getModulesByBatch
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error('useData must be used within DataProvider');
  return context;
};

import React, { useState, useEffect } from 'react';
import { useData } from '../services/DataContext';
import { AttendanceStatus, CompetencyScore, LogStatus, MentoringLog } from '../types';
import { Clock, Users, Save, AlertCircle, Link as LinkIcon, Upload } from 'lucide-react';

export const MentorLogForm: React.FC = () => {
  const { batches, getModulesByBatch, currentUser, getStudentsByBatch, addLog } = useData();

  // Local State
  const [selectedBatchId, setSelectedBatchId] = useState(batches[0]?.id || '');
  const [selectedModuleId, setSelectedModuleId] = useState('');

  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [summary, setSummary] = useState('');
  const [artifactUrl, setArtifactUrl] = useState('');
  const [scores, setScores] = useState<CompetencyScore[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  const students = getStudentsByBatch(selectedBatchId);
  const modules = getModulesByBatch(selectedBatchId);

  // Auto-select first module if available when batch changes
  useEffect(() => {
    if (modules.length > 0) {
      setSelectedModuleId(modules[0].id);
    } else {
      setSelectedModuleId('');
    }
  }, [selectedBatchId, modules]);

  // Initialize scores when students change
  useEffect(() => {
    if (students.length > 0) {
      const initialScores: CompetencyScore[] = students.map(s => ({
        studentId: s.id,
        attendance: AttendanceStatus.PRESENT,
        business: 3,
        creativity: 3,
        discipline: 3
      }));
      setScores(initialScores);
    }
  }, [selectedBatchId, students.length]); 

  const calculateDuration = () => {
    if (!startTime || !endTime) return 0;
    const start = new Date(`2000-01-01T${startTime}`);
    const end = new Date(`2000-01-01T${endTime}`);
    const diffMs = end.getTime() - start.getTime();
    return Math.max(0, Math.floor(diffMs / 60000));
  };

  const duration = calculateDuration();
  const isEligible = duration >= 50;

  const handleScoreChange = (studentId: string, field: keyof CompetencyScore, value: any) => {
    setScores(prev => prev.map(s => s.studentId === studentId ? { ...s, [field]: value } : s));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedModuleId) {
        alert("Please select a teaching module.");
        return;
    }
    if (!artifactUrl) {
      alert("Please provide an artifact link (Proof of work).");
      return;
    }

    setIsSubmitting(true);

    const module = modules.find(m => m.id === selectedModuleId);
    const hourlyRate = module ? module.hourlyRate : 1200;

    const newLog: MentoringLog = {
      id: `log-${Date.now()}`,
      mentorId: currentUser.id,
      batchId: selectedBatchId,
      moduleId: selectedModuleId,
      date,
      startTime,
      endTime,
      durationMinutes: duration,
      isPayable: isEligible,
      status: LogStatus.PENDING,
      summaryNote: summary,
      artifactUrl,
      scores,
      paymentAmount: isEligible ? hourlyRate : 0
    };

    setTimeout(() => {
        addLog(newLog);
        setIsSubmitting(false);
        setSuccessMsg("Log submitted successfully!");
        setSummary('');
        setArtifactUrl('');
        setTimeout(() => setSuccessMsg(''), 3000);
    }, 800);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="p-6 border-b border-gray-100 bg-indigo-50">
        <h2 className="text-xl font-bold text-indigo-900 flex items-center gap-2">
            <Clock className="w-5 h-5" /> New Session Log
        </h2>
        <p className="text-sm text-indigo-600 mt-1">Record your mentoring activity and assess students.</p>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-8">
        {/* Section 1: Session Details */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Batch (Cohort)</label>
            <select 
              value={selectedBatchId}
              onChange={(e) => setSelectedBatchId(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
            >
              {batches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Teaching Module</label>
            <select 
              value={selectedModuleId}
              onChange={(e) => setSelectedModuleId(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
              disabled={modules.length === 0}
            >
              {modules.length === 0 && <option>No modules found</option>}
              {modules.map(m => <option key={m.id} value={m.id}>{m.name} (฿{m.hourlyRate}/hr)</option>)}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Date</label>
            <input 
              type="date" 
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
                <label className="block text-xs font-medium text-gray-500 uppercase mb-1">Start Time</label>
                <input 
                    type="time" 
                    value={startTime}
                    onChange={(e) => setStartTime(e.target.value)}
                    className="w-full rounded-lg border-gray-300 p-2 border"
                    required
                />
             </div>
             <div>
                <label className="block text-xs font-medium text-gray-500 uppercase mb-1">End Time</label>
                <input 
                    type="time" 
                    value={endTime}
                    onChange={(e) => setEndTime(e.target.value)}
                    className="w-full rounded-lg border-gray-300 p-2 border"
                    required
                />
             </div>
          </div>

          <div className="col-span-1 md:col-span-2 flex items-center justify-center bg-gray-50 rounded-lg border border-gray-200 p-4">
             <div className="text-center">
                 <p className="text-xs text-gray-500 uppercase">Duration</p>
