const ApprovalsTab: React.FC<{ 
  logs: MentoringLog[], 
  users: User[],
  modules: Module[],
  onUpdateStatus: (id: string, status: LogStatus) => void 
}> = ({ logs, users, modules, onUpdateStatus }) => {
  const [filterBatch, setFilterBatch] = useState('ALL');
  const [viewMode, setViewMode] = useState<'PENDING' | 'HISTORY'>('PENDING');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [notification, setNotification] = useState<string | null>(null);

  const filteredLogs = logs.filter(log => {
    const matchesBatch = filterBatch === 'ALL' || log.batchId === filterBatch;
    const matchesMode = viewMode === 'PENDING' 
      ? log.status === LogStatus.PENDING 
      : (log.status === LogStatus.APPROVED || log.status === LogStatus.REJECTED);
    return matchesBatch && matchesMode;
  });

  const toggleSelection = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedIds(newSet);
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === filteredLogs.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredLogs.map(l => l.id)));
    }
  };

  const handleBulkAction = (status: LogStatus) => {
    selectedIds.forEach(id => onUpdateStatus(id, status));
    setNotification(`${selectedIds.size} logs marked as ${status}`);
    setSelectedIds(new Set());
    setTimeout(() => setNotification(null), 3000);
  };

  const getModuleName = (id: string) => {
      return modules.find(m => m.id === id)?.name || 'Unknown Module';
  };

  return (
    <div className="space-y-4 animate-fade-in">
      {notification && (
        <div className="fixed bottom-6 right-6 bg-gray-900 text-white px-6 py-3 rounded-lg shadow-lg z-50 flex items-center gap-2 animate-bounce">
          <CheckCircle className="w-5 h-5 text-green-400" />
          {notification}
        </div>
      )}

      {/* Toolbar */}
      <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-white p-4 rounded-xl border border-gray-100 shadow-sm">
        <div className="flex gap-2">
          <button 
            onClick={() => { setViewMode('PENDING'); setSelectedIds(new Set()); }}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${viewMode === 'PENDING' ? 'bg-indigo-100 text-indigo-700' : 'text-gray-600 hover:bg-gray-50'}`}
          >
            Pending Queue
          </button>
          <button 
            onClick={() => { setViewMode('HISTORY'); setSelectedIds(new Set()); }}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${viewMode === 'HISTORY' ? 'bg-indigo-100 text-indigo-700' : 'text-gray-600 hover:bg-gray-50'}`}
          >
            Approval History
          </button>
        </div>

        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2 px-3 py-2 bg-gray-50 rounded-lg border border-gray-200">
            <Filter size={16} className="text-gray-400" />
            <select 
              className="bg-transparent text-sm text-gray-700 focus:outline-none"
              value={filterBatch}
              onChange={(e) => setFilterBatch(e.target.value)}
            >
              <option value="ALL">All Batches</option>
              <option value="b1">Batch 5</option>
              <option value="b2">Batch 6</option>
            </select>
          </div>
          {viewMode === 'PENDING' && selectedIds.size > 0 && (
            <div className="flex gap-2 animate-in fade-in slide-in-from-right-4 duration-200">
               <button onClick={() => handleBulkAction(LogStatus.APPROVED)} className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg text-sm font-medium shadow-sm transition-colors">
                 Approve ({selectedIds.size})
               </button>
               <button onClick={() => handleBulkAction(LogStatus.REJECTED)} className="bg-white border border-red-200 text-red-600 hover:bg-red-50 px-4 py-2 rounded-lg text-sm font-medium shadow-sm transition-colors">
                 Reject
               </button>
            </div>
          )}
        </div>
      </div>

      {/* Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 text-gray-500 uppercase font-semibold">
              <tr>
                {viewMode === 'PENDING' && (
                   <th className="px-6 py-4 w-12">
                      <button onClick={toggleSelectAll} className="text-gray-400 hover:text-indigo-600">
                        {selectedIds.size > 0 && selectedIds.size === filteredLogs.length ? <CheckSquare size={18} /> : <Square size={18} />}
                      </button>
                   </th>
                )}
                <th className="px-6 py-4">Mentor / Module</th>
                <th className="px-6 py-4">Date & Time</th>
                <th className="px-6 py-4">Evidence</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredLogs.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-gray-400 flex flex-col items-center gap-2">
                    <Search className="w-8 h-8 opacity-20" />
                    No logs found matching criteria.
                  </td>
                </tr>
              ) : filteredLogs.map(log => (
                <tr key={log.id} className={`hover:bg-gray-50 transition-colors ${selectedIds.has(log.id) ? 'bg-indigo-50' : ''}`}>
                  {viewMode === 'PENDING' && (
                    <td className="px-6 py-4">
                      <button onClick={() => toggleSelection(log.id)} className={`text-gray-400 hover:text-indigo-600 ${selectedIds.has(log.id) ? 'text-indigo-600' : ''}`}>
                        {selectedIds.has(log.id) ? <CheckSquare size={18} /> : <Square size={18} />}
                      </button>
                    </td>
                  )}
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <img src={users.find(u => u.id === log.mentorId)?.avatarUrl} className="w-8 h-8 rounded-full border border-gray-200" alt="" />
                      <div>
                        <div className="font-medium text-gray-900">{users.find(u => u.id === log.mentorId)?.fullName}</div>
                        <div className="text-xs text-gray-500">{getModuleName(log.moduleId)}</div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="font-medium text-gray-900">{log.date}</div>
                    <div className="text-xs text-gray-500">{log.startTime} - {log.endTime} ({log.durationMinutes}m)</div>
                  </td>
                  <td className="px-6 py-4">
                    <a href={log.artifactUrl} target="_blank" rel="noreferrer" className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-gray-100 text-gray-600 hover:bg-indigo-100 hover:text-indigo-700 transition-colors text-xs font-medium">
                      <ExternalLink size={12} /> View Artifact
                    </a>
                  </td>
                  <td className="px-6 py-4">
                     <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium
                        ${log.status === LogStatus.APPROVED ? 'bg-green-100 text-green-800' : 
                          log.status === LogStatus.REJECTED ? 'bg-red-100 text-red-800' : 
                          'bg-yellow-100 text-yellow-800'}`}>
                        {log.status}
                     </span>
                     {log.isPayable && log.status !== LogStatus.REJECTED && (
                       <span className="ml-2 text-xs font-semibold text-gray-500">฿{log.paymentAmount.toLocaleString()}</span>
                     )}
                  </td>
                  <td className="px-6 py-4 text-right">
                    {log.status === LogStatus.PENDING ? (
                       <div className="flex justify-end gap-2">
                           <button onClick={() => { onUpdateStatus(log.id, LogStatus.APPROVED); setNotification("Log Approved"); setTimeout(() => setNotification(null), 2000); }} className="p-1 text-green-600 hover:bg-green-50 rounded">
                             <CheckCircle size={18} />
                           </button>
                           <button onClick={() => { onUpdateStatus(log.id, LogStatus.REJECTED); setNotification("Log Rejected"); setTimeout(() => setNotification(null), 2000); }} className="p-1 text-red-600 hover:bg-red-50 rounded">
                             <XCircle size={18} />
                           </button>
                       </div>
                    ) : (
                       <span className="text-xs text-gray-400">Processed</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

// --- Tab: People (Mentors & Students) ---
const PeopleTab: React.FC<{ users: User[], logs: MentoringLog[] }> = ({ users, logs }) => {
  const [subTab, setSubTab] = useState<'MENTORS' | 'STUDENTS'>('STUDENTS');

  const mentors = users.filter(u => u.role === Role.MENTOR).map(mentor => {
    const mentorLogs = logs.filter(l => l.mentorId === mentor.id && l.status === LogStatus.APPROVED);
    const totalHours = mentorLogs.reduce((acc, l) => acc + l.durationMinutes, 0) / 60;
    const totalEarned = mentorLogs.reduce((acc, l) => acc + l.paymentAmount, 0);
    return { ...mentor, totalHours, totalEarned, sessionCount: mentorLogs.length };
  });

  const students = users.filter(u => u.role === Role.STUDENT).map(student => {
    const studentScores = logs.flatMap(l => l.scores.filter(s => s.studentId === student.id));
    const avgScore = studentScores.length ? (studentScores.reduce((acc, s) => acc + s.business + s.creativity + s.discipline, 0) / (studentScores.length * 3)) : 0;
    const absences = studentScores.filter(s => s.attendance === AttendanceStatus.ABSENT).length;
    const isRedFlag = avgScore > 0 && (avgScore < 2.5 || absences >= 2);
    return { ...student, avgScore: avgScore.toFixed(2), absences, isRedFlag, sessionCount: studentScores.length };
  });

  const sendIDPPlan = (name: string) => {
    alert(`IDP Plan sent to ${name} via Email and Line OA.`);
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Sub-nav */}
      <div className="flex border-b border-gray-200">
         <button 
           onClick={() => setSubTab('STUDENTS')}
           className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${subTab === 'STUDENTS' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
         >
           Students & Performance
         </button>
         <button 
           onClick={() => setSubTab('MENTORS')}
           className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${subTab === 'MENTORS' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
         >
           Mentors & Payroll
         </button>
      </div>

      {subTab === 'STUDENTS' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {students.map(student => (
            <div key={student.id} className={`bg-white rounded-xl p-5 border shadow-sm transition-shadow hover:shadow-md ${student.isRedFlag ? 'border-red-200 ring-1 ring-red-100' : 'border-gray-100'}`}>
              <div className="flex items-start justify-between">
                <div className="flex items-center gap-3">
                  <img src={student.avatarUrl} className="w-12 h-12 rounded-full" alt="" />
                  <div>
                    <h4 className="font-bold text-gray-900">{student.fullName}</h4>
                    <p className="text-xs text-gray-500">{student.batchId === 'b1' ? 'Batch 5' : 'Batch 6'}</p>
                  </div>
                </div>
                {student.isRedFlag && <span className="bg-red-100 text-red-700 text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wide">At Risk</span>}
              </div>

              <div className="mt-4 grid grid-cols-2 gap-2 text-center">
                 <div className="bg-gray-50 rounded-lg p-2">
                    <p className="text-xs text-gray-500">Avg Competency</p>
                    <p className={`font-bold text-lg ${parseFloat(student.avgScore) < 2.5 && parseFloat(student.avgScore) > 0 ? 'text-red-600' : 'text-gray-800'}`}>
                      {student.avgScore}
                    </p>
                 </div>
                 <div className="bg-gray-50 rounded-lg p-2">
                    <p className="text-xs text-gray-500">Absences</p>
                    <p className={`font-bold text-lg ${student.absences >= 2 ? 'text-red-600' : 'text-gray-800'}`}>{student.absences}</p>
                 </div>
              </div>

              {student.isRedFlag && (
                <button 
                  onClick={() => sendIDPPlan(student.fullName)}
                  className="mt-4 w-full flex items-center justify-center gap-2 bg-red-50 text-red-700 text-sm font-medium py-2 rounded-lg hover:bg-red-100 transition-colors"
                >
                  <Mail size={14} /> Send IDP Plan
                </button>
              )}
            </div>
          ))}
        </div>
      )}

      {subTab === 'MENTORS' && (
         <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
           <table className="w-full text-sm text-left">
             <thead className="bg-gray-50 text-gray-500 uppercase">
               <tr>
                 <th className="px-6 py-4">Mentor</th>
                 <th className="px-6 py-4">Total Sessions</th>
                 <th className="px-6 py-4">Teaching Hours</th>
                 <th className="px-6 py-4">Total Earned</th>
                 <th className="px-6 py-4 text-right">Status</th>
               </tr>
             </thead>
             <tbody className="divide-y divide-gray-100">
               {mentors.map(mentor => (
                 <tr key={mentor.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <img src={mentor.avatarUrl} className="w-8 h-8 rounded-full" alt="" />
                        <div>
                           <div className="font-medium text-gray-900">{mentor.fullName}</div>
                           <div className="text-xs text-gray-500">{mentor.email}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">{mentor.sessionCount}</td>
                    <td className="px-6 py-4">{mentor.totalHours.toFixed(1)} hrs</td>
                    <td className="px-6 py-4 font-bold text-green-600">฿{mentor.totalEarned.toLocaleString()}</td>
                    <td className="px-6 py-4 text-right">
                       <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                         Active
                       </span>
                    </td>
                 </tr>
               ))}
             </tbody>
           </table>
         </div>
      )}
    </div>
  );
};

// --- Tab: System Setup (Creation) ---
const SetupTab: React.FC<{ 
    batches: Batch[],
    modules: Module[],
    onAddBatch: (b: Batch) => void,
    onAddModule: (m: Module) => void,
    onAddUser: (u: User) => void
}> = ({ batches, modules, onAddBatch, onAddModule, onAddUser }) => {
    // Local state for forms
    const [batchName, setBatchName] = useState('');
    const [moduleForm, setModuleForm] = useState({ batchId: '', name: '', hourlyRate: 1200 });
    const [userForm, setUserForm] = useState({ role: Role.STUDENT, fullName: '', email: '', batchId: '' });
    const [msg, setMsg] = useState('');

    const handleCreateBatch = (e: React.FormEvent) => {
        e.preventDefault();
        onAddBatch({
            id: `b-${Date.now()}`,
            name: batchName
        });
        setBatchName('');
        setMsg('Batch created successfully!');
        setTimeout(() => setMsg(''), 3000);
    };

    const handleCreateModule = (e: React.FormEvent) => {
      e.preventDefault();
      onAddModule({
          id: `m-${Date.now()}`,
          batchId: moduleForm.batchId,
          name: moduleForm.name,
          hourlyRate: moduleForm.hourlyRate
      });
      setModuleForm({ ...moduleForm, name: '', hourlyRate: 1200 });
      setMsg('Teaching Module created successfully!');
      setTimeout(() => setMsg(''), 3000);
    };

    const handleCreateUser = (e: React.FormEvent) => {
        e.preventDefault();
        const newUser: User = {
            id: `u-${Date.now()}`,
            role: userForm.role,
            fullName: userForm.fullName,
            email: userForm.email,
            avatarUrl: `https://i.pravatar.cc/150?u=${Date.now()}`,
            batchId: userForm.role === Role.STUDENT ? userForm.batchId : undefined
        };
        onAddUser(newUser);
        setUserForm({ ...userForm, fullName: '', email: '' });
        setMsg(`${userForm.role === Role.MENTOR ? 'Mentor' : 'Student'} added successfully!`);
        setTimeout(() => setMsg(''), 3000);
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in">
            {/* Column 1: Structure Management */}
            <div className="space-y-8">
                {/* 1. Batch Creation */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                    <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
                        <Layers className="w-5 h-5 text-indigo-600" /> Create Batch
                    </h3>
                    <form onSubmit={handleCreateBatch} className="flex gap-2">
                        <input 
                            required
                            type="text" 
                            placeholder="e.g. Gen 9"
                            className="flex-1 rounded-lg border-gray-300 p-2 border focus:ring-2 focus:ring-indigo-500"
                            value={batchName}
                            onChange={e => setBatchName(e.target.value)}
                        />
                        <button type="submit" className="bg-indigo-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-indigo-700 transition-colors flex items-center gap-2">
                            <Plus size={18} /> Add
                        </button>
                    </form>

                    {/* List Batches */}
                    <div className="mt-4 flex flex-wrap gap-2">
                       {batches.map(b => (
                         <span key={b.id} className="bg-gray-100 text-gray-700 px-3 py-1 rounded-full text-xs font-medium border border-gray-200">
                           {b.name}
                         </span>
                       ))}
                    </div>
                </div>

                {/* 2. Module Creation */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                    <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
                        <BookOpen className="w-5 h-5 text-indigo-600" /> Create Teaching Module
                    </h3>
                    <form onSubmit={handleCreateModule} className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Select Batch</label>
                            <select 
                                required
                                className="w-full rounded-lg border-gray-300 p-2 border focus:ring-2 focus:ring-indigo-500"
                                value={moduleForm.batchId}
                                onChange={e => setModuleForm({...moduleForm, batchId: e.target.value})}
                            >
                                <option value="">Select a Batch...</option>
                                {batches.map(b => (
                                    <option key={b.id} value={b.id}>{b.name}</option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Module Name</label>
                            <input 
                                required
                                type="text" 
                                placeholder="e.g. Advanced Data Engineering"
                                className="w-full rounded-lg border-gray-300 p-2 border focus:ring-2 focus:ring-indigo-500"
                                value={moduleForm.name}
                                onChange={e => setModuleForm({...moduleForm, name: e.target.value})}
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Hourly Rate (THB)</label>
                            <input 
                                type="number" 
                                className="w-full rounded-lg border-gray-300 p-2 border focus:ring-2 focus:ring-indigo-500"
                                value={moduleForm.hourlyRate}
                                onChange={e => setModuleForm({...moduleForm, hourlyRate: parseInt(e.target.value)})}
                            />
                        </div>
                        <button type="submit" className="w-full bg-indigo-600 text-white py-2 rounded-lg font-medium hover:bg-indigo-700 transition-colors flex justify-center items-center gap-2">
                            <Plus size={18} /> Add Module
                        </button>
                    </form>

                    <div className="mt-6 border-t pt-4">
                        <h4 className="text-xs font-bold text-gray-400 uppercase mb-2">Existing Modules</h4>
                        <div className="space-y-2 max-h-40 overflow-y-auto">
                           {modules.map(m => (
                             <div key={m.id} className="flex justify-between items-center text-sm p-2 bg-gray-50 rounded">
                                <span>{m.name} <span className="text-gray-400">({batches.find(b=>b.id===m.batchId)?.name})</span></span>
                                <span className="font-mono text-gray-600">฿{m.hourlyRate}</span>
                             </div>
                           ))}
                        </div>
                    </div>
                </div>
            </div>

            {/* Column 2: User Registration */}
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-fit">
                <h3 className="text-lg font-bold text-gray-800 mb-6 flex items-center gap-2">
                    <Users className="w-5 h-5 text-indigo-600" /> User Registration
                </h3>

                {/* Role Toggle */}
                <div className="flex bg-gray-100 p-1 rounded-lg mb-6">
                    <button 
                        type="button"
                        onClick={() => setUserForm({...userForm, role: Role.STUDENT})}
                        className={`flex-1 py-2 text-sm font-medium rounded-md transition-all flex justify-center items-center gap-2 ${userForm.role === Role.STUDENT ? 'bg-white shadow text-indigo-600' : 'text-gray-500'}`}
                    >
                        <GraduationCap size={16} /> Add Student
                    </button>
                    <button 
                        type="button"
                        onClick={() => setUserForm({...userForm, role: Role.MENTOR})}
                        className={`flex-1 py-2 text-sm font-medium rounded-md transition-all flex justify-center items-center gap-2 ${userForm.role === Role.MENTOR ? 'bg-white shadow text-indigo-600' : 'text-gray-500'}`}
                    >
                        <Briefcase size={16} /> Add Mentor
                    </button>
                </div>

                <form onSubmit={handleCreateUser} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Full Name</label>
                        <input 
                            required
                            type="text" 
                            placeholder="e.g. Somchai Jai-dee"
                            className="w-full rounded-lg border-gray-300 p-2 border focus:ring-2 focus:ring-indigo-500"
                            value={userForm.fullName}
                            onChange={e => setUserForm({...userForm, fullName: e.target.value})}
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Email Address</label>
                        <input 
                            required
                            type="email" 
                            placeholder="somchai@example.com"
                            className="w-full rounded-lg border-gray-300 p-2 border focus:ring-2 focus:ring-indigo-500"
                            value={userForm.email}
                            onChange={e => setUserForm({...userForm, email: e.target.value})}
                        />
                    </div>

                    {userForm.role === Role.STUDENT && (
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Assign to Batch</label>
                            <select 
                                required
                                className="w-full rounded-lg border-gray-300 p-2 border focus:ring-2 focus:ring-indigo-500"
                                value={userForm.batchId}
                                onChange={e => setUserForm({...userForm, batchId: e.target.value})}
                            >
                                <option value="">Select a Batch...</option>
                                {batches.map(b => (
                                    <option key={b.id} value={b.id}>{b.name}</option>
                                ))}
                            </select>
                        </div>
                    )}

                    <button type="submit" className="w-full bg-indigo-600 text-white py-2 rounded-lg font-medium hover:bg-indigo-700 transition-colors mt-4">
                        Register {userForm.role === Role.STUDENT ? 'Student' : 'Mentor'}
                    </button>
                </form>

                {msg && (
                    <div className="mt-4 p-3 bg-green-50 text-green-700 text-sm rounded-lg flex items-center gap-2">
                        <CheckCircle size={16} /> {msg}
                    </div>
                )}
            </div>
        </div>
    );
};


