                                <p className="font-semibold text-gray-800">{mentor.bankInfo.bankName}</p>
                                <p className="text-gray-500 font-mono">{mentor.bankInfo.accountNumber}</p>
                                <p className="text-gray-400">{mentor.bankInfo.accountName}</p>
                            </div>
                        ) : (
                            <span className="text-xs text-gray-400 italic">Not set</span>
                        )}
                    </td>
                    <td className="px-6 py-4">{mentor.totalHours.toFixed(1)} hrs</td>
                    <td className="px-6 py-4 font-bold text-green-600">฿{mentor.totalEarned.toLocaleString()}</td>
                    <td className="px-6 py-4 text-right">
                       <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                         Active
                       </span>
                    </td>
                 </tr>
               ))}
             </tbody>
           </table>
         </div>
      )}
    </div>
  );
};

// --- Tab: System Setup (Creation) ---
const SetupTab: React.FC<{ 
    batches: Batch[],
    modules: Module[],
    onAddBatch: (b: Batch) => void,
    onAddModule: (m: Module) => void,
    onAddUser: (u: User) => void
}> = ({ batches, modules, onAddBatch, onAddModule, onAddUser }) => {

    // Forms State
    const [batchForm, setBatchForm] = useState({ name: '', startDate: '', endDate: '' });
    const [moduleForm, setModuleForm] = useState({ batchId: '', name: '', hourlyRate: 1200 });
    const [userForm, setUserForm] = useState({ 
        role: Role.STUDENT, 
        fullName: '', 
        email: '', 
        batchId: '',
        // Mentor Bank Info
        bankName: '',
        accountNumber: '',
        accountName: ''
    });

    const [msg, setMsg] = useState('');

    const handleCreateBatch = (e: React.FormEvent) => {
        e.preventDefault();
        onAddBatch({
            id: `b-${Date.now()}`,
            name: batchForm.name,
            startDate: batchForm.startDate,
            endDate: batchForm.endDate,
            status: 'ACTIVE'
        });
        setBatchForm({ name: '', startDate: '', endDate: '' });
        setMsg('Batch created successfully!');
        setTimeout(() => setMsg(''), 3000);
    };

    const handleCreateModule = (e: React.FormEvent) => {
      e.preventDefault();
      onAddModule({
          id: `m-${Date.now()}`,
          batchId: moduleForm.batchId,
          name: moduleForm.name,
          hourlyRate: moduleForm.hourlyRate
      });
      setModuleForm({ ...moduleForm, name: '', hourlyRate: 1200 });
      setMsg('Teaching Module created successfully!');
      setTimeout(() => setMsg(''), 3000);
    };

    const handleCreateUser = (e: React.FormEvent) => {
        e.preventDefault();
        const newUser: User = {
            id: `u-${Date.now()}`,
            role: userForm.role,
            fullName: userForm.fullName,
            email: userForm.email,
            avatarUrl: `https://i.pravatar.cc/150?u=${Date.now()}`,
            batchId: userForm.role === Role.STUDENT ? userForm.batchId : undefined,
            bankInfo: userForm.role === Role.MENTOR && userForm.bankName ? {
                bankName: userForm.bankName,
                accountNumber: userForm.accountNumber,
                accountName: userForm.accountName
            } : undefined
        };
        onAddUser(newUser);

        // Reset
        setUserForm(prev => ({ 
            ...prev, 
            fullName: '', 
            email: '', 
            bankName: '', 
            accountNumber: '', 
            accountName: '' 
        }));

        setMsg(`${userForm.role === Role.MENTOR ? 'Mentor' : 'Student'} added successfully!`);
        setTimeout(() => setMsg(''), 3000);
    };

    const handleBulkUpload = () => {
        // Mocking a file upload process
        const mockUsers: User[] = [
             { id: `u-bulk-${Date.now()}-1`, role: Role.STUDENT, fullName: 'Bulk Student 1', email: 'bulk1@gennext.com', batchId: batches[0]?.id },
             { id: `u-bulk-${Date.now()}-2`, role: Role.STUDENT, fullName: 'Bulk Student 2', email: 'bulk2@gennext.com', batchId: batches[0]?.id },
             { id: `u-bulk-${Date.now()}-3`, role: Role.MENTOR, fullName: 'Bulk Mentor 1', email: 'bulk.mentor@gennext.com' }
        ];
        mockUsers.forEach(u => onAddUser(u));
        setMsg(`Imported ${mockUsers.length} users successfully!`);
        setTimeout(() => setMsg(''), 3000);
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in pb-10">
            {/* Column 1: Batch & Module Management */}
            <div className="space-y-8">
                {/* 1. Batch Creation */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                    <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
                        <Layers className="w-5 h-5 text-indigo-600" /> Batch Management
                    </h3>
                    <form onSubmit={handleCreateBatch} className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Batch Name (Cohort)</label>
                            <input 
                                required
                                type="text" 
                                placeholder="e.g. Gen 9"
                                className="w-full rounded-lg border-gray-300 p-2 border focus:ring-2 focus:ring-indigo-500"
                                value={batchForm.name}
                                onChange={e => setBatchForm({...batchForm, name: e.target.value})}
                            />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Start Date</label>
                                <input 
                                    required
                                    type="date" 
                                    className="w-full rounded-lg border-gray-300 p-2 border focus:ring-2 focus:ring-indigo-500"
                                    value={batchForm.startDate}
                                    onChange={e => setBatchForm({...batchForm, startDate: e.target.value})}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">End Date</label>
