export const AdminDashboard: React.FC = () => {
  const { logs, users, batches, modules, updateLogStatus, addBatch, addModule, addUser } = useData();
  const [activeTab, setActiveTab] = useState<'OVERVIEW' | 'APPROVALS' | 'PEOPLE' | 'SETUP'>('OVERVIEW');

  // Handlers
  const handleNavigateToRedFlags = () => {
    setActiveTab('PEOPLE');
  };

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 tracking-tight">Admin Portal</h2>
          <p className="text-gray-500">Manage program compliance, budget, and performance.</p>
        </div>

        {/* Navigation Tabs */}
        <div className="bg-white p-1 rounded-xl shadow-sm border border-gray-200 inline-flex overflow-x-auto">
           {[
             { id: 'OVERVIEW', label: 'Overview', icon: LayoutGrid },
             { id: 'APPROVALS', label: 'Log Approvals', icon: CheckSquare },
             { id: 'PEOPLE', label: 'People', icon: Users },
             { id: 'SETUP', label: 'System Setup', icon: Settings },
           ].map(tab => (
             <button
               key={tab.id}
               onClick={() => setActiveTab(tab.id as any)}
               className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                 activeTab === tab.id 
                 ? 'bg-indigo-600 text-white shadow-sm' 
                 : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'
               }`}
             >
               <tab.icon size={16} />
               <span className="hidden md:inline">{tab.label}</span>
             </button>
           ))}
        </div>
      </div>

      {/* Content Area */}
      <div className="min-h-[500px]">
        {activeTab === 'OVERVIEW' && <OverviewTab logs={logs} users={users} onNavigateToRedFlags={handleNavigateToRedFlags} />}
        {activeTab === 'APPROVALS' && <ApprovalsTab logs={logs} users={users} modules={modules} onUpdateStatus={updateLogStatus} />}
        {activeTab === 'PEOPLE' && <PeopleTab users={users} logs={logs} />}
        {activeTab === 'SETUP' && <SetupTab batches={batches} modules={modules} onAddBatch={addBatch} onAddModule={addModule} onAddUser={addUser} />}
      </div>
    </div>
  );
};

export enum Role {
  ADMIN = 'ADMIN',
  MENTOR = 'MENTOR',
  STUDENT = 'STUDENT'
}

export enum LogStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED'
}

export enum AttendanceStatus {
  PRESENT = 'PRESENT',
  LATE = 'LATE',
  ABSENT = 'ABSENT'
}

export interface BankInfo {
  bankName: string;
  accountNumber: string;
  accountName: string;
}

export interface User {
  id: string;
  role: Role;
  fullName: string;
  email: string;
  avatarUrl?: string;
  // Specific to students
  batchId?: string;
  // Specific to mentors
  bankInfo?: BankInfo;
}

export interface Batch {
  id: string;
  name: string; // e.g. "Gen 8"
  startDate: string; // ISO Date YYYY-MM-DD
  endDate: string; // ISO Date YYYY-MM-DD
  status: 'ACTIVE' | 'CLOSED';
}

export interface Module {
  id: string;
  batchId: string;
  name: string; // e.g. "Data Science"
  hourlyRate: number;
}

export interface Group {
  id: string;
  moduleId: string;
  name: string; // e.g. "Group A"
  mentorIds: string[]; // Supports multiple mentors if needed, but UI will focus on mapping
  studentIds: string[];
}

export interface CompetencyScore {
  studentId: string;
  attendance: AttendanceStatus;
  business: number; // 0-5
  creativity: number; // 0-5
  discipline: number; // 0-5
}

export interface MentoringLog {
  id: string;
  mentorId: string;
  batchId: string;
  moduleId: string; // Link to specific module
  date: string;
  startTime: string; // HH:mm
  endTime: string; // HH:mm
  durationMinutes: number;
  isPayable: boolean;
  status: LogStatus;
  summaryNote: string;
  artifactUrl: string;
  scores: CompetencyScore[]; // One entry per student in the session
  paymentAmount: number;
}

export interface SessionValidation {
  isValid: boolean;
  message: string;
  duration: number;
  isPayable: boolean;
}

