                           <div className="text-xs text-gray-500">{mentor.email}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                        {mentor.bankInfo ? (
                            <div className="text-xs">
                                <p className="font-semibold text-gray-800">{mentor.bankInfo.bankName}</p>
                                <p className="text-gray-500 font-mono">{mentor.bankInfo.accountNumber}</p>
                                <p className="text-gray-400">{mentor.bankInfo.accountName}</p>
                            </div>
                        ) : (
                            <span className="text-xs text-gray-400 italic">Not set</span>
                        )}
                    </td>
                    <td className="px-6 py-4">{mentor.totalHours.toFixed(1)} hrs</td>
                    <td className="px-6 py-4 font-bold text-green-600">฿{mentor.totalEarned.toLocaleString()}</td>
                    <td className="px-6 py-4 text-right">
                       <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                         Active
                       </span>
                    </td>
                 </tr>
               ))}
             </tbody>
           </table>
         </div>
      )}
    </div>
  );
};

// --- System Setup: Group Mapping Sub-Component ---
const GroupMappingSection: React.FC<{
  batches: Batch[],
  modules: Module[],
  groups: Group[],
  users: User[],
  onAddGroup: (g: Group) => void,
  onUpdateGroup: (g: Group) => void
}> = ({ batches, modules, groups, users, onAddGroup, onUpdateGroup }) => {
  const [selectedBatchId, setSelectedBatchId] = useState(batches[0]?.id || '');
  const [selectedModuleId, setSelectedModuleId] = useState('');
  const [newGroupName, setNewGroupName] = useState('');

  const filteredModules = modules.filter(m => m.batchId === selectedBatchId);
  const filteredGroups = groups.filter(g => g.moduleId === selectedModuleId);
  const availableStudents = users.filter(u => u.role === Role.STUDENT && u.batchId === selectedBatchId);
  const mentors = users.filter(u => u.role === Role.MENTOR);

  const handleAddGroup = () => {
    if (!selectedModuleId || !newGroupName) return;
    onAddGroup({
      id: `g-${Date.now()}`,
      moduleId: selectedModuleId,
      name: newGroupName,
      mentorIds: [],
      studentIds: []
    });
    setNewGroupName('');
  };

  const handleAssignMentor = (groupId: string, mentorId: string) => {
    const group = groups.find(g => g.id === groupId);
    if (!group) return;
    onUpdateGroup({ ...group, mentorIds: [mentorId] }); // Assign 1 mentor
  };

  const handleAddStudentToGroup = (groupId: string, studentId: string) => {
    const group = groups.find(g => g.id === groupId);
    if (!group) return;
    // Remove from other groups in this module first (transfer logic)
    const otherGroupsInModule = groups.filter(g => g.moduleId === selectedModuleId && g.id !== groupId);
    otherGroupsInModule.forEach(og => {
       if (og.studentIds.includes(studentId)) {
         onUpdateGroup({...og, studentIds: og.studentIds.filter(id => id !== studentId)});
       }
    });
    // Add to this group
    if (!group.studentIds.includes(studentId)) {
      onUpdateGroup({ ...group, studentIds: [...group.studentIds, studentId] });
    }
  };

  const handleRemoveStudentFromGroup = (groupId: string, studentId: string) => {
    const group = groups.find(g => g.id === groupId);
    if (!group) return;
    onUpdateGroup({ ...group, studentIds: group.studentIds.filter(id => id !== studentId) });
  };

  return (
    <div className="space-y-6">
       {/* Filters */}
       <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Select Batch</label>
            <select 
              className="w-full rounded-lg border-gray-300 p-2 border text-sm"
              value={selectedBatchId}
              onChange={e => setSelectedBatchId(e.target.value)}
            >
              {batches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Select Module</label>
            <select 
              className="w-full rounded-lg border-gray-300 p-2 border text-sm"
              value={selectedModuleId}
              onChange={e => setSelectedModuleId(e.target.value)}
            >
              <option value="">Select a Module...</option>
              {filteredModules.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
          </div>
       </div>

       {selectedModuleId && (
         <div className="space-y-6 animate-fade-in">
           {/* Create Group */}
           <div className="flex gap-2 items-center bg-gray-50 p-4 rounded-lg border border-gray-200">
              <input 
                type="text" 
                placeholder="New Group Name (e.g. Group A)" 
                className="flex-1 rounded border-gray-300 p-2 text-sm"
                value={newGroupName}
                onChange={e => setNewGroupName(e.target.value)}
              />
              <button onClick={handleAddGroup} className="bg-indigo-600 text-white px-4 py-2 rounded text-sm font-medium hover:bg-indigo-700 flex items-center gap-2">
                <Plus size={16} /> Create Group
              </button>
           </div>

           {/* Mapping Interface */}
           <div className="grid grid-cols-1 gap-6">
             {filteredGroups.map(group => (
               <div key={group.id} className="bg-white border border-gray-200 rounded-xl shadow-sm p-4">
                  <div className="flex justify-between items-center border-b pb-3 mb-3">
                     <h4 className="font-bold text-gray-800">{group.name}</h4>
                     <div className="flex items-center gap-2">
                       <span className="text-xs text-gray-500">Mentor:</span>
                       <select 
                          className="text-sm border-gray-300 rounded p-1"
                          value={group.mentorIds[0] || ''}
                          onChange={(e) => handleAssignMentor(group.id, e.target.value)}
                       >
                         <option value="">-- Assign Mentor --</option>
                         {mentors.map(m => <option key={m.id} value={m.id}>{m.fullName}</option>)}
                       </select>
                     </div>
                  </div>

                  <div className="flex flex-col md:flex-row gap-4">
                     {/* Assigned Students */}
                     <div className="flex-1 bg-indigo-50 rounded-lg p-3">
                        <p className="text-xs font-bold text-indigo-800 uppercase mb-2 flex items-center gap-2">
                          <Users size={14} /> Assigned Students ({group.studentIds.length})
                        </p>
                        <ul className="space-y-1">
                          {group.studentIds.map(sid => {
                            const student = users.find(u => u.id === sid);
                            return (
                              <li key={sid} className="flex justify-between items-center bg-white p-2 rounded text-sm shadow-sm">
                                <span>{student?.fullName || 'Unknown'}</span>
                                <button onClick={() => handleRemoveStudentFromGroup(group.id, sid)} className="text-red-500 hover:bg-red-50 rounded p-1">
                                  <UserMinus size={14} />
                                </button>
                              </li>
                            );
                          })}
                          {group.studentIds.length === 0 && <li className="text-xs text-gray-400 italic">No students assigned</li>}
                        </ul>
                     </div>

                     {/* Transfer Controls (Simplified) */}
                     <div className="flex flex-col justify-center items-center text-gray-400">
                        <ArrowLeft size={20} className="hidden md:block" />
                        <span className="text-xs my-1">Transfer</span>
                     </div>

                     {/* Unassigned / Available Students */}
                     <div className="flex-1 bg-gray-50 rounded-lg p-3">
                        <p className="text-xs font-bold text-gray-500 uppercase mb-2">Available in Batch</p>
                        <ul className="space-y-1 max-h-40 overflow-y-auto">
                          {availableStudents.filter(s => !group.studentIds.includes(s.id)).map(s => {
                             // Check if student is in another group for THIS module
                             const inOtherGroup = groups.some(og => og.moduleId === selectedModuleId && og.id !== group.id && og.studentIds.includes(s.id));
                             return (
                              <li key={s.id} className="flex justify-between items-center bg-white p-2 rounded text-sm border border-gray-100">
                                <span className={inOtherGroup ? "text-gray-400" : "text-gray-800"}>
                                  {s.fullName} {inOtherGroup && "(Moved)"}
                                </span>
                                <button onClick={() => handleAddStudentToGroup(group.id, s.id)} className="text-green-600 hover:bg-green-50 rounded p-1">
                                  {inOtherGroup ? <ArrowRight size={14} /> : <UserPlus size={14} />}
                                </button>
                              </li>
                             );
                          })}
                        </ul>
                     </div>
                  </div>
               </div>
             ))}
             {filteredGroups.length === 0 && <p className="text-center text-gray-400 py-4">No groups created for this module yet.</p>}
           </div>
         </div>
       )}
    </div>
  );
};


// --- Tab: System Setup (Creation) ---
const SetupTab: React.FC<{ 
