                        </div>
                        <div className="mt-4 flex justify-between items-center text-xs text-gray-500">
                            <span>Template.xlsx</span>
                            <a href="#" className="text-indigo-600 hover:underline">Download Template</a>
                        </div>
                    </div>

                    {msg && (
                        <div className="p-3 bg-green-50 text-green-700 text-sm rounded-lg flex items-center gap-2 border border-green-100 shadow-sm animate-bounce">
                            <CheckCircle size={16} /> {msg}
                        </div>
                    )}
                </div>
            </div>
            )}
        </div>
    );
