import React, { useState, useEffect } from 'react';
import { useData } from '../services/DataContext';
import { AttendanceStatus, CompetencyScore, LogStatus, MentoringLog } from '../types';
import { Clock, Users, Save, AlertCircle, Link as LinkIcon, Upload } from 'lucide-react';

export const MentorLogForm: React.FC = () => {
  const { batches, getModulesByBatch, currentUser, getStudentsByBatch, addLog } = useData();

  // Local State
  const [selectedBatchId, setSelectedBatchId] = useState(batches[0]?.id || '');
  const [selectedModuleId, setSelectedModuleId] = useState('');

  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [summary, setSummary] = useState('');
  const [artifactUrl, setArtifactUrl] = useState('');
  const [scores, setScores] = useState<CompetencyScore[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  const students = getStudentsByBatch(selectedBatchId);
  const modules = getModulesByBatch(selectedBatchId);

  // Auto-select first module if available when batch changes
  useEffect(() => {
    if (modules.length > 0) {
      setSelectedModuleId(modules[0].id);
    } else {
      setSelectedModuleId('');
    }
  }, [selectedBatchId, modules]);

  // Initialize scores when students change
  useEffect(() => {
    if (students.length > 0) {
      const initialScores: CompetencyScore[] = students.map(s => ({
        studentId: s.id,
        attendance: AttendanceStatus.PRESENT,
        business: 3,
        creativity: 3,
        discipline: 3
      }));
      setScores(initialScores);
    }
  }, [selectedBatchId, students.length]); 

  const calculateDuration = () => {
    if (!startTime || !endTime) return 0;
    const start = new Date(`2000-01-01T${startTime}`);
    const end = new Date(`2000-01-01T${endTime}`);
    const diffMs = end.getTime() - start.getTime();
    return Math.max(0, Math.floor(diffMs / 60000));
  };

  const duration = calculateDuration();
  const isEligible = duration >= 50;

  const handleScoreChange = (studentId: string, field: keyof CompetencyScore, value: any) => {
    setScores(prev => prev.map(s => s.studentId === studentId ? { ...s, [field]: value } : s));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedModuleId) {
        alert("Please select a teaching module.");
        return;
    }
    if (!artifactUrl) {
      alert("Please provide an artifact link (Proof of work).");
      return;
    }

    setIsSubmitting(true);

    const module = modules.find(m => m.id === selectedModuleId);
    const hourlyRate = module ? module.hourlyRate : 1200;

    const newLog: MentoringLog = {
      id: `log-${Date.now()}`,
      mentorId: currentUser.id,
      batchId: selectedBatchId,
      moduleId: selectedModuleId,
      date,
      startTime,
      endTime,
      durationMinutes: duration,
      isPayable: isEligible,
      status: LogStatus.PENDING,
      summaryNote: summary,
      artifactUrl,
      scores,
      paymentAmount: isEligible ? hourlyRate : 0,
      history: []
    };

    setTimeout(() => {
        addLog(newLog);
        setIsSubmitting(false);
        setSuccessMsg("Log submitted successfully!");
        setSummary('');
        setArtifactUrl('');
        setTimeout(() => setSuccessMsg(''), 3000);
    }, 800);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="p-6 border-b border-gray-100 bg-indigo-50">
        <h2 className="text-xl font-bold text-indigo-900 flex items-center gap-2">
            <Clock className="w-5 h-5" /> New Session Log
        </h2>
        <p className="text-sm text-indigo-600 mt-1">Record your mentoring activity and assess students.</p>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-8">
        {/* Section 1: Session Details */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Batch (Cohort)</label>
            <select 
              value={selectedBatchId}
              onChange={(e) => setSelectedBatchId(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
            >
              {batches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Teaching Module</label>
            <select 
              value={selectedModuleId}
              onChange={(e) => setSelectedModuleId(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
              disabled={modules.length === 0}
            >
              {modules.length === 0 && <option>No modules found</option>}
              {modules.map(m => <option key={m.id} value={m.id}>{m.name} (฿{m.hourlyRate}/hr)</option>)}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Date</label>
            <input 
              type="date" 
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
                <label className="block text-xs font-medium text-gray-500 uppercase mb-1">Start Time</label>
                <input 
                    type="time" 
                    value={startTime}
                    onChange={(e) => setStartTime(e.target.value)}
                    className="w-full rounded-lg border-gray-300 p-2 border"
                    required
                />
             </div>
             <div>
                <label className="block text-xs font-medium text-gray-500 uppercase mb-1">End Time</label>
                <input 
                    type="time" 
                    value={endTime}
                    onChange={(e) => setEndTime(e.target.value)}
                    className="w-full rounded-lg border-gray-300 p-2 border"
                    required
                />
             </div>
          </div>

          <div className="col-span-1 md:col-span-2 flex items-center justify-center bg-gray-50 rounded-lg border border-gray-200 p-4">
             <div className="text-center">
                 <p className="text-xs text-gray-500 uppercase">Duration</p>
                 <p className={`text-2xl font-bold ${isEligible ? 'text-green-600' : 'text-red-500'}`}>
                     {duration} min
                 </p>
                 <p className="text-xs mt-1">
                     {isEligible ? 
                        <span className="bg-green-100 text-green-800 px-2 py-0.5 rounded-full">Eligible for Payment</span> : 
                        <span className="bg-red-100 text-red-800 px-2 py-0.5 rounded-full">Not Eligible (&lt;50m)</span>
                     }
                 </p>
             </div>
          </div>
        </section>

        {/* Section 2: Student Assessment */}
        <section>
            <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center gap-2">
                <Users className="w-5 h-5 text-indigo-500" /> Attendance & Competency
            </h3>
            {students.length === 0 ? (
                <div className="text-center p-6 bg-gray-50 rounded-lg text-gray-500">
                    No students found in this batch.
                </div>
            ) : (
                <div className="space-y-6">
                {students.map((student) => {
                    const score = scores.find(s => s.studentId === student.id);
                    if (!score) return null;

                    return (
                        <div key={student.id} className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm hover:shadow-md transition-shadow">
                            <div className="flex flex-col sm:flex-row justify-between sm:items-center mb-4 gap-4">
                                <div className="flex items-center gap-3">
                                    <img src={student.avatarUrl} alt={student.fullName} className="w-10 h-10 rounded-full" />
                                    <span className="font-medium text-gray-900">{student.fullName}</span>
                                </div>
                                <div className="flex bg-gray-100 rounded-lg p-1">
                                    {[AttendanceStatus.PRESENT, AttendanceStatus.LATE, AttendanceStatus.ABSENT].map((status) => (
                                        <button
                                            type="button"
                                            key={status}
                                            onClick={() => handleScoreChange(student.id, 'attendance', status)}
                                            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                                                score.attendance === status 
                                                ? status === AttendanceStatus.PRESENT ? 'bg-green-500 text-white' 
                                                : status === AttendanceStatus.LATE ? 'bg-yellow-500 text-white' 
                                                : 'bg-red-500 text-white'
                                                : 'text-gray-500 hover:text-gray-900'
                                            }`}
                                        >
                                            {status}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Rubrics - Only show if present or late */}
                            {score.attendance !== AttendanceStatus.ABSENT && (
                                <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 pt-2 border-t border-gray-100">
                                    {[
                                        { label: 'Business Acumen', key: 'business' },
                                        { label: 'Creativity', key: 'creativity' },
                                        { label: 'Discipline', key: 'discipline' }
                                    ].map((metric) => (
                                        <div key={metric.key}>
                                            <div className="flex justify-between mb-1">
                                                <label className="text-xs font-medium text-gray-500 uppercase">{metric.label}</label>
                                                <span className="text-xs font-bold text-indigo-600">{(score as any)[metric.key]}/5</span>
                                            </div>
                                            <input 
                                                type="range" 
                                                min="0" max="5" step="1"
                                                value={(score as any)[metric.key]}
                                                onChange={(e) => handleScoreChange(student.id, metric.key as keyof CompetencyScore, parseInt(e.target.value))}
                                                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                                            />
                                            <div className="flex justify-between text-[10px] text-gray-400 mt-1">
                                                <span>Poor</span>
                                                <span>Excellent</span>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
            )}
        </section>

        {/* Section 3: Evidence & Summary */}
        <section className="bg-gray-50 p-6 rounded-lg border border-gray-200">
             <div className="mb-4">
                 <label className="block text-sm font-medium text-gray-700 mb-2">Session Summary</label>
                 <textarea 
                    value={summary}
                    onChange={(e) => setSummary(e.target.value)}
                    placeholder="Briefly describe what was covered..."
                    rows={3}
                    className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 p-2 border"
                 />
             </div>
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                    <LinkIcon className="w-4 h-4" /> Artifact / Evidence (Required)
                </label>
                <div className="flex gap-2">
                    <input 
                        type="url" 
                        value={artifactUrl}
                        onChange={(e) => setArtifactUrl(e.target.value)}
                        placeholder="https://github.com/..."
                        className="flex-1 rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 p-2 border"
                        required
                    />
                    <button type="button" className="bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded-lg text-sm hover:bg-gray-50 flex items-center gap-2">
                        <Upload className="w-4 h-4" /> Upload
                    </button>
                </div>
             </div>
        </section>

        {/* Footer */}
        <div className="flex items-center justify-between pt-4 border-t border-gray-100">
             <div className="text-sm text-gray-500">
                Est. Payment: <span className="font-bold text-gray-900">{isEligible ? '1,200 THB' : '0 THB'}</span>
             </div>
             <button 
                type="submit" 
                disabled={isSubmitting}
                className={`flex items-center gap-2 bg-indigo-600 text-white px-6 py-2.5 rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-all ${isSubmitting ? 'opacity-70 cursor-not-allowed' : ''}`}
             >
                <Save className="w-4 h-4" />
                {isSubmitting ? 'Submitting...' : 'Submit Log'}
             </button>
        </div>
        {successMsg && (
            <div className="bg-green-100 text-green-800 p-4 rounded-lg flex items-center gap-2 animate-bounce">
                <AlertCircle className="w-5 h-5" /> {successMsg}
            </div>
        )}
      </form>
    </div>
  );
};

export enum Role {
  ADMIN = 'ADMIN',
  MENTOR = 'MENTOR',
  STUDENT = 'STUDENT'
}

export enum LogStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED'
}

export enum AttendanceStatus {
  PRESENT = 'PRESENT',
  LATE = 'LATE',
  ABSENT = 'ABSENT'
}

export interface BankInfo {
  bankName: string;
  accountNumber: string;
  accountName: string;
}

export interface User {
  id: string;
  role: Role;
  fullName: string;
  email: string;
  avatarUrl?: string;
  // Specific to students
  batchId?: string;
  // Specific to mentors
  bankInfo?: BankInfo;
}

export interface Batch {
  id: string;
  name: string; // e.g. "Gen 8"
  startDate: string; // ISO Date YYYY-MM-DD
  endDate: string; // ISO Date YYYY-MM-DD
  status: 'ACTIVE' | 'CLOSED';
}

export interface Module {
  id: string;
  batchId: string;
  name: string; // e.g. "Data Science"
  hourlyRate: number;
}

export interface Group {
  id: string;
  moduleId: string;
  name: string; // e.g. "Group A"
  mentorIds: string[]; // Supports multiple mentors if needed, but UI will focus on mapping
  studentIds: string[];
}

export interface CompetencyScore {
  studentId: string;
  attendance: AttendanceStatus;
  business: number; // 0-5
  creativity: number; // 0-5
  discipline: number; // 0-5
}

export interface LogHistory {
  timestamp: string; // ISO Date
  actorId: string; // User ID who performed the action
  action: string; // e.g. "Created", "Approved", "Rejected"
  note?: string; // Optional reason
}

export interface Intervention {
  id: string;
  studentId: string;
  adminId: string;
  date: string; // ISO Date
  type: 'CALL' | 'EMAIL' | 'MEETING' | 'IDP_SENT' | 'OTHER';
  note: string;
}

export interface MentoringLog {
  id: string;
  mentorId: string;
  batchId: string;
  moduleId: string; // Link to specific module
  date: string;
  startTime: string; // HH:mm
  endTime: string; // HH:mm
  durationMinutes: number;
  isPayable: boolean;
  status: LogStatus;
  summaryNote: string;
  artifactUrl: string;
  scores: CompetencyScore[]; // One entry per student in the session
  paymentAmount: number;
  history: LogHistory[]; // Audit trail
}

export interface SessionValidation {
  isValid: boolean;
  message: string;
  duration: number;
  isPayable: boolean;
}

