                            required
                            className="w-full rounded-lg border-gray-300 p-2 border"
                            rows={3}
                            placeholder="Describe the discussion or outcome..."
                            value={note}
                            onChange={(e) => setNote(e.target.value)}
                         />
                    </div>
                    <div className="flex justify-end gap-2 pt-2">
                        <button type="button" onClick={onClose} className="px-4 py-2 text-sm text-gray-600 hover:bg-gray-100 rounded-lg">Cancel</button>
                        <button type="submit" className="px-4 py-2 text-sm bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">Save Log</button>
                    </div>
                </form>
            </div>
        </div>
    );
};

// --- Tab: Monitoring (Red Flags & Artifacts) ---
const MonitoringTab: React.FC<{ 
    logs: MentoringLog[], 
    users: User[],
    interventions: Intervention[],
    onAddIntervention: (int: Intervention) => void
}> = ({ logs, users, interventions, onAddIntervention }) => {
    const [view, setView] = useState<'RED_FLAGS' | 'ARTIFACTS'>('RED_FLAGS');
    const [selectedStudentForIntervention, setSelectedStudentForIntervention] = useState<User | null>(null);

    // Calculate At-Risk Students
    const students = users.filter(u => u.role === Role.STUDENT).map(student => {
        const studentScores = logs.flatMap(l => l.scores.filter(s => s.studentId === student.id));
        const avgScore = studentScores.length ? (studentScores.reduce((acc, s) => acc + s.business + s.creativity + s.discipline, 0) / (studentScores.length * 3)) : 0;
        const absences = studentScores.filter(s => s.attendance === AttendanceStatus.ABSENT).length;
        const isRedFlag = avgScore > 0 && (avgScore < 2.5 || absences >= 2);

        // Find recent interventions
        const recentInterventions = interventions.filter(i => i.studentId === student.id).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

        return { ...student, avgScore: avgScore.toFixed(2), absences, isRedFlag, recentInterventions };
    });

    const atRiskStudents = students.filter(s => s.isRedFlag);

    // Recent Artifacts (Logs with URLs)
    const recentArtifacts = logs
        .filter(l => l.artifactUrl && l.artifactUrl.length > 5)
        .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime())
        .slice(0, 12);

    const handleSaveIntervention = (type: Intervention['type'], note: string) => {
        if (!selectedStudentForIntervention) return;
        const newInt: Intervention = {
            id: `int-${Date.now()}`,
            studentId: selectedStudentForIntervention.id,
            adminId: 'current-admin-id', // In real app, use currentUser.id
            date: new Date().toISOString(),
            type,
            note
        };
        onAddIntervention(newInt);
    };

    return (
        <div className="space-y-6 animate-fade-in">
             {selectedStudentForIntervention && (
                <InterventionModal 
                    student={selectedStudentForIntervention} 
                    onClose={() => setSelectedStudentForIntervention(null)}
                    onSave={handleSaveIntervention}
                />
            )}

            {/* Sub Nav */}
            <div className="flex gap-4 border-b border-gray-200">
                <button 
                    onClick={() => setView('RED_FLAGS')}
                    className={`pb-2 px-1 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${view === 'RED_FLAGS' ? 'border-red-500 text-red-600' : 'border-transparent text-gray-500'}`}
                >
                    <AlertOctagon size={16} /> At-Risk Dashboard ({atRiskStudents.length})
                </button>
                <button 
                    onClick={() => setView('ARTIFACTS')}
                    className={`pb-2 px-1 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${view === 'ARTIFACTS' ? 'border-indigo-500 text-indigo-600' : 'border-transparent text-gray-500'}`}
                >
                    <Eye size={16} /> Artifacts Review
                </button>
            </div>

            {view === 'RED_FLAGS' && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {atRiskStudents.length === 0 ? (
                         <div className="col-span-full p-12 text-center bg-white rounded-xl border border-gray-100">
                            <CheckCircle className="w-12 h-12 text-green-400 mx-auto mb-2" />
                            <h3 className="text-lg font-bold text-gray-800">All Clear!</h3>
                            <p className="text-gray-500">No students are currently flagged as high risk.</p>
                         </div>
                    ) : (
                        atRiskStudents.map(student => (
                            <div key={student.id} className="bg-white rounded-xl border border-red-200 shadow-sm overflow-hidden">
                                <div className="p-5 border-b border-gray-100 bg-red-50">
                                    <div className="flex justify-between items-start">
                                        <div className="flex items-center gap-3">
                                            <img src={student.avatarUrl} className="w-10 h-10 rounded-full" alt="" />
                                            <div>
                                                <h4 className="font-bold text-gray-900 text-sm">{student.fullName}</h4>
                                                <p className="text-xs text-red-600 font-medium">Flagged for Review</p>
                                            </div>
                                        </div>
                                        <button 
                                            onClick={() => setSelectedStudentForIntervention(student)}
                                            className="bg-white text-red-600 text-xs font-bold px-3 py-1.5 rounded-lg border border-red-200 hover:bg-red-50"
                                        >
                                            Take Action
                                        </button>
                                    </div>
                                </div>
                                <div className="p-5 space-y-4">
                                    <div className="grid grid-cols-2 gap-2 text-center">
                                        <div className="bg-gray-50 p-2 rounded">
                                            <p className="text-xs text-gray-500">GPA (Comp.)</p>
                                            <p className="text-lg font-bold text-red-600">{student.avgScore}</p>
                                        </div>
                                        <div className="bg-gray-50 p-2 rounded">
                                            <p className="text-xs text-gray-500">Absences</p>
                                            <p className={`text-lg font-bold ${student.absences > 1 ? 'text-red-600' : 'text-gray-800'}`}>{student.absences}</p>
                                        </div>
                                    </div>

                                    {/* History */}
                                    <div>
                                        <p className="text-xs font-bold text-gray-400 uppercase mb-2">Recent Actions</p>
                                        <div className="space-y-2 max-h-32 overflow-y-auto">
                                            {student.recentInterventions.length === 0 ? (
                                                <p className="text-xs text-gray-400 italic">No interventions logged.</p>
                                            ) : (
                                                student.recentInterventions.map(int => (
                                                    <div key={int.id} className="text-xs bg-gray-50 p-2 rounded border border-gray-100">
                                                        <div className="flex justify-between mb-1">
                                                            <span className="font-semibold text-indigo-600">{int.type.replace('_', ' ')}</span>
                                                            <span className="text-gray-400">{new Date(int.date).toLocaleDateString()}</span>
                                                        </div>
                                                        <p className="text-gray-600">{int.note}</p>
                                                    </div>
                                                ))
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
            )}

            {view === 'ARTIFACTS' && (
                <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
                    <p className="text-sm text-gray-500 mb-6">Reviewing {recentArtifacts.length} most recent submission artifacts.</p>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {recentArtifacts.map(log => {
                             const mentor = users.find(u => u.id === log.mentorId);
                             return (
                                <div key={log.id} className="border border-gray-200 rounded-lg p-4 hover:border-indigo-300 transition-colors group relative">
                                    <div className="flex items-start justify-between mb-2">
                                        <div className="flex items-center gap-2">
                                            <img src={mentor?.avatarUrl} className="w-6 h-6 rounded-full" alt="" />
                                            <span className="text-xs font-medium text-gray-700">{mentor?.fullName}</span>
                                        </div>
                                        <span className="text-xs text-gray-400">{log.date}</span>
                                    </div>
                                    <p className="text-sm font-semibold text-gray-900 mb-1 line-clamp-1">{log.summaryNote || "No summary provided"}</p>
                                    <p className="text-xs text-gray-500 mb-3">{log.moduleId}</p>

                                    <a 
                                        href={log.artifactUrl} 
                                        target="_blank" 
                                        rel="noreferrer"
                                        className="inline-flex items-center gap-2 text-sm font-medium text-indigo-600 hover:text-indigo-800 bg-indigo-50 px-3 py-2 rounded-lg w-full justify-center"
                                    >
                                        <ExternalLink size={14} /> Open Artifact
                                    </a>
                                </div>
                             );
                        })}
                    </div>
                </div>
            )}
        </div>
    );
};


