// --- Tab: Reports & Analytics ---
const ReportsTab: React.FC<{ 
    logs: MentoringLog[], 
    users: User[],
    modules: Module[] 
}> = ({ logs, users, modules }) => {
    const [subTab, setSubTab] = useState<'EXECUTIVE' | 'TRANSCRIPT' | 'FEEDBACK'>('EXECUTIVE');
    const [selectedStudentId, setSelectedStudentId] = useState<string>('');
    const printRef = useRef<HTMLDivElement>(null);

    // -- Executive Data Prep --
    const approvedLogs = logs.filter(l => l.status === LogStatus.APPROVED);

    // Attendance Stats
    const allScores = approvedLogs.flatMap(l => l.scores);
    const attendanceStats = [
        { name: 'Present', value: allScores.filter(s => s.attendance === AttendanceStatus.PRESENT).length, color: '#22c55e' },
        { name: 'Late', value: allScores.filter(s => s.attendance === AttendanceStatus.LATE).length, color: '#eab308' },
        { name: 'Absent', value: allScores.filter(s => s.attendance === AttendanceStatus.ABSENT).length, color: '#ef4444' },
    ];

    // Competency Trend (Mocked monthly average for demo)
    const trendData = [
        { month: 'Aug', score: 2.8 },
        { month: 'Sep', score: 3.2 },
        { month: 'Oct', score: 3.5 },
        { month: 'Nov', score: 3.9 },
    ];

    // Budget Data
    const totalBudget = 500000;
    const spentBudget = approvedLogs.reduce((acc, l) => acc + l.paymentAmount, 0);
    const budgetData = [
        { name: 'Allocated', amount: totalBudget },
        { name: 'Utilized', amount: spentBudget },
    ];

    // -- Transcript Data Prep --
    const students = users.filter(u => u.role === Role.STUDENT);
    const selectedStudent = students.find(s => s.id === selectedStudentId);

    let studentRadarData: any[] = [];
    let studentModuleGrades: any[] = [];

    if (selectedStudent) {
        // Radar Data
        const studentScores = logs.flatMap(l => l.scores.filter(s => s.studentId === selectedStudent.id));
        const avgBus = studentScores.length ? studentScores.reduce((a,b) => a + b.business, 0) / studentScores.length : 0;
        const avgCre = studentScores.length ? studentScores.reduce((a,b) => a + b.creativity, 0) / studentScores.length : 0;
        const avgDis = studentScores.length ? studentScores.reduce((a,b) => a + b.discipline, 0) / studentScores.length : 0;

        studentRadarData = [
            { subject: 'Business', A: avgBus, fullMark: 5 },
            { subject: 'Creativity', A: avgCre, fullMark: 5 },
            { subject: 'Discipline', A: avgDis, fullMark: 5 },
        ];

        // Module Grades
        studentModuleGrades = modules.filter(m => m.batchId === selectedStudent.batchId).map(m => {
            const logsForModule = logs.filter(l => l.moduleId === m.id && l.scores.some(s => s.studentId === selectedStudent.id));
            const modScores = logsForModule.flatMap(l => l.scores.filter(s => s.studentId === selectedStudent.id));
            const modAvg = modScores.length ? (modScores.reduce((a,b) => a + b.business + b.creativity + b.discipline, 0) / (modScores.length * 3)) : 0;
            return { name: m.name, avg: modAvg, sessions: logsForModule.length };
        });
    }

    const handlePrint = () => {
        if (!printRef.current) return;
        const printContent = printRef.current.innerHTML;
        const originalContent = document.body.innerHTML;
        document.body.innerHTML = printContent;
        window.print();
        document.body.innerHTML = originalContent;
        window.location.reload(); // Quick refresh to restore event listeners (React handling)
    };

    return (
        <div className="space-y-6 animate-fade-in">
             {/* Sub Nav */}
            <div className="flex gap-4 border-b border-gray-200">
                <button 
                    onClick={() => setSubTab('EXECUTIVE')}
                    className={`pb-2 px-1 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${subTab === 'EXECUTIVE' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500'}`}
                >
                    <PieChartIcon size={16} /> Executive Dashboard
                </button>
                <button 
                    onClick={() => setSubTab('TRANSCRIPT')}
                    className={`pb-2 px-1 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${subTab === 'TRANSCRIPT' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500'}`}
                >
                    <FileOutput size={16} /> Transcript Generator
                </button>
                <button 
                    onClick={() => setSubTab('FEEDBACK')}
                    className={`pb-2 px-1 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${subTab === 'FEEDBACK' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500'}`}
                >
                    <FileText size={16} /> Mentor Feedback
                </button>
            </div>

            {subTab === 'EXECUTIVE' && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {/* Attendance Pie */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                        <h3 className="text-lg font-bold text-gray-800 mb-4">Attendance Rate</h3>
                        <div className="h-64 flex flex-col items-center">
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie data={attendanceStats} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                                        {attendanceStats.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={entry.color} />
                                        ))}
                                    </Pie>
                                    <Tooltip />
                                </PieChart>
                            </ResponsiveContainer>
                            <div className="flex gap-4 text-xs mt-2">
                                {attendanceStats.map(s => (
                                    <div key={s.name} className="flex items-center gap-1">
                                        <div className="w-2 h-2 rounded-full" style={{backgroundColor: s.color}}></div>
                                        <span>{s.name}</span>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    {/* Competency Trend */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 lg:col-span-2">
                         <h3 className="text-lg font-bold text-gray-800 mb-4">Competency Development (Batch Average)</h3>
                         <div className="h-64">
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart data={trendData}>
                                    <defs>
                                        <linearGradient id="colorScore" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.8}/>
                                            <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                                        </linearGradient>
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                                    <XAxis dataKey="month" />
                                    <YAxis domain={[0, 5]} />
                                    <Tooltip />
                                    <Area type="monotone" dataKey="score" stroke="#4f46e5" fillOpacity={1} fill="url(#colorScore)" />
                                </AreaChart>
                            </ResponsiveContainer>
                         </div>
                    </div>

                    {/* Budget Burn */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                        <h3 className="text-lg font-bold text-gray-800 mb-2">Budget Utilization</h3>
                        <div className="text-3xl font-bold text-gray-900 mb-1">
                            {((spentBudget / totalBudget) * 100).toFixed(1)}%
                        </div>
                        <div className="w-full bg-gray-100 rounded-full h-2.5 mb-4">
                            <div className="bg-indigo-600 h-2.5 rounded-full" style={{ width: `${(spentBudget / totalBudget) * 100}%` }}></div>
                        </div>
                        <div className="flex justify-between text-sm text-gray-500">
                             <span>Spent: ฿{spentBudget.toLocaleString()}</span>
                             <span>Total: ฿{totalBudget.toLocaleString()}</span>
                        </div>
                    </div>
                </div>
            )}

            {subTab === 'TRANSCRIPT' && (
                <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
                    {/* Student List */}
                    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4 h-[600px] overflow-y-auto">
                        <h3 className="font-bold text-gray-700 mb-3">Select Student</h3>
                        <input type="text" placeholder="Search..." className="w-full p-2 border rounded-lg text-sm mb-3" />
                        <ul className="space-y-1">
                            {students.map(s => (
                                <li 
                                    key={s.id}
                                    onClick={() => setSelectedStudentId(s.id)}
                                    className={`p-2 rounded-lg text-sm cursor-pointer hover:bg-gray-50 flex items-center gap-2 ${selectedStudentId === s.id ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-600'}`}
                                >
                                    <img src={s.avatarUrl} className="w-6 h-6 rounded-full" alt="" />
                                    {s.fullName}
                                </li>
                            ))}
                        </ul>
                    </div>

                    {/* Preview Area */}
                    <div className="lg:col-span-3 bg-gray-50 rounded-xl border border-gray-200 p-8 flex justify-center items-start overflow-y-auto h-[600px]">
                        {selectedStudent ? (
                            <div className="space-y-4">
                                <div className="flex justify-end">
                                    <button onClick={handlePrint} className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-indigo-700">
                                        <Printer size={16} /> Print Official Transcript
                                    </button>
                                </div>
                                {/* A4 Paper Preview */}
                                <div ref={printRef} className="bg-white w-[210mm] min-h-[297mm] p-[20mm] shadow-lg text-gray-900 relative">
                                    {/* Header */}
                                    <div className="text-center border-b-2 border-indigo-900 pb-6 mb-8">
                                        <div className="flex justify-center mb-4">
                                            <GraduationCap size={48} className="text-indigo-900" />
                                        </div>
                                        <h1 className="text-3xl font-serif font-bold text-indigo-900">Gen-Next Academy</h1>
                                        <h2 className="text-xl text-gray-600 mt-1">Competency Transcript</h2>
                                        <p className="text-sm text-gray-500 mt-2">New Breed Graduate Project (Cohort 2024)</p>
