                                            <p className="text-sm text-gray-500 uppercase font-bold">Student Name</p>
                                            <p className="text-lg font-semibold">{selectedStudent.fullName}</p>
                                        </div>
                                        <div>
                                            <p className="text-sm text-gray-500 uppercase font-bold">Student ID</p>
                                            <p className="text-lg font-mono">GN-24-{selectedStudent.id.substring(2,6).toUpperCase()}</p>
