const MonitoringTab: React.FC<{ 
    logs: MentoringLog[], 
    users: User[], 
    interventions: Intervention[],
    onAddIntervention: (i: Intervention) => void 
}> = ({ logs, users, interventions, onAddIntervention }) => {
    const [selectedStudent, setSelectedStudent] = useState<User | null>(null);

    // Identify At-Risk Students
    const students = users.filter(u => u.role === Role.STUDENT);
    const riskStudents = students.map(s => {
        const sLogs = logs.filter(l => l.scores.some(score => score.studentId === s.id));
        const absences = sLogs.reduce((acc, l) => {
            const score = l.scores.find(sc => sc.studentId === s.id);
            return acc + (score?.attendance === AttendanceStatus.ABSENT ? 1 : 0);
        }, 0);
        const avgScore = sLogs.length > 0 ? sLogs.reduce((acc, l) => {
             const score = l.scores.find(sc => sc.studentId === s.id);
             return acc + ((score ? (score.business + score.creativity + score.discipline)/3 : 0));
        }, 0) / sLogs.length : 0;

        return {
            student: s,
            absences,
            avgScore,
            isRisk: absences > 2 || (sLogs.length > 0 && avgScore < 2.5)
        };
    }).filter(r => r.isRisk);

    const handleSaveIntervention = (type: Intervention['type'], note: string) => {
        if (!selectedStudent) return;
        onAddIntervention({
            id: `int-${Date.now()}`,
            studentId: selectedStudent.id,
            adminId: 'u1', // Mock admin ID
            date: new Date().toISOString(),
            type,
            note
        });
    };

    return (
        <div className="space-y-6 animate-fade-in">
            {selectedStudent && (
                <InterventionModal 
                    student={selectedStudent} 
                    onClose={() => setSelectedStudent(null)} 
                    onSave={handleSaveIntervention}
                />
            )}

            <div className="bg-red-50 border border-red-100 rounded-xl p-6">
                 <h3 className="text-red-800 font-bold flex items-center gap-2 mb-4">
                     <AlertTriangle className="w-5 h-5" /> At-Risk Students Attention Needed
                 </h3>
                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                     {riskStudents.length === 0 && <p className="text-red-500 text-sm">No at-risk students detected.</p>}
                     {riskStudents.map(({student, absences, avgScore}) => (
                         <div key={student.id} className="bg-white p-4 rounded-lg shadow-sm border border-red-100">
                             <div className="flex items-center gap-3 mb-3">
                                 <img src={student.avatarUrl} className="w-10 h-10 rounded-full" alt="" />
                                 <div>
                                     <p className="font-bold text-gray-900">{student.fullName}</p>
                                     <p className="text-xs text-gray-500">ID: {student.id}</p>
                                 </div>
                             </div>
                             <div className="space-y-2 mb-4">
                                 <div className="flex justify-between text-sm">
                                     <span className="text-gray-500">Absences:</span>
                                     <span className="font-bold text-red-600">{absences}</span>
                                 </div>
                                 <div className="flex justify-between text-sm">
                                     <span className="text-gray-500">Avg Score:</span>
                                     <span className={`font-bold ${avgScore < 2.5 ? 'text-red-600' : 'text-gray-800'}`}>{avgScore.toFixed(1)}/5.0</span>
                                 </div>
                             </div>
                             <button 
                                onClick={() => setSelectedStudent(student)}
                                className="w-full py-2 bg-white border border-red-200 text-red-600 rounded-lg text-sm font-medium hover:bg-red-50"
                             >
                                 Log Intervention
                             </button>
                         </div>
                     ))}
                 </div>
            </div>

            <div className="bg-white border border-gray-100 rounded-xl p-6">
                <h3 className="font-bold text-gray-800 mb-4">Intervention History</h3>
                <div className="space-y-4">
                    {interventions.map(int => {
                        const s = users.find(u => u.id === int.studentId);
                        return (
                            <div key={int.id} className="flex gap-4 border-b border-gray-50 pb-4 last:border-0">
                                <div className="bg-indigo-50 p-2 rounded h-fit">
                                    <Phone size={16} className="text-indigo-600" />
                                </div>
                                <div>
                                    <p className="text-sm font-medium text-gray-900">
                                        {int.type} with <span className="font-bold">{s?.fullName}</span>
                                    </p>
                                    <p className="text-sm text-gray-600 mt-1">{int.note}</p>
                                    <p className="text-xs text-gray-400 mt-2">{new Date(int.date).toLocaleDateString()}</p>
                                </div>
                            </div>
                        )
                    })}
                    {interventions.length === 0 && <p className="text-gray-400 text-sm">No interventions logged.</p>}
                </div>
            </div>
        </div>
    );
};

