const ApprovalsTab: React.FC<{ 
    logs: MentoringLog[], 
    users: User[],
    modules: Module[], 
    onUpdateStatus: (id: string, status: LogStatus, reason?: string) => void 
}> = ({ logs, users, modules, onUpdateStatus }) => {
    const pendingLogs = logs.filter(l => l.status === LogStatus.PENDING);

    // Simple Overlap Detection
    const getOverlapWarning = (log: MentoringLog) => {
        const overlaps = logs.some(l => 
            l.id !== log.id && 
            l.mentorId === log.mentorId && 
            l.date === log.date && 
            l.status !== LogStatus.REJECTED &&
            ((l.startTime >= log.startTime && l.startTime < log.endTime) || 
             (l.endTime > log.startTime && l.endTime <= log.endTime))
        );
        return overlaps;
    };

    return (
        <div className="animate-fade-in space-y-4">
             {pendingLogs.length === 0 ? (
                 <div className="text-center p-12 bg-gray-50 rounded-xl border border-dashed border-gray-300">
                     <CheckCircle size={48} className="mx-auto text-green-500 mb-4 opacity-50" />
                     <h3 className="text-lg font-medium text-gray-900">All Caught Up!</h3>
                     <p className="text-gray-500">No pending logs to review.</p>
                 </div>
             ) : (
                 pendingLogs.map(log => {
                     const mentor = users.find(u => u.id === log.mentorId);
                     const module = modules.find(m => m.id === log.moduleId);
                     const hasOverlap = getOverlapWarning(log);

                     return (
                         <div key={log.id} className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col md:flex-row gap-6 relative">
                             {hasOverlap && (
                                 <div className="absolute top-0 right-0 bg-red-100 text-red-700 px-3 py-1 text-xs font-bold rounded-bl-lg rounded-tr-lg border-l border-b border-red-200 flex items-center gap-1">
                                     <AlertTriangle size={12} /> Time Overlap Detected
                                 </div>
                             )}
                             <div className="flex-1">
                                 <div className="flex items-center gap-3 mb-2">
                                     <img src={mentor?.avatarUrl} alt="" className="w-10 h-10 rounded-full" />
                                     <div>
                                         <p className="font-bold text-gray-900">{mentor?.fullName}</p>
                                         <p className="text-xs text-gray-500">{log.date} • {log.startTime} - {log.endTime} ({log.durationMinutes} min)</p>
                                     </div>
                                 </div>
                                 <div className="ml-13 pl-13">
                                     <p className="text-sm font-medium text-indigo-900 bg-indigo-50 inline-block px-2 py-1 rounded mb-2">
                                         {module?.name}
                                     </p>
                                     <p className="text-gray-600 text-sm mb-3">"{log.summaryNote}"</p>
                                     <div className="flex gap-4 text-xs text-gray-500 items-center">
                                         <a href={log.artifactUrl} target="_blank" rel="noreferrer" className="flex items-center gap-1 text-blue-600 hover:underline">
                                             <ExternalLink size={14} /> Check Evidence
                                         </a>

                                         {log.isValidSession ? (
                                             <span className="flex items-center gap-1 text-green-600 bg-green-50 px-2 py-0.5 rounded">
                                                 <CheckCircle size={12} /> Valid Working Hour
                                             </span>
                                         ) : (
                                             <span className="flex items-center gap-1 text-red-600 bg-red-50 px-2 py-0.5 rounded">
                                                 <AlertTriangle size={12} /> Invalid Duration (&lt;50m)
                                             </span>
                                         )}
                                     </div>
                                 </div>
                             </div>
                             <div className="flex flex-col gap-2 justify-center md:border-l md:pl-6 border-gray-100 min-w-[150px]">
                                 <button 
                                    onClick={() => onUpdateStatus(log.id, LogStatus.APPROVED)}
                                    className="bg-green-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-green-700 transition-colors flex items-center justify-center gap-2"
                                 >
                                     <CheckCircle size={16} /> Verify Log
                                 </button>
                                 <button 
                                    onClick={() => {
                                        const reason = prompt("Reason for rejection?");
                                        if (reason) onUpdateStatus(log.id, LogStatus.REJECTED, reason);
                                    }}
                                    className="bg-white border border-red-200 text-red-600 px-4 py-2 rounded-lg text-sm font-medium hover:bg-red-50 transition-colors flex items-center justify-center gap-2"
                                 >
                                     <XCircle size={16} /> Reject
                                 </button>
                             </div>
                         </div>
                     );
                 })
             )}
        </div>
    );
};

const MonitoringTab: React.FC<{ 
    logs: MentoringLog[], 
    users: User[], 
    interventions: Intervention[],
    onAddIntervention: (i: Intervention) => void 
}> = ({ logs, users, interventions, onAddIntervention }) => {
    const [selectedStudent, setSelectedStudent] = useState<User | null>(null);

    // Identify At-Risk Students
    const students = users.filter(u => u.role === Role.STUDENT);
    const riskStudents = students.map(s => {
        const sLogs = logs.filter(l => l.scores.some(score => score.studentId === s.id));
        const absences = sLogs.reduce((acc, l) => {
            const score = l.scores.find(sc => sc.studentId === s.id);
            return acc + (score?.attendance === AttendanceStatus.ABSENT ? 1 : 0);
        }, 0);
        const avgScore = sLogs.length > 0 ? sLogs.reduce((acc, l) => {
             const score = l.scores.find(sc => sc.studentId === s.id);
             return acc + ((score ? (score.business + score.creativity + score.discipline)/3 : 0));
        }, 0) / sLogs.length : 0;

        return {
            student: s,
            absences,
            avgScore,
            isRisk: absences > 2 || (sLogs.length > 0 && avgScore < 2.5)
        };
    }).filter(r => r.isRisk);

    const handleSaveIntervention = (type: Intervention['type'], note: string) => {
        if (!selectedStudent) return;
        onAddIntervention({
            id: `int-${Date.now()}`,
            studentId: selectedStudent.id,
            adminId: 'u1',
            date: new Date().toISOString(),
            type,
            note
        });
    };

    return (
        <div className="space-y-6 animate-fade-in">
            {selectedStudent && (
                <InterventionModal 
                    student={selectedStudent} 
                    onClose={() => setSelectedStudent(null)} 
                    onSave={handleSaveIntervention}
                />
            )}

            <div className="bg-red-50 border border-red-100 rounded-xl p-6">
                 <h3 className="text-red-800 font-bold flex items-center gap-2 mb-4">
                     <AlertTriangle className="w-5 h-5" /> At-Risk Students Attention Needed
                 </h3>
                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                     {riskStudents.length === 0 && <p className="text-red-500 text-sm">No at-risk students detected.</p>}
                     {riskStudents.map(({student, absences, avgScore}) => (
                         <div key={student.id} className="bg-white p-4 rounded-lg shadow-sm border border-red-100">
                             <div className="flex items-center gap-3 mb-3">
                                 <img src={student.avatarUrl} className="w-10 h-10 rounded-full" alt="" />
                                 <div>
                                     <p className="font-bold text-gray-900">{student.fullName}</p>
                                     <p className="text-xs text-gray-500">ID: {student.id}</p>
                                 </div>
                             </div>
                             <div className="space-y-2 mb-4">
                                 <div className="flex justify-between text-sm">
                                     <span className="text-gray-500">Absences:</span>
                                     <span className="font-bold text-red-600">{absences}</span>
                                 </div>
                                 <div className="flex justify-between text-sm">
                                     <span className="text-gray-500">Avg Score:</span>
                                     <span className={`font-bold ${avgScore < 2.5 ? 'text-red-600' : 'text-gray-800'}`}>{avgScore.toFixed(1)}/5.0</span>
                                 </div>
                             </div>
                             <button 
                                onClick={() => setSelectedStudent(student)}
                                className="w-full py-2 bg-white border border-red-200 text-red-600 rounded-lg text-sm font-medium hover:bg-red-50"
                             >
                                 Log Intervention
                             </button>
                         </div>
                     ))}
                 </div>
            </div>

            <div className="bg-white border border-gray-100 rounded-xl p-6">
                <h3 className="font-bold text-gray-800 mb-4">Intervention History</h3>
                <div className="space-y-4">
                    {interventions.map(int => {
                        const s = users.find(u => u.id === int.studentId);
                        return (
                            <div key={int.id} className="flex gap-4 border-b border-gray-50 pb-4 last:border-0">
                                <div className="bg-indigo-50 p-2 rounded h-fit">
                                    <Phone size={16} className="text-indigo-600" />
                                </div>
                                <div>
                                    <p className="text-sm font-medium text-gray-900">
                                        {int.type} with <span className="font-bold">{s?.fullName}</span>
                                    </p>
                                    <p className="text-sm text-gray-600 mt-1">{int.note}</p>
                                    <p className="text-xs text-gray-400 mt-2">{new Date(int.date).toLocaleDateString()}</p>
                                </div>
                            </div>
                        )
                    })}
                    {interventions.length === 0 && <p className="text-gray-400 text-sm">No interventions logged.</p>}
                </div>
            </div>
        </div>
    );
};

