import React, { createContext, useContext, useState, ReactNode } from 'react';
import { MentoringLog, User, Batch, Module, Role, LogStatus, Group, LogHistory, Intervention } from '../types';
import { MOCK_USERS, MOCK_BATCHES, MOCK_MODULES, MOCK_GROUPS, INITIAL_LOGS, MOCK_INTERVENTIONS } from '../constants';

interface DataContextType {
  currentUser: User;
  switchRole: (role: Role) => void;
  logs: MentoringLog[];
  users: User[];
  batches: Batch[];
  modules: Module[];
  groups: Group[];
  interventions: Intervention[];
  addLog: (log: MentoringLog, overrideMentorId?: string) => void;
  updateLogStatus: (id: string, status: LogStatus, reason?: string) => void;
  getStudentsByBatch: (batchId: string) => User[];
  addUser: (user: User) => void;
  addBatch: (batch: Batch) => void;
  addModule: (module: Module) => void;
  getModulesByBatch: (batchId: string) => Module[];
  addGroup: (group: Group) => void;
  updateGroup: (group: Group) => void;
  addIntervention: (intervention: Intervention) => void;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]); // Default to Admin
  const [logs, setLogs] = useState<MentoringLog[]>(INITIAL_LOGS);
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [batches, setBatches] = useState<Batch[]>(MOCK_BATCHES);
  const [modules, setModules] = useState<Module[]>(MOCK_MODULES);
  const [groups, setGroups] = useState<Group[]>(MOCK_GROUPS);
  const [interventions, setInterventions] = useState<Intervention[]>(MOCK_INTERVENTIONS);

  const switchRole = (role: Role) => {
    const user = users.find(u => u.role === role);
    if (user) setCurrentUser(user);
  };

  const addLog = (log: MentoringLog, overrideMentorId?: string) => {
    // If overrideMentorId is provided (Admin proxy), use it. Otherwise use currentUser.
    const mentorId = overrideMentorId || currentUser.id;

    // Add creation history
    const logWithHistory = {
      ...log,
      mentorId,
      recordedBy: currentUser.id, // Audit trail: who physically clicked save
      history: [{
        timestamp: new Date().toISOString(),
        actorId: currentUser.id,
        action: 'Created',
        note: currentUser.id !== mentorId ? 'Recorded via Admin Proxy' : undefined
      }]
    };
    setLogs(prev => [logWithHistory, ...prev]);
  };

  const updateLogStatus = (id: string, status: LogStatus, reason?: string) => {
    setLogs(prev => prev.map(log => {
      if (log.id === id) {
        // Create history entry
        const historyEntry: LogHistory = {
            timestamp: new Date().toISOString(),
            actorId: currentUser.id,
            action: `Status changed to ${status}`,
            note: reason
        };
        return { 
            ...log, 
            status,
            history: [...log.history, historyEntry]
        };
      }
      return log;
    }));
  };

  const getStudentsByBatch = (batchId: string) => {
    return users.filter(u => u.role === Role.STUDENT && u.batchId === batchId);
  };

  const addUser = (user: User) => {
    setUsers(prev => [...prev, user]);
  };

  const addBatch = (batch: Batch) => {
    setBatches(prev => [...prev, batch]);
  };

  const addModule = (module: Module) => {
    setModules(prev => [...prev, module]);
  };

  const getModulesByBatch = (batchId: string) => {
    return modules.filter(m => m.batchId === batchId);
  };

  const addGroup = (group: Group) => {
    setGroups(prev => [...prev, group]);
  };

  const updateGroup = (updatedGroup: Group) => {
    setGroups(prev => prev.map(g => g.id === updatedGroup.id ? updatedGroup : g));
  };

  const addIntervention = (intervention: Intervention) => {
    setInterventions(prev => [intervention, ...prev]);
  };

  return (
    <DataContext.Provider value={{ 
      currentUser, 
      switchRole, 
      logs, 
      users, 
      batches, 
      modules,
      groups,
      interventions,
      addLog, 
      updateLogStatus,
      getStudentsByBatch,
      addUser,
      addBatch,
      addModule,
      getModulesByBatch,
      addGroup,
      updateGroup,
      addIntervention
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error('useData must be used within DataProvider');
  return context;
};

import React, { useState, useEffect } from 'react';
import { useData } from '../services/DataContext';
import { AttendanceStatus, CompetencyScore, LogStatus, MentoringLog, Role } from '../types';
import { Clock, Users, Save, Link as LinkIcon, Upload, AlertTriangle, CheckCircle, Shield } from 'lucide-react';

export const MentorLogForm: React.FC = () => {
  const { batches, getModulesByBatch, currentUser, getStudentsByBatch, addLog, users } = useData();

  // Local State
  const [selectedBatchId, setSelectedBatchId] = useState(batches[0]?.id || '');
  const [selectedModuleId, setSelectedModuleId] = useState('');

  // Admin Proxy State
  const isAdmin = currentUser.role === Role.ADMIN;
  const mentors = users.filter(u => u.role === Role.MENTOR);
  const [selectedMentorId, setSelectedMentorId] = useState('');

  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [summary, setSummary] = useState('');
  const [artifactUrl, setArtifactUrl] = useState('');
  const [scores, setScores] = useState<CompetencyScore[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  const students = getStudentsByBatch(selectedBatchId);
  const modules = getModulesByBatch(selectedBatchId);

  // Auto-select first module if available when batch changes
  useEffect(() => {
    if (modules.length > 0) {
      setSelectedModuleId(modules[0].id);
    } else {
      setSelectedModuleId('');
    }
  }, [selectedBatchId, modules]);

  // Set default mentor ID if Admin
  useEffect(() => {
      if (isAdmin && mentors.length > 0 && !selectedMentorId) {
          setSelectedMentorId(mentors[0].id);
      }
  }, [isAdmin, mentors]);

  // Initialize scores when students change
  useEffect(() => {
    if (students.length > 0) {
      const initialScores: CompetencyScore[] = students.map(s => ({
        studentId: s.id,
        attendance: AttendanceStatus.PRESENT,
        business: 3,
        creativity: 3,
        discipline: 3
      }));
      setScores(initialScores);
    }
  }, [selectedBatchId, students.length]); 

  const calculateDuration = () => {
    if (!startTime || !endTime) return 0;
    const start = new Date(`2000-01-01T${startTime}`);
    const end = new Date(`2000-01-01T${endTime}`);
    const diffMs = end.getTime() - start.getTime();
    return Math.max(0, Math.floor(diffMs / 60000));
  };

  const duration = calculateDuration();
  const isValidSession = duration >= 50;

  const handleScoreChange = (studentId: string, field: keyof CompetencyScore, value: any) => {
    setScores(prev => prev.map(s => s.studentId === studentId ? { ...s, [field]: value } : s));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isAdmin && !selectedMentorId) {
        alert("Please select a mentor to record for.");
        return;
    }
    if (!selectedModuleId) {
        alert("Please select a teaching module.");
        return;
    }
    if (!artifactUrl) {
      alert("Please provide an artifact link (Proof of work).");
      return;
    }

    setIsSubmitting(true);

    const newLog: MentoringLog = {
      id: `log-${Date.now()}`,
      mentorId: '', // Will be set in addLog
      recordedBy: '', // Will be set in addLog
      batchId: selectedBatchId,
      moduleId: selectedModuleId,
      date,
      startTime,
      endTime,
      durationMinutes: duration,
      isValidSession: isValidSession,
      status: LogStatus.PENDING,
      summaryNote: summary,
      artifactUrl,
      scores,
      history: []
    };

    setTimeout(() => {
        // Pass selectedMentorId if Admin, otherwise undefined (addLog will use currentUser)
        addLog(newLog, isAdmin ? selectedMentorId : undefined);
        setIsSubmitting(false);
        setSuccessMsg("Log submitted successfully!");
        setSummary('');
        setArtifactUrl('');
        setTimeout(() => setSuccessMsg(''), 3000);
    }, 800);
  };

  return (
    <div className={`bg-white rounded-xl shadow-sm border overflow-hidden ${isAdmin ? 'border-indigo-200' : 'border-gray-100'}`}>
      <div className={`p-6 border-b ${isAdmin ? 'bg-indigo-600 text-white' : 'bg-indigo-50 text-indigo-900'}`}>
        <div className="flex justify-between items-start">
            <div>
                <h2 className="text-xl font-bold flex items-center gap-2">
                    <Clock className="w-5 h-5" /> 
                    {isAdmin ? "Admin Proxy Entry" : "New Session Log"}
                </h2>
                <p className={`text-sm mt-1 ${isAdmin ? 'text-indigo-100' : 'text-indigo-600'}`}>
                    {isAdmin 
                        ? "You are recording a session on behalf of a mentor." 
                        : "Record your mentoring activity. Sessions must be 50+ minutes."}
                </p>
            </div>
            {isAdmin && <Shield className="w-8 h-8 text-indigo-300 opacity-50" />}
        </div>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-8">

        {/* Admin Proxy Selection */}
        {isAdmin && (
            <div className="bg-yellow-50 border border-yellow-200 p-4 rounded-lg flex items-center gap-4">
                <div className="flex-shrink-0">
                    <Shield className="w-6 h-6 text-yellow-600" />
                </div>
                <div className="flex-1">
                    <label className="block text-sm font-bold text-yellow-800 mb-1">Log on behalf of Mentor:</label>
                    <select
                        value={selectedMentorId}
                        onChange={(e) => setSelectedMentorId(e.target.value)}
                        className="w-full rounded border-yellow-300 p-2 text-sm focus:ring-yellow-500 focus:border-yellow-500"
                    >
                        <option value="">-- Select Mentor --</option>
                        {mentors.map(m => (
                            <option key={m.id} value={m.id}>
                                {m.fullName} ({m.mentorType})
                            </option>
                        ))}
                    </select>
                </div>
            </div>
        )}

        {/* Section 1: Session Details */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Batch (Cohort)</label>
            <select 
              value={selectedBatchId}
              onChange={(e) => setSelectedBatchId(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
            >
              {batches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Teaching Module</label>
            <select 
              value={selectedModuleId}
              onChange={(e) => setSelectedModuleId(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
              disabled={modules.length === 0}
            >
              {modules.length === 0 && <option>No modules found</option>}
              {modules.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Date</label>
            <input 
              type="date" 
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
                <label className="block text-xs font-medium text-gray-500 uppercase mb-1">Start Time</label>
                <input 
                    type="time" 
                    value={startTime}
                    onChange={(e) => setStartTime(e.target.value)}
                    className="w-full rounded-lg border-gray-300 p-2 border"
                    required
                />
             </div>
             <div>
                <label className="block text-xs font-medium text-gray-500 uppercase mb-1">End Time</label>
                <input 
                    type="time" 
                    value={endTime}
                    onChange={(e) => setEndTime(e.target.value)}
                    className="w-full rounded-lg border-gray-300 p-2 border"
                    required
                />
             </div>
          </div>

          <div className="col-span-1 md:col-span-2">
             <div className={`rounded-lg border p-4 flex flex-col items-center justify-center transition-colors ${isValidSession ? 'bg-green-50 border-green-200' : 'bg-red-50 border-red-200'}`}>
                 <div className="text-center">
                     <p className="text-xs text-gray-500 uppercase font-semibold mb-1">Net Duration</p>
                     <p className={`text-3xl font-bold ${isValidSession ? 'text-green-700' : 'text-red-600'}`}>
                         {duration} min
                     </p>
                 </div>
                 <div className="mt-2 flex items-center gap-2">
                     {isValidSession ? (
                        <>
                            <CheckCircle size={18} className="text-green-600" />
                            <span className="text-sm font-medium text-green-800">Valid Working Hour (1 Credit)</span>
                        </>
                     ) : (
                        <>
                            <AlertTriangle size={18} className="text-red-600" />
                            <span className="text-sm font-medium text-red-800">Duration too short (Min. 50 mins required)</span>
                        </>
                     )}
                 </div>
             </div>
          </div>
        </section>

        {/* Section 2: Student Assessment */}
        <section>
            <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center gap-2">
                <Users className="w-5 h-5 text-indigo-500" /> Attendance & Competency
            </h3>
            {students.length === 0 ? (
                <div className="text-center p-6 bg-gray-50 rounded-lg text-gray-500">
                    No students found in this batch.
                </div>
            ) : (
                <div className="space-y-6">
                {students.map((student) => {
                    const score = scores.find(s => s.studentId === student.id);
                    if (!score) return null;

                    return (
                        <div key={student.id} className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm hover:shadow-md transition-shadow">
