const MonitoringTab: React.FC<{ 
    logs: MentoringLog[], 
    users: User[], 
    interventions: Intervention[],
    onAddIntervention: (i: Intervention) => void 
}> = ({ logs, users, interventions, onAddIntervention }) => {
    const { currentUser } = useData();
    const [selectedStudent, setSelectedStudent] = useState<User | null>(null);

    // Calculate Risk Metrics
    const studentMetrics = users
        .filter(u => u.role === Role.STUDENT)
        .map(student => {
            // Find logs where this student has a score
            const studentScores = logs
                .filter(l => l.status !== LogStatus.REJECTED)
                .flatMap(l => l.scores.filter(s => s.studentId === student.id));

            const totalRecorded = studentScores.length;
            if (totalRecorded === 0) return { student, attendance: 100, avgScore: 5, risk: false, myInterventions: [] };

            const absentCount = studentScores.filter(s => s.attendance === AttendanceStatus.ABSENT).length;
            const attendanceRate = ((totalRecorded - absentCount) / totalRecorded) * 100;

            const totalScoreVal = studentScores.reduce((acc, s) => acc + s.business + s.creativity + s.discipline, 0);
            const avgScore = totalScoreVal / (totalRecorded * 3); // Max 15 points per session (5*3) -> normalized to 5

            // Risk Logic: Attendance < 80% OR Avg Score < 2.5
            const risk = attendanceRate < 80 || avgScore < 2.5;

            const myInterventions = interventions.filter(i => i.studentId === student.id);

            return { student, attendance: attendanceRate, avgScore, risk, myInterventions };
        });

    const atRiskCount = studentMetrics.filter(m => m.risk).length;

    const handleSave = (type: Intervention['type'], note: string) => {
        if (!selectedStudent) return;
        const intervention: Intervention = {
            id: `int-${Date.now()}`,
            studentId: selectedStudent.id,
            adminId: currentUser.id,
            date: new Date().toISOString(),
            type,
            note
        };
        onAddIntervention(intervention);
        setSelectedStudent(null);
    };

    return (
        <div className="animate-fade-in space-y-6">
            <div className="flex gap-4 mb-6">
                <div className="bg-red-50 text-red-800 p-4 rounded-xl border border-red-100 flex-1">
                    <h4 className="font-bold text-lg">{atRiskCount} Students At Risk</h4>
                    <p className="text-xs opacity-75">Attendance &lt; 80% or Avg Score &lt; 2.5</p>
                </div>
                <div className="bg-blue-50 text-blue-800 p-4 rounded-xl border border-blue-100 flex-1">
                    <h4 className="font-bold text-lg">{interventions.length} Interventions</h4>
                    <p className="text-xs opacity-75">Total actions taken this semester</p>
                </div>
            </div>

            <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
                <table className="w-full text-sm text-left">
                    <thead className="bg-gray-50 text-gray-500 font-medium border-b border-gray-200">
                        <tr>
                            <th className="p-4">Student</th>
                            <th className="p-4">Attendance</th>
                            <th className="p-4">Performance</th>
                            <th className="p-4">Status</th>
                            <th className="p-4">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {studentMetrics.map((m) => (
                            <tr key={m.student.id} className="hover:bg-gray-50">
                                <td className="p-4">
                                    <div className="flex items-center gap-3">
                                        <img src={m.student.avatarUrl} className="w-8 h-8 rounded-full bg-gray-200" alt="" />
                                        <div>
                                            <p className="font-medium text-gray-900">{m.student.fullName}</p>
                                            <p className="text-xs text-gray-500">{m.myInterventions.length} interventions</p>
                                        </div>
                                    </div>
                                </td>
                                <td className="p-4">
                                    <div className="flex items-center gap-2">
                                        <div className="w-16 h-1.5 bg-gray-100 rounded-full overflow-hidden">
                                            <div 
                                                className={`h-full ${m.attendance < 80 ? 'bg-red-500' : 'bg-green-500'}`} 
                                                style={{ width: `${m.attendance}%` }}
                                            />
                                        </div>
                                        <span className="text-xs font-medium">{m.attendance.toFixed(0)}%</span>
                                    </div>
                                </td>
                                <td className="p-4">
                                    <div className="flex items-center gap-1">
                                        <span className={`font-bold ${m.avgScore < 2.5 ? 'text-red-600' : 'text-gray-700'}`}>
                                            {m.avgScore.toFixed(1)}
                                        </span>
                                        <span className="text-gray-400 text-xs">/ 5.0</span>
                                    </div>
                                </td>
                                <td className="p-4">
                                    {m.risk ? (
                                        <span className="bg-red-100 text-red-700 px-2 py-1 rounded text-xs font-bold inline-flex items-center gap-1">
                                            <AlertTriangle size={10} /> At Risk
                                        </span>
                                    ) : (
                                        <span className="bg-green-100 text-green-700 px-2 py-1 rounded text-xs font-bold">
                                            On Track
                                        </span>
                                    )}
                                </td>
                                <td className="p-4">
                                    <button 
                                        onClick={() => setSelectedStudent(m.student)}
                                        className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                                        title="Log Intervention"
                                    >
                                        <Activity size={16} />
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {selectedStudent && (
                <InterventionModal 
                    student={selectedStudent}
                    onClose={() => setSelectedStudent(null)}
                    onSave={handleSave}
                />
            )}
        </div>
    );
};

