        { name: 'Present', value: allScores.filter(s => s.attendance === AttendanceStatus.PRESENT).length, color: '#22c55e' },
        { name: 'Late', value: allScores.filter(s => s.attendance === AttendanceStatus.LATE).length, color: '#eab308' },
        { name: 'Absent', value: allScores.filter(s => s.attendance === AttendanceStatus.ABSENT).length, color: '#ef4444' },
    ];

    // Competency Trend (Mocked monthly average for demo)
    const trendData = [
        { month: 'Aug', score: 2.8 },
        { month: 'Sep', score: 3.2 },
        { month: 'Oct', score: 3.5 },
        { month: 'Nov', score: 3.9 },
    ];

    // -- Transcript Data Prep --
    const students = users.filter(u => u.role === Role.STUDENT);
    const selectedStudent = students.find(s => s.id === selectedStudentId);

    let studentRadarData: any[] = [];
    let studentModuleGrades: any[] = [];

    if (selectedStudent) {
        // Radar Data
        const studentScores = logs.flatMap(l => l.scores.filter(s => s.studentId === selectedStudent.id));
        const avgBus = studentScores.length ? studentScores.reduce((a,b) => a + b.business, 0) / studentScores.length : 0;
        const avgCre = studentScores.length ? studentScores.reduce((a,b) => a + b.creativity, 0) / studentScores.length : 0;
        const avgDis = studentScores.length ? studentScores.reduce((a,b) => a + b.discipline, 0) / studentScores.length : 0;

        studentRadarData = [
            { subject: 'Business', A: avgBus, fullMark: 5 },
            { subject: 'Creativity', A: avgCre, fullMark: 5 },
            { subject: 'Discipline', A: avgDis, fullMark: 5 },
        ];

        // Module Grades
        studentModuleGrades = modules.filter(m => m.batchId === selectedStudent.batchId).map(m => {
            const logsForModule = logs.filter(l => l.moduleId === m.id && l.scores.some(s => s.studentId === selectedStudent.id));
            const modScores = logsForModule.flatMap(l => l.scores.filter(s => s.studentId === selectedStudent.id));
            const modAvg = modScores.length ? (modScores.reduce((a,b) => a + b.business + b.creativity + b.discipline, 0) / (modScores.length * 3)) : 0;
            return { name: m.name, avg: modAvg, sessions: logsForModule.length };
        });
    }

    const handlePrint = () => {
        if (!printRef.current) return;
        const printContent = printRef.current.innerHTML;
        const originalContent = document.body.innerHTML;
        document.body.innerHTML = printContent;
        window.print();
        document.body.innerHTML = originalContent;
        window.location.reload(); 
    };

    // -- Helpers for Export --
    const downloadCSV = (content: string, filename: string) => {
        const blob = new Blob([content], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        const url = URL.createObjectURL(blob);
        link.setAttribute('href', url);
        link.setAttribute('download', filename);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const generateWorkLogCSV = () => {
        const headers = ['Date', 'Mentor Name', 'Mentor Type', 'Module', 'Start Time', 'End Time', 'Duration (min)', 'Valid Session (>50m)', 'Recorded By', 'Status'];
        const rows = logs.map(log => {
            const mentor = users.find(u => u.id === log.mentorId);
            const module = modules.find(m => m.id === log.moduleId);
            const recorder = users.find(u => u.id === log.recordedBy);
            const isProxy = log.mentorId !== log.recordedBy;

            return [
                log.date,
                `"${mentor?.fullName || 'Unknown'}"`,
                mentor?.mentorType || 'N/A',
                `"${module?.name || 'Unknown'}"`,
                log.startTime,
                log.endTime,
                log.durationMinutes,
                log.isValidSession ? 'Yes' : 'No',
                isProxy ? `Admin (${recorder?.fullName})` : 'Self',
                log.status
            ].join(',');
        });

        const csvContent = [headers.join(','), ...rows].join('\n');
        downloadCSV(csvContent, `work_logs_${new Date().toISOString().split('T')[0]}.csv`);
    };

    const generateStudentPerfCSV = () => {
        const headers = ['Student Name', 'ID', 'Batch', 'Total Sessions', 'Attendance Rate %', 'Avg Business', 'Avg Creativity', 'Avg Discipline', 'Overall Avg'];
        const studentRows = students.map(student => {
            const sLogs = logs.filter(l => l.scores.some(s => s.studentId === student.id));
            const totalRecorded = sLogs.length;
            if (totalRecorded === 0) return [student.fullName, student.id, student.batchId, 0, 0, 0, 0, 0, 0].join(',');

            const scores = sLogs.flatMap(l => l.scores.filter(s => s.studentId === student.id));
            const presentCount = scores.filter(s => s.attendance !== AttendanceStatus.ABSENT).length;
            const attendanceRate = (presentCount / totalRecorded) * 100;

            const avgBus = scores.reduce((a,b) => a + b.business, 0) / totalRecorded;
            const avgCre = scores.reduce((a,b) => a + b.creativity, 0) / totalRecorded;
            const avgDis = scores.reduce((a,b) => a + b.discipline, 0) / totalRecorded;
            const overall = (avgBus + avgCre + avgDis) / 3;

            return [
                `"${student.fullName}"`,
                student.id,
                student.batchId,
                totalRecorded,
                attendanceRate.toFixed(1),
                avgBus.toFixed(2),
                avgCre.toFixed(2),
                avgDis.toFixed(2),
                overall.toFixed(2)
            ].join(',');
        });

        const csvContent = [headers.join(','), ...studentRows].join('\n');
        downloadCSV(csvContent, `student_performance_${new Date().toISOString().split('T')[0]}.csv`);
    };

    return (
        <div className="space-y-6 animate-fade-in">
             {/* Sub Nav */}
            <div className="flex gap-4 border-b border-gray-200">
                <button 
                    onClick={() => setSubTab('EXECUTIVE')}
                    className={`pb-2 px-1 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${subTab === 'EXECUTIVE' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500'}`}
                >
                    <PieChartIcon size={16} /> Executive Dashboard
                </button>
                <button 
                    onClick={() => setSubTab('TRANSCRIPT')}
                    className={`pb-2 px-1 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${subTab === 'TRANSCRIPT' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500'}`}
                >
                    <FileOutput size={16} /> Transcript Generator
                </button>
                <button 
                    onClick={() => setSubTab('EXPORTS')}
                    className={`pb-2 px-1 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${subTab === 'EXPORTS' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500'}`}
                >
                    <FileSpreadsheet size={16} /> Data Exports
                </button>
            </div>

            {subTab === 'EXECUTIVE' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Attendance Pie */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                        <h3 className="text-lg font-bold text-gray-800 mb-4">Overall Attendance Rate</h3>
                        <div className="h-64 flex flex-col items-center">
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie data={attendanceStats} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                                        {attendanceStats.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={entry.color} />
                                        ))}
                                    </Pie>
                                    <Tooltip />
                                </PieChart>
                            </ResponsiveContainer>
                            <div className="flex gap-4 text-xs mt-2">
                                {attendanceStats.map(s => (
                                    <div key={s.name} className="flex items-center gap-1">
                                        <div className="w-2 h-2 rounded-full" style={{backgroundColor: s.color}}></div>
                                        <span>{s.name}</span>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    {/* Competency Trend */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                         <h3 className="text-lg font-bold text-gray-800 mb-4">Competency Development</h3>
                         <div className="h-64">
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart data={trendData}>
                                    <defs>
                                        <linearGradient id="colorScore" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.8}/>
                                            <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
