                 activeTab === tab.id 
                 ? 'bg-indigo-600 text-white shadow-sm' 
                 : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'
               }`}
             >
               <tab.icon size={16} />
               <span className="hidden md:inline">{tab.label}</span>
             </button>
           ))}
        </div>
      </div>

      {/* Content Area */}
      <div className="min-h-[500px]">
        {activeTab === 'OVERVIEW' && <OverviewTab logs={logs} users={users} onNavigateToRedFlags={handleNavigateToRedFlags} />}
        {activeTab === 'APPROVALS' && <ApprovalsTab logs={logs} users={users} modules={modules} onUpdateStatus={updateLogStatus} />}
        {activeTab === 'PROXY_LOG' && <MentorLogForm />} 
        {activeTab === 'MONITORING' && (
            <MonitoringTab 
                logs={logs} 
                users={users} 
                interventions={interventions}
                onAddIntervention={addIntervention}
            />
        )}
        {activeTab === 'REPORTS' && (
             <ReportsTab logs={logs} users={users} modules={modules} />
        )}
        {activeTab === 'PEOPLE' && <PeopleTab users={users} logs={logs} />}
        {activeTab === 'SETUP' && (
          <SetupTab 
            batches={batches} 
            modules={modules} 
            groups={groups} 
            users={users} 
            onAddBatch={addBatch} 
            onAddModule={addModule} 
            onAddUser={addUser} 
            onAddGroup={addGroup}
            onUpdateGroup={updateGroup}
          />
        )}
      </div>
    </div>
  );
};

