const GroupManagement: React.FC<{
    groups: Group[];
    modules: Module[];
    users: User[];
    onSave: (group: Group) => void;
}> = ({ groups, modules, users, onSave }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingGroup, setEditingGroup] = useState<Group | null>(null);

    // Form State
    const [name, setName] = useState('');
    const [moduleId, setModuleId] = useState('');
    const [selectedMentorIds, setSelectedMentorIds] = useState<string[]>([]);
    const [selectedStudentIds, setSelectedStudentIds] = useState<string[]>([]);

    const openModal = (group?: Group) => {
        if (group) {
            setEditingGroup(group);
            setName(group.name);
            setModuleId(group.moduleId);
            setSelectedMentorIds(group.mentorIds);
            setSelectedStudentIds(group.studentIds);
        } else {
            setEditingGroup(null);
            setName('');
            setModuleId(modules[0]?.id || '');
            setSelectedMentorIds([]);
            setSelectedStudentIds([]);
        }
        setIsModalOpen(true);
    };

    const handleSave = () => {
        if (!name || !moduleId) {
            alert("Please fill in group name and select a module.");
            return;
        }
        const group: Group = {
            id: editingGroup ? editingGroup.id : `g-${Date.now()}`,
            name,
            moduleId,
            mentorIds: selectedMentorIds,
            studentIds: selectedStudentIds
        };
        onSave(group);
        setIsModalOpen(false);
    };

    // Filter students based on selected module's batch
    const selectedModule = modules.find(m => m.id === moduleId);
    const availableStudents = users.filter(u => u.role === Role.STUDENT && (!selectedModule || u.batchId === selectedModule.batchId));
    const availableMentors = users.filter(u => u.role === Role.MENTOR);

    return (
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 col-span-1 md:col-span-2">
            <div className="flex justify-between items-center mb-6">
                <div>
                    <h3 className="font-bold text-gray-800 flex items-center gap-2">
                        <Users size={20} className="text-indigo-600" /> Student Groups & Mentor Matching
                    </h3>
                    <p className="text-sm text-gray-500 mt-1">Assign students to groups and match them with mentors for a module.</p>
                </div>
                <button onClick={() => openModal()} className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-indigo-700">
                    <Plus size={16} /> Create Group
                </button>
            </div>

            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left border-collapse">
                    <thead className="bg-gray-50 text-gray-500 font-medium">
                        <tr>
                            <th className="p-3 border-b border-gray-100 rounded-tl-lg">Group Name</th>
                            <th className="p-3 border-b border-gray-100">Module</th>
                            <th className="p-3 border-b border-gray-100">Mentors</th>
                            <th className="p-3 border-b border-gray-100">Students</th>
                            <th className="p-3 border-b border-gray-100 rounded-tr-lg text-right">Action</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {groups.length === 0 && (
                            <tr>
                                <td colSpan={5} className="p-8 text-center text-gray-400 italic">No groups created yet.</td>
                            </tr>
                        )}
                        {groups.map(g => {
                            const mod = modules.find(m => m.id === g.moduleId);
                            return (
                                <tr key={g.id} className="hover:bg-gray-50 transition-colors">
                                    <td className="p-3 font-medium text-gray-900">{g.name}</td>
                                    <td className="p-3 text-gray-500">
                                        <span className="bg-indigo-50 text-indigo-700 px-2 py-0.5 rounded text-xs border border-indigo-100">
                                            {mod?.name}
                                        </span>
                                    </td>
                                    <td className="p-3">
                                        <div className="flex -space-x-2 overflow-hidden">
                                            {g.mentorIds.length === 0 && <span className="text-xs text-gray-400">No mentors</span>}
                                            {g.mentorIds.map(mid => {
                                                const m = users.find(u => u.id === mid);
                                                return (
                                                    <img 
                                                        key={mid} 
                                                        title={m?.fullName} 
                                                        className="inline-block h-8 w-8 rounded-full ring-2 ring-white bg-gray-200" 
                                                        src={m?.avatarUrl} 
                                                        alt={m?.fullName}
                                                    />
                                                );
                                            })}
                                        </div>
                                    </td>
                                    <td className="p-3 text-gray-600">
                                        <div className="flex items-center gap-2">
                                            <Users size={14} />
                                            <span className="font-medium">{g.studentIds.length}</span> Students
                                        </div>
                                    </td>
                                    <td className="p-3 text-right">
                                        <button 
                                            onClick={() => openModal(g)} 
                                            className="text-gray-500 hover:text-indigo-600 p-1.5 hover:bg-gray-100 rounded transition-colors"
                                        >
                                            <Edit size={16} />
                                        </button>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>

            {/* Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
                    <div className="bg-white rounded-xl shadow-2xl max-w-2xl w-full p-6 animate-fade-in max-h-[90vh] overflow-y-auto flex flex-col">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="text-xl font-bold text-gray-900">{editingGroup ? 'Edit Student Group' : 'Create New Group'}</h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600"><XCircle size={24} /></button>
                        </div>

                        <div className="space-y-5">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Group Name</label>
                                    <input 
                                        type="text" 
                                        value={name} 
                                        onChange={e => setName(e.target.value)} 
                                        placeholder="e.g. Group Alpha"
                                        className="w-full border border-gray-300 rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500" 
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Module</label>
                                    <select 
                                        value={moduleId} 
                                        onChange={e => {
                                            setModuleId(e.target.value);
                                            // Clear students if module changes as batch might change
                                            setSelectedStudentIds([]);
                                        }} 
                                        className="w-full border border-gray-300 rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                                    >
                                        <option value="" disabled>Select Module</option>
                                        {modules.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                                    </select>
                                </div>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                {/* Mentors List */}
                                <div className="border border-gray-200 rounded-xl overflow-hidden flex flex-col h-64">
                                    <div className="bg-gray-50 p-3 border-b border-gray-200 flex justify-between items-center">
                                        <span className="font-semibold text-gray-700 text-sm">Assign Mentors</span>
                                        <span className="bg-indigo-100 text-indigo-700 text-xs px-2 py-0.5 rounded-full">{selectedMentorIds.length} selected</span>
                                    </div>
                                    <div className="overflow-y-auto p-2 space-y-1 bg-white flex-1">
                                        {availableMentors.map(m => (
                                            <label key={m.id} className={`flex items-center gap-3 p-2 rounded-lg cursor-pointer transition-colors ${selectedMentorIds.includes(m.id) ? 'bg-indigo-50 border border-indigo-100' : 'hover:bg-gray-50 border border-transparent'}`}>
                                                <input 
                                                    type="checkbox" 
                                                    className="rounded text-indigo-600 focus:ring-indigo-500"
                                                    checked={selectedMentorIds.includes(m.id)}
                                                    onChange={e => {
                                                        if(e.target.checked) setSelectedMentorIds([...selectedMentorIds, m.id]);
                                                        else setSelectedMentorIds(selectedMentorIds.filter(id => id !== m.id));
                                                    }}
                                                />
                                                <div className="flex items-center gap-2">
                                                    <img src={m.avatarUrl} className="w-6 h-6 rounded-full" alt="" />
                                                    <div>
                                                        <div className="text-sm font-medium text-gray-900">{m.fullName}</div>
                                                        <div className="text-[10px] text-gray-500">{m.mentorType}</div>
                                                    </div>
                                                </div>
                                            </label>
                                        ))}
                                    </div>
                                </div>

                                {/* Students List */}
                                <div className="border border-gray-200 rounded-xl overflow-hidden flex flex-col h-64">
                                    <div className="bg-gray-50 p-3 border-b border-gray-200 flex justify-between items-center">
                                        <span className="font-semibold text-gray-700 text-sm">Assign Students</span>
                                        <span className="bg-green-100 text-green-700 text-xs px-2 py-0.5 rounded-full">{selectedStudentIds.length} selected</span>
                                    </div>
                                    <div className="overflow-y-auto p-2 space-y-1 bg-white flex-1">
                                        {!moduleId ? (
                                             <div className="h-full flex flex-col items-center justify-center text-gray-400 text-xs">
                                                 <BookOpen size={24} className="mb-2 opacity-20"/>
                                                 Please select a module first
                                             </div>
                                        ) : availableStudents.length === 0 ? (
                                            <div className="h-full flex items-center justify-center text-gray-400 text-xs">No eligible students found in this module's batch.</div>
                                        ) : (
                                            availableStudents.map(s => (
                                                <label key={s.id} className={`flex items-center gap-3 p-2 rounded-lg cursor-pointer transition-colors ${selectedStudentIds.includes(s.id) ? 'bg-green-50 border border-green-100' : 'hover:bg-gray-50 border border-transparent'}`}>
                                                    <input 
                                                        type="checkbox" 
                                                        className="rounded text-green-600 focus:ring-green-500"
                                                        checked={selectedStudentIds.includes(s.id)}
                                                        onChange={e => {
                                                            if(e.target.checked) setSelectedStudentIds([...selectedStudentIds, s.id]);
                                                            else setSelectedStudentIds(selectedStudentIds.filter(id => id !== s.id));
                                                        }}
                                                    />
                                                    <div className="flex items-center gap-2">
                                                        <img src={s.avatarUrl} className="w-6 h-6 rounded-full" alt="" />
                                                        <span className="text-sm font-medium text-gray-900">{s.fullName}</span>
                                                    </div>
                                                </label>
                                            ))
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-gray-100">
                            <button onClick={() => setIsModalOpen(false)} className="px-5 py-2 text-gray-600 hover:bg-gray-100 rounded-lg text-sm font-medium transition-colors">Cancel</button>
                            <button onClick={handleSave} className="px-5 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-md transition-all flex items-center gap-2">
                                <CheckCircle size={16} /> Save Group
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

