export enum Role {
  ADMIN = 'ADMIN',
  MENTOR = 'MENTOR',
  STUDENT = 'STUDENT'
}

export enum MentorType {
  INTERNAL = 'INTERNAL', // University Staff (600 THB rate logic hidden)
  EXTERNAL = 'EXTERNAL', // Industry Expert (1200 THB rate logic hidden)
  NONE = 'NONE'
}

export enum LogStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED'
}

export enum AttendanceStatus {
  PRESENT = 'PRESENT',
  LATE = 'LATE',
  ABSENT = 'ABSENT'
}

export enum ActivityType {
  LECTURE = 'LECTURE',
  PRACTICE = 'PRACTICE'
}

export interface User {
  id: string;
  role: Role;
  fullName: string;
  email: string;
  avatarUrl?: string;
  // Specific to mentors
  mentorType?: MentorType; 
  // Specific to students
  batchId?: string;
}

export interface Batch {
  id: string;
  name: string; // e.g. "Gen 8"
  startDate: string; // ISO Date YYYY-MM-DD
  endDate: string; // ISO Date YYYY-MM-DD
  status: 'ACTIVE' | 'CLOSED';
}

export interface Module {
  id: string;
  batchId: string;
  name: string; // e.g. "Data Science"
}

export interface Group {
  id: string;
  moduleId: string;
  name: string; // e.g. "Group A"
  mentorIds: string[]; 
  studentIds: string[];
}

export interface LessonPlan {
  id: string;
  moduleId: string;
  date: string; // YYYY-MM-DD
  startTime: string; // HH:mm
  endTime: string; // HH:mm
  durationMinutes: number;
  activityType: ActivityType;
  topic: string;
  mentorId: string;
}

export interface CompetencyScore {
  studentId: string;
  attendance: AttendanceStatus;
  business: number; // 0-5
  creativity: number; // 0-5
  discipline: number; // 0-5
}

export interface LogHistory {
  timestamp: string; // ISO Date
  actorId: string; // User ID who performed the action
  action: string; // e.g. "Created", "Approved", "Rejected"
  note?: string; // Optional reason
}

export interface Intervention {
  id: string;
  studentId: string;
  adminId: string;
  date: string; // ISO Date
  type: 'CALL' | 'EMAIL' | 'MEETING' | 'IDP_SENT' | 'OTHER';
  note: string;
}

export interface MentoringLog {
  id: string;
  mentorId: string; // The mentor who taught the session
  recordedBy: string; // The user who entered the log (Could be Admin)
  batchId: string;
  moduleId: string; // Link to specific module
  date: string;
  startTime: string; // HH:mm
  endTime: string; // HH:mm
  durationMinutes: number;
  isValidSession: boolean; // True if >= 50 mins
  status: LogStatus;
  summaryNote: string;
  artifactUrl: string;
  scores: CompetencyScore[]; // One entry per student in the session
  history: LogHistory[]; // Audit trail
}

export interface SessionValidation {
  isValid: boolean;
  message: string;
  duration: number;
}

import React, { createContext, useContext, useState, ReactNode } from 'react';
