                      </div>
                  </div>
                  <button 
                    type="button" 
                    onClick={applyLessonPlan}
                    className="bg-blue-600 text-white text-xs px-3 py-1.5 rounded-md hover:bg-blue-700"
                  >
                      Apply Plan
