                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
            )}
        </section>

        {/* Section 3: Evidence & Summary */}
        <section className="bg-gray-50 p-6 rounded-lg border border-gray-200">
             <div className="mb-4">
                 <label className="block text-sm font-medium text-gray-700 mb-2">Session Summary</label>
                 <textarea 
                    value={summary}
                    onChange={(e) => setSummary(e.target.value)}
                    placeholder="Briefly describe what was covered..."
                    rows={3}
                    className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 p-2 border"
                 />
             </div>
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                    <LinkIcon className="w-4 h-4" /> Artifact / Evidence (Required)
                </label>
                <div className="flex gap-2">
                    <input 
                        type="url" 
                        value={artifactUrl}
                        onChange={(e) => setArtifactUrl(e.target.value)}
                        placeholder="https://github.com/..."
                        className="flex-1 rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 p-2 border"
                        required
                    />
                    <button type="button" className="bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded-lg text-sm hover:bg-gray-50 flex items-center gap-2">
                        <Upload className="w-4 h-4" /> Upload
                    </button>
                </div>
             </div>
        </section>

        {/* Footer */}
        <div className="flex items-center justify-between pt-4 border-t border-gray-100">
             <div className="text-sm text-gray-500">
                System Status: <span className="font-semibold text-gray-800">Online</span>
             </div>
             <button 
                type="submit" 
                disabled={isSubmitting}
                className={`flex items-center gap-2 text-white px-6 py-2.5 rounded-lg font-medium shadow-md transition-all ${isSubmitting ? 'opacity-70 cursor-not-allowed' : ''} ${isAdmin ? 'bg-indigo-700 hover:bg-indigo-800' : 'bg-indigo-600 hover:bg-indigo-700'}`}
             >
                <Save className="w-4 h-4" />
                {isSubmitting ? 'Submitting...' : 'Submit Log'}
             </button>
        </div>
        {successMsg && (
            <div className="bg-green-100 text-green-800 p-4 rounded-lg flex items-center gap-2 animate-bounce">
                <CheckCircle className="w-5 h-5" /> {successMsg}
            </div>
        )}
      </form>
    </div>
  );
};

import React from 'react';
