                            <PolarGrid />
                            <PolarAngleAxis dataKey="subject" />
                            <PolarRadiusAxis angle={30} domain={[0, 5]} />
                            <Radar name="My Competency" dataKey="A" stroke="#4f46e5" fill="#4f46e5" fillOpacity={0.6} />
                            <Tooltip />
                        </RadarChart>
                    </ResponsiveContainer>
                ) : (
                    <p className="text-gray-400">No assessment data available yet.</p>
                )}
