               <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                    <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
                        <Calendar className="w-5 h-5 text-gray-500" /> Recent Sessions
                    </h3>
                    <div className="space-y-3">
                        {myScores.slice(0, 3).map((score, idx) => {
                            // Calc average for this specific session
                            const values = Object.values(score.metrics);
                            const avg = values.length > 0 ? values.reduce((a,b) => a+b, 0) / values.length : 0;

                            return (
                                <div key={idx} className="flex justify-between items-center p-3 hover:bg-gray-50 rounded-lg transition-colors border-b border-gray-50 last:border-0">
                                    <div>
                                        <p className="text-sm font-medium text-gray-900">{score.date}</p>
