import React, { useState, useEffect } from 'react';
import { useData } from '../services/DataContext';
import { AttendanceStatus, CompetencyScore, LogStatus, MentoringLog, Role, LessonPlan } from '../types';
import { Clock, Users, Save, Link as LinkIcon, Upload, AlertTriangle, CheckCircle, Shield, CalendarCheck, HelpCircle, ArrowLeft } from 'lucide-react';

interface MentorLogFormProps {
  initialData?: Partial<MentoringLog> & { lessonPlanId?: string };
  onSuccess?: () => void;
  onCancel?: () => void;
}

export const MentorLogForm: React.FC<MentorLogFormProps> = ({ initialData, onSuccess, onCancel }) => {
  const { batches, getModulesByBatch, currentUser, getStudentsByBatch, addLog, users, lessonPlans } = useData();

  // Local State
  const [selectedBatchId, setSelectedBatchId] = useState(batches[0]?.id || '');
  const [selectedModuleId, setSelectedModuleId] = useState('');

  // Admin Proxy State
  const isAdmin = currentUser.role === Role.ADMIN;
  const mentors = users.filter(u => u.role === Role.MENTOR);
  const [selectedMentorId, setSelectedMentorId] = useState('');

  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [summary, setSummary] = useState('');
  const [artifactUrl, setArtifactUrl] = useState('');
  const [scores, setScores] = useState<CompetencyScore[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  const students = getStudentsByBatch(selectedBatchId);
  const modules = getModulesByBatch(selectedBatchId);
  const selectedModule = modules.find(m => m.id === selectedModuleId);

  // Backdate limitation logic: Mentors max 3 days, Admin unlimited
  const minDate = isAdmin ? undefined : new Date(Date.now() - 3 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

  // Load Initial Data (From Dashboard)
  useEffect(() => {
    if (initialData) {
      if (initialData.batchId) setSelectedBatchId(initialData.batchId);
      if (initialData.moduleId) setSelectedModuleId(initialData.moduleId);
      if (initialData.date) setDate(initialData.date);
      if (initialData.startTime) setStartTime(initialData.startTime);
      if (initialData.endTime) setEndTime(initialData.endTime);
      if (initialData.summaryNote) setSummary(initialData.summaryNote);
      if (initialData.artifactUrl) setArtifactUrl(initialData.artifactUrl);
      if (initialData.scores) setScores(initialData.scores);
      if (initialData.mentorId && isAdmin) setSelectedMentorId(initialData.mentorId);
    }
  }, [initialData, isAdmin]);

  // Auto-select first module if available when batch changes
  useEffect(() => {
    if (!initialData?.moduleId && modules.length > 0) {
      setSelectedModuleId(modules[0].id);
    }
  }, [selectedBatchId, modules, initialData]);

  // Set default mentor ID if Admin
  useEffect(() => {
      if (isAdmin && mentors.length > 0 && !selectedMentorId) {
          setSelectedMentorId(mentors[0].id);
      }
  }, [isAdmin, mentors]);

  // Initialize scores
  useEffect(() => {
    if (students.length > 0 && scores.length === 0) {
      const activeCategories = selectedModule?.assessmentConfig?.filter(c => c.isEnabled) || [];

      const initialScores: CompetencyScore[] = students.map(s => {
          const metrics: Record<string, number> = {};
          if (activeCategories.length > 0) {
              activeCategories.forEach(cat => metrics[cat.name] = 3);
          } else {
              // Fallback default
              metrics['Business Acumen'] = 3;
              metrics['Creativity'] = 3;
              metrics['Discipline'] = 3;
          }

          return {
            studentId: s.id,
            attendance: AttendanceStatus.PRESENT,
            metrics: metrics
          };
      });
      setScores(initialScores);
    }
  }, [selectedBatchId, students.length, selectedModuleId, selectedModule, scores.length]); 

  // Check for Lesson Plans (Logic mostly for manual entry, redundant if initialData passed but good to keep)
  const availablePlan = lessonPlans.find(p => p.moduleId === selectedModuleId && p.date === date);

  const applyLessonPlan = () => {
      if (availablePlan) {
          setStartTime(availablePlan.startTime);
          setEndTime(availablePlan.endTime);
          setSummary(availablePlan.topic);
          if (availablePlan.mentorId && isAdmin) {
              setSelectedMentorId(availablePlan.mentorId);
          }
      }
  };

  const calculateDuration = () => {
    if (!startTime || !endTime) return 0;
    const start = new Date(`2000-01-01T${startTime}`);
    const end = new Date(`2000-01-01T${endTime}`);
    const diffMs = end.getTime() - start.getTime();
    return Math.max(0, Math.floor(diffMs / 60000));
  };

  const duration = calculateDuration();
  const isValidSession = duration >= 50;

  const handleScoreChange = (studentId: string, categoryName: string, value: number) => {
    setScores(prev => prev.map(s => {
        if (s.studentId !== studentId) return s;
        return {
            ...s,
            metrics: {
                ...s.metrics,
                [categoryName]: value
            }
        };
    }));
  };

  const handleAttendanceChange = (studentId: string, status: AttendanceStatus) => {
      setScores(prev => prev.map(s => s.studentId === studentId ? { ...s, attendance: status } : s));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isAdmin && !selectedMentorId) {
        alert("Please select a mentor to record for.");
        return;
    }
    if (!selectedModuleId) {
        alert("Please select a teaching module.");
        return;
    }
    if (!artifactUrl) {
      alert("Please provide an artifact link (Proof of work).");
      return;
    }

    setIsSubmitting(true);

    const newLog: MentoringLog = {
      id: initialData?.id || `log-${Date.now()}`,
      mentorId: '', 
      recordedBy: '', 
      batchId: selectedBatchId,
      moduleId: selectedModuleId,
      date,
      startTime,
      endTime,
      durationMinutes: duration,
      isValidSession: isValidSession,
      status: LogStatus.PENDING,
      summaryNote: summary,
      artifactUrl,
      scores,
      history: []
    };

    setTimeout(() => {
        addLog(newLog, isAdmin ? selectedMentorId : undefined);
        setIsSubmitting(false);
        setSuccessMsg("Log submitted successfully!");
        setSummary('');
        setArtifactUrl('');

        if (onSuccess) {
            setTimeout(() => onSuccess(), 1000);
        } else {
            setTimeout(() => setSuccessMsg(''), 3000);
        }
    }, 800);
  };

  // Determine which categories to render
  const activeCategories = selectedModule?.assessmentConfig?.filter(c => c.isEnabled) || [
      { id: 'def-1', name: 'Business Acumen', description: 'Business understanding', weight: 0, isEnabled: true },
      { id: 'def-2', name: 'Creativity', description: 'Innovation capability', weight: 0, isEnabled: true },
      { id: 'def-3', name: 'Discipline', description: 'Professionalism', weight: 0, isEnabled: true }
  ];

  return (
    <div className={`bg-white rounded-xl shadow-sm border overflow-hidden ${isAdmin ? 'border-indigo-200' : 'border-gray-100'}`}>
      <div className={`p-6 border-b ${isAdmin ? 'bg-indigo-600 text-white' : 'bg-indigo-50 text-indigo-900'}`}>
        <div className="flex justify-between items-start">
            <div className="flex items-center gap-3">
                {onCancel && (
                    <button onClick={onCancel} className={`p-1.5 rounded-full ${isAdmin ? 'bg-indigo-700 hover:bg-indigo-800' : 'bg-white hover:bg-gray-100 text-gray-600'}`}>
                        <ArrowLeft size={20} />
                    </button>
                )}
                <div>
                    <h2 className="text-xl font-bold flex items-center gap-2">
                        <Clock className="w-5 h-5" /> 
                        {isAdmin ? "Admin Proxy Entry" : initialData ? "Complete Session Log" : "New Session Log"}
                    </h2>
                    <p className={`text-sm mt-1 ${isAdmin ? 'text-indigo-100' : 'text-indigo-600'}`}>
                        {isAdmin 
                            ? "You are recording a session on behalf of a mentor." 
                            : "Record your mentoring activity. Sessions must be 50+ minutes."}
                    </p>
                </div>
            </div>
            {isAdmin && <Shield className="w-8 h-8 text-indigo-300 opacity-50" />}
        </div>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-8">

        {/* Admin Proxy Selection */}
        {isAdmin && (
            <div className="bg-yellow-50 border border-yellow-200 p-4 rounded-lg flex items-center gap-4">
                <div className="flex-shrink-0">
                    <Shield className="w-6 h-6 text-yellow-600" />
                </div>
                <div className="flex-1">
                    <label className="block text-sm font-bold text-yellow-800 mb-1">Log on behalf of Mentor:</label>
                    <select
                        value={selectedMentorId}
                        onChange={(e) => setSelectedMentorId(e.target.value)}
                        className="w-full rounded border-yellow-300 p-2 text-sm focus:ring-yellow-500 focus:border-yellow-500"
                    >
                        <option value="">-- Select Mentor --</option>
                        {mentors.map(m => (
                            <option key={m.id} value={m.id}>
                                {m.fullName} ({m.mentorType})
                            </option>
                        ))}
                    </select>
                </div>
            </div>
        )}

        {/* Section 1: Session Details */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-6 relative">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Batch (Cohort)</label>
            <select 
              value={selectedBatchId}
              onChange={(e) => setSelectedBatchId(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
              disabled={!!initialData}
            >
              {batches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Teaching Module</label>
            <select 
              value={selectedModuleId}
              onChange={(e) => setSelectedModuleId(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
              disabled={modules.length === 0 || !!initialData}
            >
              {modules.length === 0 && <option>No modules found</option>}
              {modules.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Date</label>
            <input 
              type="date" 
              value={date}
              min={minDate}
              onChange={(e) => setDate(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border"
              disabled={!!initialData?.date}
            />
             {!isAdmin && <p className="text-[10px] text-gray-500 mt-1">Mentors can only log up to 3 days prior.</p>}
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
                <label className="block text-xs font-medium text-gray-500 uppercase mb-1">Start Time</label>
                <input 
                    type="time" 
                    value={startTime}
                    onChange={(e) => setStartTime(e.target.value)}
                    className="w-full rounded-lg border-gray-300 p-2 border"
                    required
                />
             </div>
             <div>
                <label className="block text-xs font-medium text-gray-500 uppercase mb-1">End Time</label>
                <input 
                    type="time" 
                    value={endTime}
                    onChange={(e) => setEndTime(e.target.value)}
                    className="w-full rounded-lg border-gray-300 p-2 border"
                    required
                />
             </div>
          </div>

          {/* Plan Auto-fill Notification */}
          {availablePlan && !initialData && (
              <div className="col-span-1 md:col-span-2 bg-blue-50 border border-blue-200 rounded-lg p-3 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                      <CalendarCheck className="text-blue-600 w-5 h-5" />
                      <div>
                          <p className="text-sm font-bold text-blue-900">Planned Session Found!</p>
                          <p className="text-xs text-blue-700">Topic: {availablePlan.topic} ({availablePlan.startTime} - {availablePlan.endTime})</p>
                      </div>
                  </div>
                  <button 
                    type="button" 
                    onClick={applyLessonPlan}
                    className="bg-blue-600 text-white text-xs px-3 py-1.5 rounded-md hover:bg-blue-700"
                  >
                      Apply Plan
                  </button>
              </div>
          )}

          <div className="col-span-1 md:col-span-2">
             <div className={`rounded-lg border p-4 flex flex-col items-center justify-center transition-colors ${isValidSession ? 'bg-green-50 border-green-200' : 'bg-red-50 border-red-200'}`}>
                 <div className="text-center">
                     <p className="text-xs text-gray-500 uppercase font-semibold mb-1">Net Duration</p>
                     <p className={`text-3xl font-bold ${isValidSession ? 'text-green-700' : 'text-red-600'}`}>
                         {duration} min
                     </p>
                 </div>
                 <div className="mt-2 flex items-center gap-2">
                     {isValidSession ? (
                        <>
                            <CheckCircle size={18} className="text-green-600" />
                            <span className="text-sm font-medium text-green-800">Valid Working Hour (1 Credit)</span>
                        </>
                     ) : (
                        <>
                            <AlertTriangle size={18} className="text-red-600" />
                            <span className="text-sm font-medium text-red-800">Duration too short (Min. 50 mins required)</span>
                        </>
                     )}
                 </div>
             </div>
          </div>
        </section>

        {/* Section 2: Student Assessment */}
        <section>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2">
                    <Users className="w-5 h-5 text-indigo-500" /> Attendance & Competency
                </h3>
                <span className="text-xs text-gray-500 bg-gray-100 px-2 py-1 rounded">
                    Using Rubric: {selectedModule?.assessmentConfig ? 'Custom' : 'Default'}
                </span>
            </div>

            {students.length === 0 ? (
                <div className="text-center p-6 bg-gray-50 rounded-lg text-gray-500">
                    No students found in this batch.
                </div>
            ) : (
                <div className="space-y-6">
                {students.map((student) => {
                    const score = scores.find(s => s.studentId === student.id);
                    if (!score) return null;

                    return (
                        <div key={student.id} className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm hover:shadow-md transition-shadow">
                            <div className="flex flex-col sm:flex-row justify-between sm:items-center mb-4 gap-4">
                                <div className="flex items-center gap-3">
                                    <img src={student.avatarUrl} alt={student.fullName} className="w-10 h-10 rounded-full" />
                                    <span className="font-medium text-gray-900">{student.fullName}</span>
                                </div>
                                <div className="flex bg-gray-100 rounded-lg p-1">
                                    {[AttendanceStatus.PRESENT, AttendanceStatus.LATE, AttendanceStatus.ABSENT].map((status) => (
                                        <button
                                            type="button"
                                            key={status}
                                            onClick={() => handleAttendanceChange(student.id, status)}
                                            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                                                score.attendance === status 
                                                ? status === AttendanceStatus.PRESENT ? 'bg-green-500 text-white' 
                                                : status === AttendanceStatus.LATE ? 'bg-yellow-500 text-white' 
                                                : 'bg-red-500 text-white'
                                                : 'text-gray-500 hover:text-gray-900'
                                            }`}
                                        >
                                            {status}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Rubrics - Only show if present or late */}
                            {score.attendance !== AttendanceStatus.ABSENT && (
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 pt-2 border-t border-gray-100">
                                    {activeCategories.map((cat) => (
                                        <div key={cat.id} className="group relative">
                                            <div className="flex justify-between mb-1">
                                                <label className="text-xs font-medium text-gray-500 uppercase flex items-center gap-1">
                                                    {cat.name}
                                                    {cat.description && (
                                                        <span className="text-gray-300 group-hover:text-indigo-400 cursor-help" title={`Score 5 Criteria: ${cat.description}`}>
                                                            <HelpCircle size={12} />
                                                        </span>
                                                    )}
                                                </label>
                                                <span className="text-xs font-bold text-indigo-600">{(score.metrics[cat.name] || 0)}/5</span>
                                            </div>
                                            <input 
                                                type="range" 
                                                min="0" max="5" step="1"
                                                value={(score.metrics[cat.name] || 0)}
                                                onChange={(e) => handleScoreChange(student.id, cat.name, parseInt(e.target.value))}
                                                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                                            />
                                            <div className="flex justify-between text-[10px] text-gray-400 mt-1">
                                                <span>Poor</span>
                                                <span className="hidden group-hover:inline text-indigo-500">{cat.description?.substring(0,20)}...</span>
                                                <span>Excellent</span>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
            )}
        </section>

        {/* Section 3: Evidence & Summary */}
        <section className="bg-gray-50 p-6 rounded-lg border border-gray-200">
             <div className="mb-4">
                 <label className="block text-sm font-medium text-gray-700 mb-2">Session Summary</label>
                 <textarea 
                    value={summary}
                    onChange={(e) => setSummary(e.target.value)}
                    placeholder="Briefly describe what was covered..."
                    rows={3}
                    className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 p-2 border"
                 />
             </div>
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                    <LinkIcon className="w-4 h-4" /> Artifact / Evidence (Required)
                </label>
                <div className="flex gap-2">
                    <input 
                        type="url" 
                        value={artifactUrl}
                        onChange={(e) => setArtifactUrl(e.target.value)}
                        placeholder="https://github.com/..."
                        className="flex-1 rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 p-2 border"
                        required
                    />
                    <button type="button" className="bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded-lg text-sm hover:bg-gray-50 flex items-center gap-2">
                        <Upload className="w-4 h-4" /> Upload
                    </button>
                </div>
             </div>
        </section>

        {/* Footer */}
        <div className="flex items-center justify-between pt-4 border-t border-gray-100">
             <div className="text-sm text-gray-500">
                System Status: <span className="font-semibold text-gray-800">Online</span>
             </div>
             <button 
                type="submit" 
                disabled={isSubmitting}
                className={`flex items-center gap-2 text-white px-6 py-2.5 rounded-lg font-medium shadow-md transition-all ${isSubmitting ? 'opacity-70 cursor-not-allowed' : ''} ${isAdmin ? 'bg-indigo-700 hover:bg-indigo-800' : 'bg-indigo-600 hover:bg-indigo-700'}`}
             >
                <Save className="w-4 h-4" />
                {isSubmitting ? 'Submitting...' : 'Submit Log'}
             </button>
        </div>
        {successMsg && (
            <div className="bg-green-100 text-green-800 p-4 rounded-lg flex items-center gap-2 animate-bounce">
                <CheckCircle className="w-5 h-5" /> {successMsg}
            </div>
        )}
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { useData } from '../services/DataContext';
import { LogStatus, MentoringLog, ActivityType, LessonPlan } from '../types';
import { 
  Bell, BookOpen, Calendar, CheckCircle, Clock, FileText, 
  LayoutDashboard, PieChart, Plus, Search, TrendingUp, 
  Upload, XCircle, ChevronRight, PlayCircle
} from 'lucide-react';
import { RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, ResponsiveContainer, Tooltip } from 'recharts';
import { MentorLogForm } from './MentorLogForm';

export const MentorDashboard: React.FC = () => {
    const { currentUser, lessonPlans, logs, modules, batches } = useData();
    const [view, setView] = useState<'dashboard' | 'log_entry'>('dashboard');
    const [selectedPlan, setSelectedPlan] = useState<LessonPlan | null>(null);
    const [selectedLogToEdit, setSelectedLogToEdit] = useState<MentoringLog | null>(null);

    // --- Data Preparation ---

    // 1. Today's Classes
    const today = new Date().toISOString().split('T')[0];
    const todaysClasses = lessonPlans.filter(p => p.mentorId === currentUser.id && p.date === today);

    // 2. Pending Actions (Rejected Logs)
    const rejectedLogs = logs.filter(l => l.mentorId === currentUser.id && l.status === LogStatus.REJECTED);

    // 3. Stats (Hours)
    const myLogs = logs.filter(l => l.mentorId === currentUser.id && l.status === LogStatus.APPROVED);

    // Attempt to categorize hours by Lecture (L) vs Practice (P) based on Module or Plan matches
    // Note: Since Logs don't strictly have 'ActivityType', we infer or default to L for now, 
    // or ideally map back to the plan. For this demo, let's assume valid logs are 60% practice.
    const totalMinutes = myLogs.reduce((acc, l) => acc + l.durationMinutes, 0);
    const totalHours = totalMinutes / 60;

    // Mock split for demonstration as logs don't have explicit activity type yet
    const lectureHours = totalHours * 0.4; 
    const practiceHours = totalHours * 0.6;

    // 4. Module Progress
    const myModules = modules.filter(m => 
        // Find modules where this mentor has any lesson plans or logs
        lessonPlans.some(p => p.mentorId === currentUser.id && p.moduleId === m.id) ||
        logs.some(l => l.mentorId === currentUser.id && l.moduleId === m.id)
    );

    const getModuleProgress = (moduleId: string) => {
        const planned = lessonPlans.filter(p => p.moduleId === moduleId && p.mentorId === currentUser.id).length;
        const logged = logs.filter(l => l.moduleId === moduleId && l.mentorId === currentUser.id).length;
        const total = Math.max(planned, 1); // Avoid div by 0
        const percent = Math.min(100, Math.round((logged / total) * 100));
        return { logged, planned, percent };
    };

    // 5. Student Insights (Aggregated Radar)
    // Get all scores given by this mentor
    const myGivenScores = logs.filter(l => l.mentorId === currentUser.id).flatMap(l => l.scores);
    const metricTotals: Record<string, { sum: number, count: number }> = {};

    myGivenScores.forEach(score => {
        Object.entries(score.metrics).forEach(([key, value]) => {
            if (!metricTotals[key]) metricTotals[key] = { sum: 0, count: 0 };
            metricTotals[key].sum += (value as number);
            metricTotals[key].count += 1;
        });
    });

    const radarData = Object.keys(metricTotals).map(key => ({
        subject: key,
        A: metricTotals[key].count > 0 ? (metricTotals[key].sum / metricTotals[key].count) : 0,
        fullMark: 5
    }));

    // 6. Recent Artifacts
    const recentArtifacts = logs
        .filter(l => l.mentorId === currentUser.id && l.artifactUrl)
        .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime())
        .slice(0, 3);

    // --- Handlers ---

    const handleStartLog = (plan?: LessonPlan) => {
        setSelectedPlan(plan || null);
        setSelectedLogToEdit(null);
        setView('log_entry');
    };

    const handleEditLog = (log: MentoringLog) => {
        setSelectedLogToEdit(log);
        setSelectedPlan(null);
        setView('log_entry');
    };

    const handleLogSuccess = () => {
        setView('dashboard');
        setSelectedPlan(null);
        setSelectedLogToEdit(null);
    };

    if (view === 'log_entry') {
        const initialData = selectedLogToEdit || (selectedPlan ? {
            moduleId: selectedPlan.moduleId,
            date: selectedPlan.date,
            startTime: selectedPlan.startTime,
            endTime: selectedPlan.endTime,
            summaryNote: selectedPlan.topic,
        } : undefined);

        return (
            <MentorLogForm 
                initialData={initialData} 
                onSuccess={handleLogSuccess}
                onCancel={() => setView('dashboard')}
            />
        );
    }

    return (
        <div className="space-y-6 animate-fade-in">
            {/* Header */}
            <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Hello, {currentUser.fullName}</h1>
                    <p className="text-gray-500">Here's your teaching summary for {new Date().toLocaleDateString('en-US', { weekday: 'long', day: 'numeric', month: 'long'})}</p>
                </div>
                <div className="flex gap-3">
                     <button className="p-2 bg-white border border-gray-200 rounded-full text-gray-500 hover:text-indigo-600 relative">
                        <Bell size={20} />
                        {rejectedLogs.length > 0 && <span className="absolute top-0 right-0 w-3 h-3 bg-red-500 rounded-full border-2 border-white"></span>}
                     </button>
                     <button className="flex items-center gap-2 bg-white border border-gray-200 text-gray-700 px-4 py-2 rounded-lg text-sm font-medium hover:bg-gray-50">
                        <FileText size={16} /> Export Report
                     </button>
                </div>
            </header>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* Column 1: Immediate Actions */}
                <div className="lg:col-span-2 space-y-6">

                    {/* Today's Classes Card */}
                    <div className="bg-indigo-600 rounded-2xl p-6 text-white shadow-lg relative overflow-hidden">
                        <div className="relative z-10">
                            <h2 className="text-lg font-bold flex items-center gap-2 mb-4">
                                <Calendar className="w-5 h-5" /> Today's Classes
                            </h2>

                            {todaysClasses.length === 0 ? (
                                <div className="text-indigo-100 bg-indigo-700/50 p-4 rounded-xl flex items-center justify-between">
                                    <span>No classes scheduled for today.</span>
                                    <button 
                                        onClick={() => handleStartLog()}
                                        className="bg-white text-indigo-600 px-4 py-2 rounded-lg text-sm font-bold shadow-sm hover:bg-indigo-50"
                                    >
                                        Record Unscheduled Log
                                    </button>
                                </div>
                            ) : (
                                <div className="space-y-3">
                                    {todaysClasses.map(plan => {
                                        const moduleName = modules.find(m => m.id === plan.moduleId)?.name;
                                        const isDone = logs.some(l => l.mentorId === currentUser.id && l.date === plan.date && l.startTime === plan.startTime);

                                        return (
                                            <div key={plan.id} className="bg-white/10 backdrop-blur-sm p-4 rounded-xl border border-indigo-400/30 flex justify-between items-center">
                                                <div>
                                                    <div className="flex items-center gap-2 text-indigo-100 text-xs font-medium uppercase mb-1">
                                                        <Clock size={12} /> {plan.startTime} - {plan.endTime}
                                                        <span className={`px-1.5 py-0.5 rounded border ${plan.activityType === ActivityType.LECTURE ? 'bg-blue-500/20 border-blue-300/50' : 'bg-green-500/20 border-green-300/50'}`}>
                                                            {plan.activityType}
                                                        </span>
                                                    </div>
                                                    <h3 className="font-bold text-lg">{moduleName}</h3>
                                                    <p className="text-indigo-200 text-sm">{plan.topic}</p>
                                                </div>

                                                {isDone ? (
                                                    <button disabled className="bg-green-500 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 cursor-default">
                                                        <CheckCircle size={16} /> Logged
                                                    </button>
                                                ) : (
                                                    <button 
                                                        onClick={() => handleStartLog(plan)}
                                                        className="bg-white text-indigo-600 px-4 py-2 rounded-lg text-sm font-bold shadow-sm hover:bg-indigo-50 flex items-center gap-2 transition-all hover:scale-105"
                                                    >
                                                        <PlayCircle size={16} /> Start Class
                                                    </button>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                        {/* Decorative Background */}
                        <div className="absolute -right-10 -bottom-10 w-64 h-64 bg-indigo-500 rounded-full opacity-20 blur-3xl"></div>
                    </div>

                    {/* Pending Tasks / Rejected Logs */}
                    {rejectedLogs.length > 0 && (
                        <div className="bg-white border border-red-200 rounded-xl p-5 shadow-sm">
                            <h3 className="text-red-700 font-bold flex items-center gap-2 mb-3">
                                <XCircle size={20} /> Action Required
                            </h3>
                            <div className="space-y-3">
                                {rejectedLogs.map(log => (
                                    <div key={log.id} className="flex items-center justify-between p-3 bg-red-50 rounded-lg border border-red-100">
                                        <div>
                                            <p className="text-sm font-bold text-gray-800">{log.summaryNote}</p>
                                            <p className="text-xs text-red-600 mt-1">
                                                Reason: {log.history[log.history.length-1]?.note || "Please revise."}
                                            </p>
                                        </div>
                                        <button 
                                            onClick={() => handleEditLog(log)}
                                            className="text-xs bg-white border border-red-200 text-red-600 px-3 py-1.5 rounded-md font-bold hover:bg-red-50"
                                        >
                                            Fix & Resubmit
                                        </button>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Progress Tracking */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                        <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                            <TrendingUp size={20} className="text-indigo-600" /> Module Progress
                        </h3>
                        <div className="space-y-5">
                            {myModules.length === 0 && <p className="text-gray-400 text-sm">No modules assigned.</p>}
                            {myModules.map(m => {
                                const { logged, planned, percent } = getModuleProgress(m.id);
                                return (
                                    <div key={m.id}>
                                        <div className="flex justify-between text-sm mb-1">
                                            <span className="font-medium text-gray-700">{m.name}</span>
                                            <span className="text-gray-500">{logged}/{planned} Sessions</span>
                                        </div>
                                        <div className="w-full bg-gray-100 rounded-full h-2.5">
                                            <div 
                                                className="bg-indigo-600 h-2.5 rounded-full transition-all duration-500" 
                                                style={{ width: `${percent}%` }}
                                            ></div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                </div>

                {/* Column 2: Stats & Insights */}
                <div className="space-y-6">

                    {/* Hours Summary */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                        <h3 className="font-bold text-gray-800 mb-4">Cumulative Hours</h3>
                        <div className="flex items-end gap-2 mb-2">
                            <span className="text-4xl font-bold text-indigo-900">{totalHours.toFixed(1)}</span>
                            <span className="text-sm text-gray-500 mb-1">hrs total (verified)</span>
                        </div>

                        <div className="grid grid-cols-2 gap-3 mt-4">
                            <div className="p-3 bg-blue-50 rounded-lg border border-blue-100">
                                <div className="text-xs text-blue-500 uppercase font-bold mb-1">Lecture</div>
                                <div className="text-lg font-bold text-blue-900">{lectureHours.toFixed(1)} h</div>
                            </div>
                            <div className="p-3 bg-green-50 rounded-lg border border-green-100">
                                <div className="text-xs text-green-500 uppercase font-bold mb-1">Practice</div>
                                <div className="text-lg font-bold text-green-900">{practiceHours.toFixed(1)} h</div>
                            </div>
                        </div>
                    </div>

                    {/* Class Competency Radar */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                         <h3 className="font-bold text-gray-800 mb-2 flex items-center gap-2">
                             <PieChart size={18} className="text-orange-500" /> Class Insights
                         </h3>
                         <p className="text-xs text-gray-500 mb-4">Average competency of students you taught.</p>

                         <div className="h-48 w-full flex justify-center items-center">
                            {radarData.length > 0 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <RadarChart cx="50%" cy="50%" outerRadius="70%" data={radarData}>
                                        <PolarGrid />
                                        <PolarAngleAxis dataKey="subject" tick={{ fontSize: 10 }} />
                                        <PolarRadiusAxis angle={30} domain={[0, 5]} tick={false} />
                                        <Radar name="Class Avg" dataKey="A" stroke="#f97316" fill="#f97316" fillOpacity={0.5} />
                                        <Tooltip />
                                    </RadarChart>
                                </ResponsiveContainer>
                            ) : (
                                <p className="text-xs text-gray-400 text-center">No assessment data yet.</p>
                            )}
                         </div>
                    </div>

                    {/* Material Repository (Quick Links) */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                        <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                            <BookOpen size={18} className="text-gray-600" /> Recent Materials
                        </h3>
                        <ul className="space-y-3">
                            {recentArtifacts.length === 0 && <li className="text-xs text-gray-400">No uploads yet.</li>}
                            {recentArtifacts.map(l => (
