export const MentorDashboard: React.FC = () => {
    const { currentUser, lessonPlans, logs, modules, users, groups } = useData();
    const [view, setView] = useState<'dashboard' | 'students' | 'log_entry'>('dashboard');
    const [selectedPlan, setSelectedPlan] = useState<LessonPlan | null>(null);
    const [selectedLogToEdit, setSelectedLogToEdit] = useState<MentoringLog | null>(null);
    const [selectedStudent, setSelectedStudent] = useState<User | null>(null);

    // --- Data Preparation (Dashboard View) ---
    // 1. Today's Classes
    const today = new Date().toISOString().split('T')[0];
    const todaysClasses = lessonPlans.filter(p => p.mentorId === currentUser.id && p.date === today);

    // 2. Pending Actions (Rejected Logs)
    const rejectedLogs = logs.filter(l => l.mentorId === currentUser.id && l.status === LogStatus.REJECTED);

    // 3. Stats (Hours)
    const myLogs = logs.filter(l => l.mentorId === currentUser.id && l.status === LogStatus.APPROVED);
    const totalMinutes = myLogs.reduce((acc, l) => acc + l.durationMinutes, 0);
    const totalHours = totalMinutes / 60;
    const lectureHours = totalHours * 0.4; // Mock split
    const practiceHours = totalHours * 0.6; // Mock split

    // 4. Module Progress
    const myModules = modules.filter(m => 
        lessonPlans.some(p => p.mentorId === currentUser.id && p.moduleId === m.id) ||
        logs.some(l => l.mentorId === currentUser.id && l.moduleId === m.id)
    );

    const getModuleProgress = (moduleId: string) => {
        const planned = lessonPlans.filter(p => p.moduleId === moduleId && p.mentorId === currentUser.id).length;
        const logged = logs.filter(l => l.moduleId === moduleId && l.mentorId === currentUser.id).length;
        const total = Math.max(planned, 1);
        const percent = Math.min(100, Math.round((logged / total) * 100));
        return { logged, planned, percent };
    };

    // 5. Student Insights (Aggregated Radar for Dashboard)
    const myGivenScores = logs.filter(l => l.mentorId === currentUser.id).flatMap(l => l.scores);
    const metricTotals: Record<string, { sum: number, count: number }> = {};
    myGivenScores.forEach(score => {
        Object.entries(score.metrics).forEach(([key, value]) => {
            if (!metricTotals[key]) metricTotals[key] = { sum: 0, count: 0 };
            metricTotals[key].sum += (value as number);
            metricTotals[key].count += 1;
        });
    });
    const radarData = Object.keys(metricTotals).map(key => ({
        subject: key,
        A: metricTotals[key].count > 0 ? (metricTotals[key].sum / metricTotals[key].count) : 0,
        fullMark: 5
    }));

    // 6. Recent Artifacts
    const recentArtifacts = logs
        .filter(l => l.mentorId === currentUser.id && l.artifactUrl)
        .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime())
        .slice(0, 3);

    // --- Handlers ---

    const handleStartLog = (plan?: LessonPlan) => {
        setSelectedPlan(plan || null);
        setSelectedLogToEdit(null);
        setView('log_entry');
