import React, { useState, useMemo } from 'react';
import { useData } from '../services/DataContext';
import { LogStatus, MentoringLog, ActivityType, LessonPlan, User, Role, Group, AttendanceStatus, Module } from '../types';
import { 
  Bell, BookOpen, Calendar, CheckCircle, Clock, FileText, 
  LayoutDashboard, PieChart, Search, TrendingUp, 
  Upload, XCircle, ChevronRight, PlayCircle, Users, Filter,
  GraduationCap, MessageSquare
} from 'lucide-react';
import { 
  RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, ResponsiveContainer, Tooltip,
  LineChart, Line, XAxis, YAxis, CartesianGrid
} from 'recharts';
import { MentorLogForm } from './MentorLogForm';

// --- Sub-Components ---

const StudentProfileModal: React.FC<{ 
    student: User; 
    logs: MentoringLog[];
    modules: Module[];
    onClose: () => void 
}> = ({ student, logs, modules, onClose }) => {
    // 1. Filter logs for this student
    const studentLogs = useMemo(() => 
        logs
            .filter(l => l.status === LogStatus.APPROVED && l.scores.some(s => s.studentId === student.id))
            .sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime()),
    [logs, student.id]);

    // 2. Calculate Radar Data (Overall Average)
    const radarData = useMemo(() => {
        const metricTotals: Record<string, { sum: number, count: number }> = {};
        studentLogs.forEach(log => {
            const score = log.scores.find(s => s.studentId === student.id);
            if (score && score.attendance !== AttendanceStatus.ABSENT) {
                Object.entries(score.metrics).forEach(([key, value]) => {
                    if (!metricTotals[key]) metricTotals[key] = { sum: 0, count: 0 };
                    metricTotals[key].sum += (value as number);
                    metricTotals[key].count += 1;
                });
            }
        });
        return Object.keys(metricTotals).map(key => ({
            subject: key,
            A: metricTotals[key].count > 0 ? (metricTotals[key].sum / metricTotals[key].count) : 0,
            fullMark: 5
        }));
    }, [studentLogs, student.id]);

    // 3. Calculate Line Data (Progress over time)
    const progressData = useMemo(() => {
        return studentLogs.reduce((acc, log) => {
            const score = log.scores.find(s => s.studentId === student.id);
            if (!score || score.attendance === AttendanceStatus.ABSENT) return acc;

            const values = Object.values(score.metrics) as number[];
            const avg = values.length ? values.reduce((a,b) => a+b,0)/values.length : 0;
            const moduleName = modules.find(m => m.id === log.moduleId)?.name || log.moduleId;

            acc.push({
                date: log.date,
                score: parseFloat(avg.toFixed(2)),
                module: moduleName
            });
            return acc;
        }, [] as { date: string; score: number; module: string }[]);
    }, [studentLogs, student.id, modules]);

    // Custom Tooltip for Line Chart
    const CustomLineTooltip = ({ active, payload, label }: any) => {
        if (active && payload && payload.length) {
            return (
                <div className="bg-white p-3 border border-gray-100 shadow-xl rounded-lg text-xs">
                    <p className="font-bold text-gray-800 mb-1">{new Date(label).toLocaleDateString()}</p>
                    <p className="text-indigo-600 font-semibold mb-1">{payload[0].payload.module}</p>
                    <p className="text-gray-600">Avg Score: <span className="font-bold">{payload[0].value}</span></p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
            <div className="bg-white rounded-2xl shadow-2xl max-w-4xl w-full h-[90vh] overflow-y-auto flex flex-col">
                {/* Header */}
                <div className="p-6 border-b border-gray-100 flex justify-between items-start sticky top-0 bg-white z-10">
                    <div className="flex items-center gap-4">
                        <img src={student.avatarUrl} alt={student.fullName} className="w-16 h-16 rounded-full border-2 border-indigo-100" />
                        <div>
                            <h2 className="text-2xl font-bold text-gray-900">{student.fullName}</h2>
                            <p className="text-gray-500 text-sm flex items-center gap-2">
                                <GraduationCap size={16} /> Student Profile
                                <span className="text-gray-300">|</span>
                                <span className="text-indigo-600">{studentLogs.length} Sessions Recorded</span>
                            </p>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full text-gray-400 hover:text-gray-600 transition-colors">
                        <XCircle size={28} />
                    </button>
                </div>

                <div className="p-6 grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {/* Analytics Section */}
                    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4">
                        <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                            <PieChart size={18} className="text-indigo-500" /> Competency Map
                        </h3>
                        <div className="h-64">
                            {radarData.length > 0 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <RadarChart cx="50%" cy="50%" outerRadius="70%" data={radarData}>
                                        <PolarGrid />
                                        <PolarAngleAxis dataKey="subject" tick={{fontSize: 12}} />
                                        <PolarRadiusAxis angle={30} domain={[0, 5]} />
                                        <Radar name={student.fullName} dataKey="A" stroke="#4f46e5" fill="#4f46e5" fillOpacity={0.6} />
                                        <Tooltip />
                                    </RadarChart>
                                </ResponsiveContainer>
                            ) : (
                                <div className="h-full flex items-center justify-center text-gray-400">No data available</div>
                            )}
                        </div>
                    </div>

                    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4">
                        <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                            <TrendingUp size={18} className="text-green-500" /> Growth Trajectory
                        </h3>
                        <div className="h-64">
                            {progressData.length > 0 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <LineChart data={progressData}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                                        <XAxis 
                                            dataKey="date" 
                                            tick={{fontSize: 10}} 
                                            tickMargin={10} 
                                            tickFormatter={(val) => new Date(val).toLocaleDateString('en-US', {month: 'short', day: 'numeric'})}
                                        />
                                        <YAxis domain={[0, 5]} hide />
                                        <Tooltip content={<CustomLineTooltip />} />
                                        <Line type="monotone" dataKey="score" stroke="#10b981" strokeWidth={3} dot={{r: 4}} activeDot={{r: 6}} />
                                    </LineChart>
                                </ResponsiveContainer>
                            ) : (
                                <div className="h-full flex items-center justify-center text-gray-400">No data available</div>
                            )}
                        </div>
                    </div>

                    {/* Feedback History */}
                    <div className="lg:col-span-2">
                        <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                            <MessageSquare size={18} className="text-orange-500" /> Mentor Feedback History
                        </h3>
                        <div className="space-y-3 max-h-60 overflow-y-auto pr-2 custom-scrollbar">
                            {studentLogs.length === 0 && <p className="text-gray-400 italic">No recorded sessions yet.</p>}
                            {studentLogs.map(log => {
                                const score = log.scores.find(s => s.studentId === student.id);
                                const isAbsent = score?.attendance === AttendanceStatus.ABSENT;
                                const moduleName = modules.find(m => m.id === log.moduleId)?.name;

                                return (
                                    <div key={log.id} className="bg-gray-50 rounded-lg p-4 border border-gray-100 hover:border-indigo-200 transition-colors">
                                        <div className="flex justify-between items-start mb-2">
                                            <div className="flex items-center gap-2">
                                                <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">{log.date}</span>
                                                <span className="text-xs text-gray-500 bg-white px-2 py-0.5 rounded border border-gray-200">{moduleName}</span>
                                                {isAbsent && <span className="ml-2 text-xs font-bold text-red-600 bg-red-50 px-2 py-0.5 rounded border border-red-100">ABSENT</span>}
                                            </div>
                                            {!isAbsent && (
                                                <div className="flex gap-2 text-xs text-gray-500">
                                                    {Object.entries(score?.metrics || {}).map(([k,v]) => (
                                                        <span key={k} title={k}>{k.substring(0,3)}: <b>{v}</b></span>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                        <p className="text-sm text-gray-700 font-medium italic">"{log.summaryNote}"</p>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const StudentDirectory: React.FC<{
    users: User[];
    groups: Group[];
    currentUserId: string;
    onSelectStudent: (s: User) => void;
}> = ({ users, groups, currentUserId, onSelectStudent }) => {
    const [filterMode, setFilterMode] = useState<'ALL' | 'MY_GROUPS'>('ALL');
    const [selectedGroupId, setSelectedGroupId] = useState<string>('');
    const [searchQuery, setSearchQuery] = useState('');

    const allStudents = users.filter(u => u.role === Role.STUDENT);

    // Filter logic
    const myGroups = groups.filter(g => g.mentorIds.includes(currentUserId));

    const displayedStudents = useMemo(() => {
        let list = allStudents;

        if (filterMode === 'MY_GROUPS') {
            if (selectedGroupId) {
                const grp = groups.find(g => g.id === selectedGroupId);
                list = list.filter(s => grp?.studentIds.includes(s.id));
            } else {
                // Show all students in ANY of my groups
                const allMyStudentIds = myGroups.flatMap(g => g.studentIds);
                list = list.filter(s => allMyStudentIds.includes(s.id));
            }
        }

        if (searchQuery) {
            const lower = searchQuery.toLowerCase();
            list = list.filter(s => s.fullName.toLowerCase().includes(lower) || s.email.toLowerCase().includes(lower));
        }

        return list;
    }, [allStudents, filterMode, selectedGroupId, searchQuery, myGroups, groups]);

    return (
        <div className="space-y-6 animate-fade-in">
            {/* Controls */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col md:flex-row gap-4 justify-between items-center">
                <div className="flex bg-gray-100 p-1 rounded-lg">
                    <button 
                        onClick={() => { setFilterMode('ALL'); setSelectedGroupId(''); }}
                        className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${filterMode === 'ALL' ? 'bg-white shadow text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
                    >
                        <Users size={16} /> All Students
                    </button>
                    <button 
                        onClick={() => { setFilterMode('MY_GROUPS'); if(myGroups.length > 0) setSelectedGroupId(myGroups[0].id); }}
                        className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${filterMode === 'MY_GROUPS' ? 'bg-white shadow text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
                    >
                        <Filter size={16} /> My Groups
                    </button>
                </div>

                <div className="flex-1 w-full md:w-auto flex gap-3">
                    {filterMode === 'MY_GROUPS' && (
                        <select 
                            value={selectedGroupId}
                            onChange={(e) => setSelectedGroupId(e.target.value)}
                            className="rounded-lg border-gray-300 text-sm p-2 border focus:ring-2 focus:ring-indigo-500"
                        >
                            {myGroups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                            {myGroups.length === 0 && <option value="">No Assigned Groups</option>}
                        </select>
                    )}
                    <div className="relative flex-1">
                        <Search className="absolute left-3 top-2.5 text-gray-400 w-4 h-4" />
                        <input 
                            type="text" 
                            placeholder="Search students..." 
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full pl-9 rounded-lg border-gray-300 text-sm p-2 border focus:ring-2 focus:ring-indigo-500"
                        />
                    </div>
                </div>
            </div>

            {/* Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                {displayedStudents.map(student => (
                    <div 
                        key={student.id} 
                        onClick={() => onSelectStudent(student)}
                        className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm hover:shadow-md hover:border-indigo-300 transition-all cursor-pointer group"
                    >
                        <div className="flex items-center gap-4">
                            <img src={student.avatarUrl} alt={student.fullName} className="w-12 h-12 rounded-full bg-gray-100" />
                            <div className="flex-1 overflow-hidden">
                                <h4 className="font-bold text-gray-900 truncate group-hover:text-indigo-600 transition-colors">{student.fullName}</h4>
                                <p className="text-xs text-gray-500 truncate">{student.email}</p>
                            </div>
                            <ChevronRight className="text-gray-300 group-hover:text-indigo-500" size={20} />
                        </div>

                        <div className="mt-4 pt-3 border-t border-gray-50 flex justify-between text-xs text-gray-500">
                             <span className="flex items-center gap-1"><BookOpen size={12}/> View Profile</span>
                             {filterMode === 'MY_GROUPS' && <span className="text-indigo-600 font-medium">Assigned</span>}
                        </div>
                    </div>
                ))}
                {displayedStudents.length === 0 && (
                    <div className="col-span-full py-12 text-center text-gray-400">
                        <Users size={48} className="mx-auto mb-4 opacity-20" />
                        <p>No students found matching criteria.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

