export const MentorDashboard: React.FC = () => {
    const { currentUser, lessonPlans, logs, modules, users, groups } = useData();
    const [view, setView] = useState<'dashboard' | 'students' | 'log_entry'>('dashboard');
    const [selectedPlan, setSelectedPlan] = useState<LessonPlan | null>(null);
    const [selectedLogToEdit, setSelectedLogToEdit] = useState<MentoringLog | null>(null);
    const [selectedStudent, setSelectedStudent] = useState<User | null>(null);

    // --- Data Preparation (Dashboard View) ---
    // 1. Today's Classes
    const today = new Date().toISOString().split('T')[0];
    const todaysClasses = lessonPlans.filter(p => p.mentorId === currentUser.id && p.date === today);

    // 2. Pending Actions (Rejected Logs)
    const rejectedLogs = logs.filter(l => l.mentorId === currentUser.id && l.status === LogStatus.REJECTED);

    // 3. Stats (Hours)
    const myLogs = logs.filter(l => l.mentorId === currentUser.id && l.status === LogStatus.APPROVED);
    const totalMinutes = myLogs.reduce((acc, l) => acc + l.durationMinutes, 0);
    const totalHours = totalMinutes / 60;
    const lectureHours = totalHours * 0.4; // Mock split
    const practiceHours = totalHours * 0.6; // Mock split

    // 4. Module Progress
    const myModules = modules.filter(m => 
        lessonPlans.some(p => p.mentorId === currentUser.id && p.moduleId === m.id) ||
        logs.some(l => l.mentorId === currentUser.id && l.moduleId === m.id)
    );

    const getModuleProgress = (moduleId: string) => {
        const planned = lessonPlans.filter(p => p.moduleId === moduleId && p.mentorId === currentUser.id).length;
        const logged = logs.filter(l => l.moduleId === moduleId && l.mentorId === currentUser.id).length;
        const total = Math.max(planned, 1);
        const percent = Math.min(100, Math.round((logged / total) * 100));
        return { logged, planned, percent };
    };

    // 5. Student Insights (Aggregated Radar for Dashboard)
    const myGivenScores = logs.filter(l => l.mentorId === currentUser.id).flatMap(l => l.scores);
    const metricTotals: Record<string, { sum: number, count: number }> = {};
    myGivenScores.forEach(score => {
        Object.entries(score.metrics).forEach(([key, value]) => {
            if (!metricTotals[key]) metricTotals[key] = { sum: 0, count: 0 };
            metricTotals[key].sum += (value as number);
            metricTotals[key].count += 1;
        });
    });
    const radarData = Object.keys(metricTotals).map(key => ({
        subject: key,
        A: metricTotals[key].count > 0 ? (metricTotals[key].sum / metricTotals[key].count) : 0,
        fullMark: 5
    }));

    // 6. Recent Artifacts
    const recentArtifacts = logs
        .filter(l => l.mentorId === currentUser.id && l.artifactUrl)
        .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime())
        .slice(0, 3);

    // --- Handlers ---

    const handleStartLog = (plan?: LessonPlan) => {
        setSelectedPlan(plan || null);
        setSelectedLogToEdit(null);
        setView('log_entry');
    };

    const handleEditLog = (log: MentoringLog) => {
        setSelectedLogToEdit(log);
        setSelectedPlan(null);
        setView('log_entry');
    };

    const handleLogSuccess = () => {
        setView('dashboard');
        setSelectedPlan(null);
        setSelectedLogToEdit(null);
    };

    if (view === 'log_entry') {
        const initialData = selectedLogToEdit || (selectedPlan ? {
            moduleId: selectedPlan.moduleId,
            date: selectedPlan.date,
            startTime: selectedPlan.startTime,
            endTime: selectedPlan.endTime,
            summaryNote: selectedPlan.topic,
        } : undefined);

        return (
            <MentorLogForm 
                initialData={initialData} 
                onSuccess={handleLogSuccess}
                onCancel={() => setView('dashboard')}
            />
        );
    }

    return (
        <div className="space-y-6">
            {/* Top Navigation Bar */}
            <div className="bg-white p-2 rounded-xl border border-gray-200 shadow-sm flex items-center justify-between sticky top-0 z-20">
                <div className="flex gap-2">
                    <button 
                        onClick={() => setView('dashboard')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${view === 'dashboard' ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:bg-gray-100'}`}
                    >
                        <LayoutDashboard size={18} /> Overview
                    </button>
                    <button 
                        onClick={() => setView('students')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${view === 'students' ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:bg-gray-100'}`}
                    >
                        <Users size={18} /> My Students
                    </button>
                </div>
                <div className="flex items-center gap-3 px-4">
                     <div className="hidden md:flex flex-col items-end">
                        <span className="text-sm font-bold text-gray-800">{currentUser.fullName}</span>
                        <span className="text-xs text-gray-500 uppercase">{currentUser.role}</span>
                     </div>
                     <img src={currentUser.avatarUrl} className="w-8 h-8 rounded-full border border-gray-300" />
                </div>
            </div>

            {/* Dashboard View */}
            {view === 'dashboard' && (
                <div className="animate-fade-in grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Column 1: Immediate Actions */}
                    <div className="lg:col-span-2 space-y-6">
                        {/* Today's Classes Card */}
                        <div className="bg-gradient-to-r from-indigo-600 to-indigo-800 rounded-2xl p-6 text-white shadow-lg relative overflow-hidden">
                            <div className="relative z-10">
                                <h2 className="text-lg font-bold flex items-center gap-2 mb-4">
                                    <Calendar className="w-5 h-5" /> Today's Classes
                                </h2>

                                {todaysClasses.length === 0 ? (
                                    <div className="text-indigo-100 bg-white/10 backdrop-blur-md p-4 rounded-xl flex items-center justify-between border border-white/20">
                                        <span>No classes scheduled for today.</span>
                                        <button 
                                            onClick={() => handleStartLog()}
                                            className="bg-white text-indigo-600 px-4 py-2 rounded-lg text-sm font-bold shadow-sm hover:bg-indigo-50"
                                        >
                                            Record Unscheduled Log
                                        </button>
                                    </div>
                                ) : (
                                    <div className="space-y-3">
                                        {todaysClasses.map(plan => {
                                            const moduleName = modules.find(m => m.id === plan.moduleId)?.name;
                                            const isDone = logs.some(l => l.mentorId === currentUser.id && l.date === plan.date && l.startTime === plan.startTime);
                                            return (
                                                <div key={plan.id} className="bg-white/10 backdrop-blur-sm p-4 rounded-xl border border-indigo-400/30 flex justify-between items-center">
                                                    <div>
                                                        <div className="flex items-center gap-2 text-indigo-100 text-xs font-medium uppercase mb-1">
                                                            <Clock size={12} /> {plan.startTime} - {plan.endTime}
                                                            <span className={`px-1.5 py-0.5 rounded border ${plan.activityType === ActivityType.LECTURE ? 'bg-blue-500/20 border-blue-300/50' : 'bg-green-500/20 border-green-300/50'}`}>
                                                                {plan.activityType}
                                                            </span>
                                                        </div>
                                                        <h3 className="font-bold text-lg">{moduleName}</h3>
                                                        <p className="text-indigo-200 text-sm">{plan.topic}</p>
                                                    </div>
                                                    {isDone ? (
                                                        <button disabled className="bg-green-500 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 cursor-default">
                                                            <CheckCircle size={16} /> Logged
                                                        </button>
                                                    ) : (
                                                        <button 
                                                            onClick={() => handleStartLog(plan)}
                                                            className="bg-white text-indigo-600 px-4 py-2 rounded-lg text-sm font-bold shadow-sm hover:bg-indigo-50 flex items-center gap-2 transition-all hover:scale-105"
                                                        >
                                                            <PlayCircle size={16} /> Start Class
                                                        </button>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>
                                )}
                            </div>
                            <div className="absolute -right-10 -bottom-10 w-64 h-64 bg-white rounded-full opacity-10 blur-3xl"></div>
                        </div>

                        {/* Rejected Logs */}
                        {rejectedLogs.length > 0 && (
                            <div className="bg-white border border-red-200 rounded-xl p-5 shadow-sm">
                                <h3 className="text-red-700 font-bold flex items-center gap-2 mb-3">
                                    <XCircle size={20} /> Action Required
                                </h3>
                                <div className="space-y-3">
                                    {rejectedLogs.map(log => (
                                        <div key={log.id} className="flex items-center justify-between p-3 bg-red-50 rounded-lg border border-red-100">
                                            <div>
                                                <p className="text-sm font-bold text-gray-800">{log.summaryNote}</p>
                                                <p className="text-xs text-red-600 mt-1">Reason: {log.history[log.history.length-1]?.note}</p>
                                            </div>
                                            <button 
                                                onClick={() => handleEditLog(log)}
                                                className="text-xs bg-white border border-red-200 text-red-600 px-3 py-1.5 rounded-md font-bold hover:bg-red-50"
                                            >
                                                Fix
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Progress Tracking */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                            <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                                <TrendingUp size={20} className="text-indigo-600" /> Module Progress
                            </h3>
                            <div className="space-y-5">
                                {myModules.length === 0 && <p className="text-gray-400 text-sm">No modules assigned.</p>}
                                {myModules.map(m => {
                                    const { logged, planned, percent } = getModuleProgress(m.id);
                                    return (
                                        <div key={m.id}>
                                            <div className="flex justify-between text-sm mb-1">
                                                <span className="font-medium text-gray-700">{m.name}</span>
                                                <span className="text-gray-500">{logged}/{planned} Sessions</span>
                                            </div>
                                            <div className="w-full bg-gray-100 rounded-full h-2.5">
                                                <div className="bg-indigo-600 h-2.5 rounded-full transition-all duration-500" style={{ width: `${percent}%` }}></div>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    </div>

                    {/* Column 2: Stats & Insights */}
                    <div className="space-y-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                            <h3 className="font-bold text-gray-800 mb-4">Cumulative Hours</h3>
                            <div className="flex items-end gap-2 mb-2">
                                <span className="text-4xl font-bold text-indigo-900">{totalHours.toFixed(1)}</span>
                                <span className="text-sm text-gray-500 mb-1">hrs total (verified)</span>
                            </div>
                            <div className="grid grid-cols-2 gap-3 mt-4">
                                <div className="p-3 bg-blue-50 rounded-lg border border-blue-100 text-center">
                                    <div className="text-xs text-blue-500 uppercase font-bold mb-1">Lecture</div>
                                    <div className="text-lg font-bold text-blue-900">{lectureHours.toFixed(1)} h</div>
                                </div>
                                <div className="p-3 bg-green-50 rounded-lg border border-green-100 text-center">
                                    <div className="text-xs text-green-500 uppercase font-bold mb-1">Practice</div>
                                    <div className="text-lg font-bold text-green-900">{practiceHours.toFixed(1)} h</div>
                                </div>
                            </div>
                        </div>

                        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                             <h3 className="font-bold text-gray-800 mb-2 flex items-center gap-2">
                                 <PieChart size={18} className="text-orange-500" /> Class Insights
                             </h3>
                             <p className="text-xs text-gray-500 mb-4">Average competency of students you taught.</p>
                             <div className="h-48 w-full flex justify-center items-center">
                                {radarData.length > 0 ? (
                                    <ResponsiveContainer width="100%" height="100%">
                                        <RadarChart cx="50%" cy="50%" outerRadius="70%" data={radarData}>
                                            <PolarGrid />
                                            <PolarAngleAxis dataKey="subject" tick={{ fontSize: 10 }} />
                                            <PolarRadiusAxis angle={30} domain={[0, 5]} tick={false} />
                                            <Radar name="Class Avg" dataKey="A" stroke="#f97316" fill="#f97316" fillOpacity={0.5} />
                                            <Tooltip />
                                        </RadarChart>
                                    </ResponsiveContainer>
                                ) : (
                                    <p className="text-xs text-gray-400">No assessment data yet.</p>
                                )}
                             </div>
                        </div>

                        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                            <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                                <BookOpen size={18} className="text-gray-600" /> Recent Materials
                            </h3>
                            <ul className="space-y-3">
                                {recentArtifacts.length === 0 && <li className="text-xs text-gray-400">No uploads yet.</li>}
                                {recentArtifacts.map(l => (
                                    <li key={l.id} className="flex items-center gap-3 group cursor-pointer">
                                        <div className="bg-gray-100 p-2 rounded text-gray-500 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition-colors">
                                            <FileText size={14} />
                                        </div>
                                        <div className="overflow-hidden">
                                            <a href={l.artifactUrl} target="_blank" rel="noreferrer" className="text-sm font-medium text-gray-700 truncate block hover:text-indigo-600 hover:underline">
                                                {l.summaryNote || "Untitled Log"}
                                            </a>
                                            <p className="text-[10px] text-gray-400">{l.date}</p>
                                        </div>
                                    </li>
                                ))}
                            </ul>
                            <button className="w-full mt-4 py-2 border border-dashed border-gray-300 rounded-lg text-xs font-medium text-gray-500 hover:bg-gray-50 flex items-center justify-center gap-2">
                                <Upload size={12} /> Upload New Material
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Students View */}
            {view === 'students' && (
                <StudentDirectory 
                    users={users} 
                    groups={groups} 
                    currentUserId={currentUser.id} 
                    onSelectStudent={setSelectedStudent} 
                />
            )}

            {/* Student Profile Modal */}
            {selectedStudent && (
                <StudentProfileModal 
                    student={selectedStudent} 
                    logs={logs}
                    modules={modules}
                    onClose={() => setSelectedStudent(null)} 
                />
            )}
        </div>
    );
};

export enum Role {
  ADMIN = 'ADMIN',
  MENTOR = 'MENTOR',
  STUDENT = 'STUDENT'
}

export enum MentorType {
  INTERNAL = 'INTERNAL', // University Staff (600 THB rate logic hidden)
  EXTERNAL = 'EXTERNAL', // Industry Expert (1200 THB rate logic hidden)
  NONE = 'NONE'
}

export enum LogStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED'
}

export enum PlanStatus {
  DRAFT = 'DRAFT',
  PUBLISHED = 'PUBLISHED'
}

export enum AttendanceStatus {
  PRESENT = 'PRESENT',
  LATE = 'LATE',
  ABSENT = 'ABSENT'
}

export enum ActivityType {
  LECTURE = 'LECTURE',
  PRACTICE = 'PRACTICE'
}

export interface User {
  id: string;
  role: Role;
  fullName: string;
  email: string;
  avatarUrl?: string;
  // Specific to mentors
  mentorType?: MentorType; 
  // Specific to students
  batchId?: string;
}

export interface Batch {
  id: string;
  name: string; // e.g. "Gen 8"
  startDate: string; // ISO Date YYYY-MM-DD
  endDate: string; // ISO Date YYYY-MM-DD
  status: 'ACTIVE' | 'CLOSED';
}

export interface AssessmentCategory {
  id: string;
  name: string; // e.g. "Critical Thinking"
  description: string; // Description of what a score of 5 looks like
  weight: number; // Percentage 0-100
  isEnabled: boolean;
}

export interface Module {
  id: string;
  batchId: string;
  name: string; // e.g. "Data Science"
  assessmentConfig?: AssessmentCategory[]; // Custom rubrics for this module
}

export interface Group {
  id: string;
  moduleId: string;
  name: string; // e.g. "Group A"
  mentorIds: string[]; 
  studentIds: string[];
}

export interface LessonPlan {
  id: string;
  moduleId: string;
  date: string; // YYYY-MM-DD
  startTime: string; // HH:mm
  endTime: string; // HH:mm
  durationMinutes: number;
  activityType: ActivityType;
  topic: string;
  mentorId: string;
  status: PlanStatus;
}

export interface CompetencyScore {
  studentId: string;
  attendance: AttendanceStatus;
  // Dynamic Key-Value for scores. Key = AssessmentCategory.name
  metrics: Record<string, number>; 
}

export interface LogHistory {
  timestamp: string; // ISO Date
  actorId: string; // User ID who performed the action
  action: string; // e.g. "Created", "Approved", "Rejected"
  note?: string; // Optional reason
}

export interface Intervention {
  id: string;
  studentId: string;
  adminId: string;
  date: string; // ISO Date
  type: 'CALL' | 'EMAIL' | 'MEETING' | 'IDP_SENT' | 'OTHER';
  note: string;
}

export interface MentoringLog {
  id: string;
  mentorId: string; // The mentor who taught the session
  recordedBy: string; // The user who entered the log (Could be Admin)
  batchId: string;
  moduleId: string; // Link to specific module
  date: string;
  startTime: string; // HH:mm
  endTime: string; // HH:mm
  durationMinutes: number;
  isValidSession: boolean; // True if >= 50 mins
  status: LogStatus;
  summaryNote: string;
  artifactUrl: string;
  scores: CompetencyScore[]; // One entry per student in the session
  history: LogHistory[]; // Audit trail
  isStarred?: boolean; // For "Best Artifacts" showcase
  digitalSignature?: boolean; // Checkbox for integrity
}

export interface SessionValidation {
  isValid: boolean;
  message: string;
  duration: number;
}

import React, { useState, useEffect } from 'react';
import { useData } from '../services/DataContext';
import { AttendanceStatus, CompetencyScore, LogStatus, MentoringLog, Role, LessonPlan } from '../types';
import { Clock, Users, Save, Link as LinkIcon, Upload, AlertTriangle, CheckCircle, Shield, CalendarCheck, HelpCircle, ArrowLeft, Mic, Star } from 'lucide-react';

interface MentorLogFormProps {
  initialData?: Partial<MentoringLog> & { lessonPlanId?: string };
  onSuccess?: () => void;
  onCancel?: () => void;
}

export const MentorLogForm: React.FC<MentorLogFormProps> = ({ initialData, onSuccess, onCancel }) => {
  const { batches, getModulesByBatch, currentUser, getStudentsByBatch, addLog, users, lessonPlans } = useData();

  // Local State
  const [selectedBatchId, setSelectedBatchId] = useState(batches[0]?.id || '');
  const [selectedModuleId, setSelectedModuleId] = useState('');

  // Admin Proxy State
  const isAdmin = currentUser.role === Role.ADMIN;
  const mentors = users.filter(u => u.role === Role.MENTOR);
  const [selectedMentorId, setSelectedMentorId] = useState('');

  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [summary, setSummary] = useState('');
  const [artifactUrl, setArtifactUrl] = useState('');
  const [scores, setScores] = useState<CompetencyScore[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  // New Features State
  const [isListening, setIsListening] = useState(false);
  const [isStarred, setIsStarred] = useState(false);
  const [digitalSignature, setDigitalSignature] = useState(false);

  const students = getStudentsByBatch(selectedBatchId);
  const modules = getModulesByBatch(selectedBatchId);
  const selectedModule = modules.find(m => m.id === selectedModuleId);

  // Backdate limitation logic: Mentors max 3 days, Admin unlimited
  const minDate = isAdmin ? undefined : new Date(Date.now() - 3 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

  // Load Initial Data (From Dashboard)
  useEffect(() => {
    if (initialData) {
      if (initialData.batchId) setSelectedBatchId(initialData.batchId);
      if (initialData.moduleId) setSelectedModuleId(initialData.moduleId);
      if (initialData.date) setDate(initialData.date);
      if (initialData.startTime) setStartTime(initialData.startTime);
      if (initialData.endTime) setEndTime(initialData.endTime);
      if (initialData.summaryNote) setSummary(initialData.summaryNote);
      if (initialData.artifactUrl) setArtifactUrl(initialData.artifactUrl);
      if (initialData.scores) setScores(initialData.scores);
      if (initialData.isStarred) setIsStarred(initialData.isStarred);
      if (initialData.mentorId && isAdmin) setSelectedMentorId(initialData.mentorId);
    }
  }, [initialData, isAdmin]);

  // Auto-select first module if available when batch changes
  useEffect(() => {
    if (!initialData?.moduleId && modules.length > 0) {
      setSelectedModuleId(modules[0].id);
    }
  }, [selectedBatchId, modules, initialData]);

  // Set default mentor ID if Admin
  useEffect(() => {
      if (isAdmin && mentors.length > 0 && !selectedMentorId) {
          setSelectedMentorId(mentors[0].id);
      }
  }, [isAdmin, mentors]);

  // Initialize scores
  useEffect(() => {
    if (students.length > 0 && scores.length === 0) {
      const activeCategories = selectedModule?.assessmentConfig?.filter(c => c.isEnabled) || [];

      const initialScores: CompetencyScore[] = students.map(s => {
          const metrics: Record<string, number> = {};
          if (activeCategories.length > 0) {
              activeCategories.forEach(cat => metrics[cat.name] = 3);
          } else {
              // Fallback default
              metrics['Business Acumen'] = 3;
              metrics['Creativity'] = 3;
              metrics['Discipline'] = 3;
          }

          return {
            studentId: s.id,
            attendance: AttendanceStatus.PRESENT,
            metrics: metrics
          };
      });
      setScores(initialScores);
    }
  }, [selectedBatchId, students.length, selectedModuleId, selectedModule, scores.length]); 

  // Check for Lesson Plans
  const availablePlan = lessonPlans.find(p => p.moduleId === selectedModuleId && p.date === date);

  const applyLessonPlan = () => {
      if (availablePlan) {
          setStartTime(availablePlan.startTime);
          setEndTime(availablePlan.endTime);
          setSummary(availablePlan.topic);
          if (availablePlan.mentorId && isAdmin) {
              setSelectedMentorId(availablePlan.mentorId);
          }
      }
  };

  const calculateDuration = () => {
    if (!startTime || !endTime) return 0;
    const start = new Date(`2000-01-01T${startTime}`);
    const end = new Date(`2000-01-01T${endTime}`);
    const diffMs = end.getTime() - start.getTime();
    return Math.max(0, Math.floor(diffMs / 60000));
  };

  const duration = calculateDuration();
  const isValidSession = duration >= 50;

  const handleScoreChange = (studentId: string, categoryName: string, value: number) => {
    setScores(prev => prev.map(s => {
        if (s.studentId !== studentId) return s;
        return {
            ...s,
            metrics: {
                ...s.metrics,
                [categoryName]: value
            }
        };
    }));
  };

  const handleAttendanceChange = (studentId: string, status: AttendanceStatus) => {
      setScores(prev => prev.map(s => s.studentId === studentId ? { ...s, attendance: status } : s));
  };

  // Voice to Text Simulation/Implementation
  const toggleVoiceInput = () => {
      if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
          // @ts-ignore
          const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
          const recognition = new SpeechRecognition();
          recognition.lang = 'en-US';
          recognition.interimResults = false;

          recognition.onstart = () => setIsListening(true);
          recognition.onend = () => setIsListening(false);
          recognition.onresult = (event: any) => {
              const transcript = event.results[0][0].transcript;
              setSummary(prev => prev + (prev ? ' ' : '') + transcript);
          };
          recognition.start();
      } else {
          // Fallback simulation for demo
          if (!isListening) {
            setIsListening(true);
            setTimeout(() => {
                setSummary(prev => prev + (prev ? ' ' : '') + "Student showed great progress in understanding the core concepts today.");
                setIsListening(false);
            }, 1500);
          }
      }
  };

  // Logic to calculate if session is "Red Flag" (Low Scores)
  const isRedFlagSession = scores.some(s => {
      if (s.attendance === AttendanceStatus.ABSENT) return false;
      const values = Object.values(s.metrics);
      const avg = values.length ? values.reduce((a,b) => a+b, 0) / values.length : 0;
      return avg < 2.5;
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isAdmin && !selectedMentorId) {
        alert("Please select a mentor to record for.");
        return;
    }
    if (!selectedModuleId) {
        alert("Please select a teaching module.");
        return;
    }
    if (!artifactUrl) {
      alert("Please provide an artifact link (Proof of work).");
      return;
    }
    if (!digitalSignature) {
        alert("Please check the digital signature box to certify this session.");
        return;
    }

    setIsSubmitting(true);

    const newLog: MentoringLog = {
      id: initialData?.id || `log-${Date.now()}`,
      mentorId: '', 
      recordedBy: '', 
      batchId: selectedBatchId,
      moduleId: selectedModuleId,
      date,
      startTime,
      endTime,
      durationMinutes: duration,
      isValidSession: isValidSession,
      status: LogStatus.PENDING,
      summaryNote: summary,
      artifactUrl,
      scores,
      isStarred,
      digitalSignature,
      history: []
    };

    setTimeout(() => {
        addLog(newLog, isAdmin ? selectedMentorId : undefined);
        setIsSubmitting(false);
        setSuccessMsg("Log submitted successfully!");
        setSummary('');
        setArtifactUrl('');
        setDigitalSignature(false);
        setIsStarred(false);

        if (onSuccess) {
            setTimeout(() => onSuccess(), 1000);
        } else {
            setTimeout(() => setSuccessMsg(''), 3000);
        }
    }, 800);
  };

  // Determine which categories to render
  const activeCategories = selectedModule?.assessmentConfig?.filter(c => c.isEnabled) || [
      { id: 'def-1', name: 'Business Acumen', description: 'Business understanding', weight: 0, isEnabled: true },
      { id: 'def-2', name: 'Creativity', description: 'Innovation capability', weight: 0, isEnabled: true },
      { id: 'def-3', name: 'Discipline', description: 'Professionalism', weight: 0, isEnabled: true }
  ];

  return (
    <div className={`bg-white rounded-xl shadow-sm border overflow-hidden ${isAdmin ? 'border-indigo-200' : 'border-gray-100'}`}>
      <div className={`p-6 border-b ${isAdmin ? 'bg-indigo-600 text-white' : 'bg-indigo-50 text-indigo-900'}`}>
        <div className="flex justify-between items-start">
            <div className="flex items-center gap-3">
                {onCancel && (
                    <button onClick={onCancel} className={`p-1.5 rounded-full ${isAdmin ? 'bg-indigo-700 hover:bg-indigo-800' : 'bg-white hover:bg-gray-100 text-gray-600'}`}>
                        <ArrowLeft size={20} />
                    </button>
                )}
                <div>
                    <h2 className="text-xl font-bold flex items-center gap-2">
                        <Clock className="w-5 h-5" /> 
