      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-8">

        {/* Admin Proxy Selection */}
        {isAdmin && (
            <div className="bg-yellow-50 border border-yellow-200 p-4 rounded-lg flex items-center gap-4">
