                                </div>
                                <div className="flex bg-gray-100 rounded-lg p-1">
                                    {[AttendanceStatus.PRESENT, AttendanceStatus.LATE, AttendanceStatus.ABSENT].map((status) => (
                                        <button
                                            type="button"
                                            key={status}
                                            onClick={() => handleAttendanceChange(student.id, status)}
                                            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                                                score.attendance === status 
                                                ? status === AttendanceStatus.PRESENT ? 'bg-green-500 text-white' 
                                                : status === AttendanceStatus.LATE ? 'bg-yellow-500 text-white' 
                                                : 'bg-red-500 text-white'
                                                : 'text-gray-500 hover:text-gray-900'
                                            }`}
                                        >
                                            {status}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Rubrics - Only show if present or late */}
                            {score.attendance !== AttendanceStatus.ABSENT && (
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 pt-2 border-t border-gray-100">
                                    {activeCategories.map((cat) => (
                                        <div key={cat.id} className="group relative">
                                            <div className="flex justify-between mb-1">
                                                <label className="text-xs font-medium text-gray-500 uppercase flex items-center gap-1">
                                                    {cat.name}
                                                    {cat.description && (
                                                        <span className="text-gray-300 group-hover:text-indigo-400 cursor-help" title={`Score 5 Criteria: ${cat.description}`}>
                                                            <HelpCircle size={12} />
                                                        </span>
                                                    )}
                                                </label>
                                                <span className="text-xs font-bold text-indigo-600">{(score.metrics[cat.name] || 0)}/5</span>
                                            </div>
                                            <input 
                                                type="range" 
                                                min="0" max="5" step="1"
                                                value={(score.metrics[cat.name] || 0)}
                                                onChange={(e) => handleScoreChange(student.id, cat.name, parseInt(e.target.value))}
